values
  ('3016', '매운락교무침', '반찬', ' 락교(30g), 쪽파(2g), 마늘(0.1g)
, 고춧가루(0.3g), 설탕(0.3g), 참기름(0.1g), 참깨(0.1g)', '["락교","쪽파","마늘","고춧가루","설탕","참기름","참깨"]'::jsonb, ARRAY['4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','84104c49-0af4-4323-a56b-b67002a422d9','06e6f3e7-0293-469d-a338-11a610f3e71b','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"락교는 물에 헹군다.","imageUrl":null},{"step":2,"text":"락교의 물기를 제거한다.","imageUrl":null},{"step":3,"text":"쪽파는 송송 썬다.","imageUrl":null},{"step":4,"text":"마늘은 곱게 다진다.","imageUrl":null},{"step":5,"text":"양념장을 만든다.","imageUrl":null},{"step":6,"text":"락교와 쪽파, 다진마늘에 양념장을 골고루 버무려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309033105_1678343465526.jpg', 46.9, 8.4, 0.9, 1.1, 500.6),
  ('3017', '채소초밥', '일품', '쌀 40g, 현미 30g, 현미찹쌀 5g, 애호박 20g, 새송이버섯 20g, 우엉 20g, 적파프리카 15g, 황파프리카 15g, 주황파프리카 15g, 식초 2.5g, 설탕 2g, 파래김 1g, 미향 1g, 레몬 0.3g, 건다시마 0.1g', '["쌀","현미","현미찹쌀","애호박","새송이버섯","우엉","적파프리카","황파프리카","주황파프리카","식초","설탕","파래김","미향","레몬","건다시마"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','3f94371a-728f-49ae-8ea9-1a1e87b68048','6b3a8bca-adc3-48f5-813b-6b06630e11dd','5e79d288-1400-4817-bd20-e5e6041821b1','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','84032a7e-ec18-44d5-ab30-c7b960ca5ca9']::uuid[], '[{"step":1,"text":"쌀, 현미, 현미찹쌀은 물에 불린 뒤 고슬고슬하게 밥을 짓는다.","imageUrl":null},{"step":2,"text":"분량의 식초, 설탕, 다시마, 레몬, 미향을 넣고 초밥용 배합초를 만들어 밥과 섞는다.","imageUrl":null},{"step":3,"text":"우엉은 0.5cm 두께로 슬라이스 한 뒤 끓는 물에 데쳐 팬에 굽는다.","imageUrl":null},{"step":4,"text":"애호박, 파프리카는 초밥 크기로 썰어 소금물에 절인 뒤 팬에 굽는다.","imageUrl":null},{"step":5,"text":"밥을 초밥모양으로 길쭉하게 만든 뒤 파프리카, 우엉, 버섯, 애호박을 올려 초밥을 만든다.","imageUrl":null},{"step":6,"text":"길게 썬 파래김으로 채소가 고정되도록 밥을 감싼다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410014740_1554871660142.jpg', 393.26, 87.64, 7.59, 1.37, 144.48),
  ('3058', '꽃게바지락찌개', '국&찌개', '꽃게 8.2g, 바지락 4g, 조선무 11.3g, 깐양파 5g, 애호박 9.2g, 두절콩나물 5.3g, 국멸치 1.3g, 건다시마 0.3g, 깐대파 2g, 국간장 1.4g, 고춧가루 0.6g, 된장 0.5g, 고추장 0.6g, 물 300ml', '["꽃게","바지락","조선무","깐양파","애호박","두절콩나물","국멸치","건다시마","깐대파","국간장","고춧가루","된장","고추장","물"]'::jsonb, ARRAY['0c2a6773-2dcd-4ed5-a02c-4a52b1bdeab4','b6047d76-6c94-4757-b1d1-9175aea0c84a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','dd2eee03-8bbf-44ff-8a7f-ed1443986711','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9','392236b1-82e9-4e38-bd12-6a53b80bf463','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"국멸치, 건다시마로 육수를 낸다.","imageUrl":null},{"step":2,"text":"꽃게는 먹기 좋은 크기로 손질하고, 바지락은 해감하여 준비한다.","imageUrl":null},{"step":3,"text":"무는 나박썰기, 양파는 사각썰기, 애호박은 반달썰기, 파는 어슷썰기 한다.","imageUrl":null},{"step":4,"text":"콩나물은 거두절미 한다.","imageUrl":null},{"step":5,"text":"육수에 무, 꽃게, 바지락을 넣고 한소끔 끓인다.","imageUrl":null},{"step":6,"text":"콩나물, 양파, 애호박 대파를 넣고 끓이다 간을 맞춰 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306045438_1583481278124.jpg', 23.2, 0.2, 1.4, 1.3, 113.5),
  ('3066', '새뱅이찌개', '국&찌개', '물 300ml, 다시마 2g, 양파 15g, 새뱅이 30g, 밀가루 20g, 호박 10g, 무 10g, 청양고추 5g, 파10g, 마늘 5g, 쑥갓 5g, 고춧가루 3g, 고추장 3g, 소금 2g, 간장 1g', '["물","다시마","양파","새뱅이","밀가루","호박","무","청양고추","파","마늘","쑥갓","고춧가루","고추장","소금","간장"]'::jsonb, ARRAY['94786475-832c-4f97-aab7-bf6fbbe2236b','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aab3b0b9-d346-4697-a1c8-1b1530153788','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','f80c9a7d-1510-44e2-a82b-28b9f684e191','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','84104c49-0af4-4323-a56b-b67002a422d9','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','2cf0c12b-f248-4012-8f53-303c730a7b3d','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"다시마, 양파와 물을 넣고 육수를 만든다.","imageUrl":null},{"step":2,"text":"새뱅이는 불순문을 제거하여 세척하고, 밀가루에 물을 넣어 손수제비 반죽을 한다.","imageUrl":null},{"step":3,"text":"무와 호박은 나박썰기, 고추와 파는 어슷썰기, 마늘은 다진다.","imageUrl":null},{"step":4,"text":"들기름 두른 냄비에 무, 고추장, 고춧가루를 볶다가 육수를 부워 끓인다.","imageUrl":null},{"step":5,"text":"새뱅이와 호박, 고추 마늘을 넣어 끓인다.","imageUrl":null},{"step":6,"text":"손수제비와 파를 넣고 간을 맞추고 마지막에 쑥갓을 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309020630_1583730390527.jpg', 74.9, 14.7, 3.8, 0.1, 561),
  ('3071', '황태미역국', '국&찌개', ' 건미역(2g), 황태(4g)
, 황태머리(5g), 다시마(1g), 표고버섯(1g), 대파(1g), 물(250g)
, 참기름(1g), 다진마늘(1g), 저염국간장(2g)', '["건미역","황태","황태머리","다시마","표고버섯","대파","물","참기름","다진마늘","저염국간장"]'::jsonb, ARRAY['6565cc3a-c3d6-45b5-a7fb-05a3c03015bf','a6228d2a-6158-4542-bb52-b4f41a06f448','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','66458b1b-c92f-43fa-8eba-e428892ce88a','4b410642-7bf9-45ad-9055-e7d9a34edaa1','94786475-832c-4f97-aab7-bf6fbbe2236b','0c0ade94-cfd8-4104-b44c-40e942cac482','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"물과 육수 재료를 넣고 끓여 육수를 만든다.","imageUrl":null},{"step":2,"text":"끓인 육수를 체에 거른다.","imageUrl":null},{"step":3,"text":"건미역과 황태를 물에 불린 후, 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":4,"text":"냄비에 참기름을 두르고 미역과 황태를 넣어 볶는다.","imageUrl":null},{"step":5,"text":"냄비에 육수를 넣고 끓인다","imageUrl":null},{"step":6,"text":"다진마늘과 저염국간장으로 간을 맞춰 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308030341_1678255421758.jpg', 46, 6.6, 3.5, 0.6, 170.4),
  ('3081', '매실입은가지닭볶음탕', '반찬', '닭고기 100g, 가지 30g, 매실엑기스 5g, 파 5g,, 마늘2g, 대두유 3g, 간장 3g, 식초 2g, 미림 2g, 올리고당 2g, 참기름 1g', '["닭고기","가지","매실엑기스","파","마늘","대두유","간장","식초","미림","올리고당","참기름"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','3e12cf79-2cde-4309-9f7c-4eccce3fde28','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"닭과 가지는 먹기 좋은 사이즈로 토막 낸다.","imageUrl":null},{"step":2,"text":"다진파, 다진 마늘, 맛술, 참기름, 올리고당에 닭을 재운다.","imageUrl":null},{"step":3,"text":"매실엑기스, 간장, 식초, 다진마늘, 미림, 물을 섞어 소스를 만든다.","imageUrl":null},{"step":4,"text":"가지와 닭은 오븐에 구워준다.","imageUrl":null},{"step":5,"text":"구워진 닭과 가지를 매실소스에 버무린다.","imageUrl":null},{"step":6,"text":"팬에 소스 묻은 닭과 가지를 볶아 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313021810_1584076690447.jpg', 211.4, 9.2, 26.2, 7.7, 241.6),
  ('3184', '홍시잼 식빵', '기타', ' 강력분 500g, 인스턴트 이스트 5g, 소금 7g, 달걀 50g(1개), 우유 250g, 포도씨유 50g 
 홍시 1000g,  레몬즙 3g', '["강력분","인스턴트 이스트","소금","달걀","우유","포도씨유","홍시","레몬즙"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','c7d438a6-34d6-423f-905d-446b839e2f39','e937397f-54e2-49df-997a-f393c58360be','a7a59e81-de3d-4893-b56a-b2218732a25b','2db5cf59-b4ac-4d7b-8e13-68d143e5f34a','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"(속재료) 홍시는 껍질을 제거하고 체에 거른 다음 냄비에 레몬즙을 넣고 졸여서 잼을 만든다.","imageUrl":null},{"step":2,"text":"강력분, 소금, 인스던트 이스트를 먼저 섞다가 달걀, 포도씨유, 미지근하게 데운 우유를 넣어 가며 반죽한다.\r\n★ 액체 온도가 60℃가 넘어가면 이스트가 죽을 수 있어 조심해 주세요.","imageUrl":null},{"step":3,"text":"완성된 반죽을 1~2시간동안 실온에서 1차 발효 시킨 후, 세 덩어리로 나누어 15분 정도 2차 발효한다.","imageUrl":null},{"step":4,"text":"반죽을 60g씩 8개의 덩어리로 만들어 밀대를 사용하여 피자도우처럼 얇게 편다.","imageUrl":null},{"step":5,"text":"얇게 핀 반죽 위에 홍시 잼을 바르고 그 위에 핀 반죽을 올리는 걸 반복한 후 맨 위에 홍시 잼을 바르지 않은 반죽을 올리고 소량의 포도씨유를 바른 큐브식빵 틀에 담는다.","imageUrl":null},{"step":6,"text":"\"180도로 예열한 오븐에 식빵 틀을 넣고 40분정도 굽는다.\r\n★ 윗 면의 색이 많이 나면 종이 호일을 덮고 속까지 익혀요.\"","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129012126_1611894086934.jpg', 239, 43.76, 6.41, 4.25, 12.37),
  ('3203', '콩가루 소보로', '기타', ' 강력분 320g, 날콩가루 80g, 따뜻한 우유 140ml, 이스트 8g, 달걀 2개, 코코넛 오일 20g, 소금 2g 
(비스킷재료) 박력 쌀가루 100g, 볶은 콩가루 60g, 베이킹파우더 2g, 달걀 2개, 버터 60g 
 고구마 500g, 우유 50g, 크랜베리 100g, 아몬드 30g', '["강력분","날콩가루","따뜻한 우유","이스트","달걀","코코넛 오일","소금","박력 쌀가루","볶은 콩가루","베이킹파우더","버터","고구마","우유","크랜베리","아몬드"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','c1a987ee-fe94-4eb5-b3e7-d41c23cd3445','325279ee-6de6-4d84-96a0-16af87dfdbc6','c7d438a6-34d6-423f-905d-446b839e2f39','2cf0c12b-f248-4012-8f53-303c730a7b3d','7aabd532-361f-4240-aa33-6bfa1be4bc4e','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','e937397f-54e2-49df-997a-f393c58360be','1c1e5578-1128-45a4-bcaf-aae79de3639e','52ba316f-8e7f-415f-8079-9a9d674c9adf']::uuid[], '[{"step":1,"text":"(속재료) 찐 고구마에 우유, 다진 아몬드, 크랜베리를 넣어 섞는다.\r\n★ 고구마를 물에 삶으면 수분이 많아 우유량을 조절해야 해요.","imageUrl":null},{"step":2,"text":"(비스킷) 버터를 부드럽게 만들어 준 다음 볶은 콩가루와 소금을 넣고 섞다가 계란을 조금씩 넣어 분리되지 않게 반죽한다. 여기에 체 친 박력 쌀가루와 베이킹파우더를 넣어 섞어준 뒤 냉장고에 30분간 휴지시킨다.","imageUrl":null},{"step":3,"text":"코코넛 오일을 제외한 반죽 재료를 모두 반죽하다가 한 덩어리가 되면 코코넛 오일을 넣어 부드러워질 때까지 반죽한 다음 반죽의 크기가 두배가 될 때까지 발효한다. (약 1시간)","imageUrl":null},{"step":4,"text":"1차 발효 반죽은 30g씩 분할해 둥글리기 하고 중간 발효 (약 15분)한 다음 반죽 속 가스를 빼고 ①의 속재료를 40g씩 넣어 감싼다.","imageUrl":null},{"step":5,"text":"20g씩 비스킷을 분할해 비닐 위에 얇게 민 다음 비닐을 이용해 빵 반죽 위에 덮어준다.\r\n★반죽이 비닐에 달라 붙으면 덧가루를 조금 뿌려요.","imageUrl":null},{"step":6,"text":"팬닝 후 2차 발효(약15분)를 하고 윗불 180℃ , 아랫불 160℃ 로 예열된 오븐에서 20분 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112827_1612405707511.jpg', 279, 41.91, 9.08, 8.35, 13.53),
  ('3215', '곤약 가스', '일품', '냉동 곤약(200g), 채 썬 양파(50g), 납작 썬 마늘(10g), 채소 육수(100㎖), 아몬드(100g), 땅콩(100g), 통밀가루(45g), 미림(20g), 간장(5g), 간 마늘(10g), 토마토 페이스트(30g), 간장(10g), 설탕(3g), 발사믹식초(5g), 식용유(5㎖)', '["냉동 곤약","채 썬 양파","납작 썬 마늘","채소 육수","아몬드","땅콩","통밀가루","미림","간장","간 마늘","토마토 페이스트","설탕","발사믹식초","식용유"]'::jsonb, ARRAY['54a52322-b4df-4354-a7a5-2a7b0c41f7bd','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','52ba316f-8e7f-415f-8079-9a9d674c9adf','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','aab3b0b9-d346-4697-a1c8-1b1530153788','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','f175019d-5a93-4cd4-aabc-e7e79445f15a','76e95535-f965-4685-a7a6-55ae26aa202c','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"냉동 곤약에 칼집을 낸 뒤 냄비에 조림 양념과 물(40㎖)을 함께 넣고 5분간 조린다.","imageUrl":null},{"step":2,"text":"팬에 채 썬 양파와 납작 썬 마늘을 넣어 3분간 볶다가 토마토 페이스트(30g)를 넣어 3분간 볶는다.","imageUrl":null},{"step":3,"text":"채소 육수(100㎖), 간장(10g), 설탕(3g), 발사믹식초(5g)를 넣어 3분간 끓인 뒤 체에 밭쳐 건더기를 걸러 내 소스를 만든다.","imageUrl":null},{"step":4,"text":"중간 불로 달군 마른 팬에 아몬드와 땅콩을 5분간 볶은 뒤 잘게 다진다.","imageUrl":null},{"step":5,"text":"조린 곤약에 통밀가루(45g)와 물(40㎖)을 섞은 반죽을 입힌 뒤 잘게 다진 견과류를 묻힌다.","imageUrl":null},{"step":6,"text":"중간 불로 달군 팬에 식용유(5㎖)를 두른 뒤 견과류를 묻힌 곤약을 넣어 앞뒤로 3~5분간 굽고, 그릇에 곤약가스를 올리고 ③의 소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210113042_1612924242867.jpg', 449.8, 39, 15, 26, 385.3),
  ('3260', '두부크림 관자뇨키', '일품', ' 양파(25g), 관자(200g), 새우(6마리), 모시조개(6개), 청양고추(2개), 두부(200g), 우유(⅔컵), 생크림(⅔컵), 후춧가루(약간), 다진 마늘(0.7Ts), 바질(4장), 그라나파다노 치즈(1Ts)', '["양파","관자","새우","모시조개","청양고추","두부","우유","생크림","후춧가루","다진 마늘","바질","그라나파다노 치즈"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5b1f2880-4947-495e-81f3-b6dca1cbe265','6f10b4ad-53a2-4a07-ba89-19a6b074373d','b6047d76-6c94-4757-b1d1-9175aea0c84a','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4566cac5-9166-4c0d-906a-bfc7360f8f5b','e937397f-54e2-49df-997a-f393c58360be','af187077-b7f6-4b0e-9e99-f844f6359ac2','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','fc6e31ce-388e-45cd-956b-b238b9134eb1','ba9e5a79-cab3-4af0-942b-0b35fd745150']::uuid[], '[{"step":1,"text":"양파는 5mm 두께로 채 썰고, 청양고추는 어슷 썬 뒤 씨를 제거하고, 관자는 깨끗하게 헹군 뒤 후춧가루로 밑간한다.","imageUrl":null},{"step":2,"text":"두부에 우유와 생크림을 넣어 고루 섞어 두부크림을 만든다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 식용유(1.5Ts)를 두른 뒤 관자를 넣어 불투명해질 때까지 구워 꺼낸다.","imageUrl":null},{"step":4,"text":"같은 팬에 식용유(0.5Ts)를 두른 뒤 다진 마늘과 양파를 넣어 볶다가 새우, 모시조개, 청양고추를 넣어 볶는다.","imageUrl":null},{"step":5,"text":"물(100ml)을 넣어 조개가 입을 벌릴 때까지 끓이고, 두부크림을 넣어 끓어오르면 관자를 넣어 3분간 익힌다.","imageUrl":null},{"step":6,"text":"그릇에 담아 바질을 올리고, 그라나파다노 치즈를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9W1G', 267.6, 12.9, 26.5, 12.2, 478.9),
  ('3462', '토마토 해물누룽지탕', '국&찌개', ', 알배추(40g), 우목심(50g), 깻잎(5g), 청경채(25g), 팽이버섯(20g), 표고버섯(5g), 숙주(30g), 오징어(30g), 새우(40g), 홍합(164g), 베트남 건고추(10g), 토마토(250g), 청양고추(4g), 양파(50g), 대파(흰 부분, 10g), 편 마늘(10g), 시판 누룽지(50g), 토마토 페이스트(20g), 식용유(10g), 간장(5g), 고춧가루(6g), 후추(3g), 다시팩(20g), 물(4컵=800g)', '["알배추","우목심","깻잎","청경채","팽이버섯","표고버섯","숙주","오징어","새우","홍합","베트남 건고추","토마토","청양고추","양파","대파","편 마늘","시판 누룽지","토마토 페이스트","식용유","간장","고춧가루","후추","다시팩","물"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','66458b1b-c92f-43fa-8eba-e428892ce88a','2647e451-e8f5-4fce-91bd-8beabb2384d8','4d148f68-08e0-4599-8953-595db492bf23','6f10b4ad-53a2-4a07-ba89-19a6b074373d','1ddd4301-779b-4e99-a008-4933509afaf7','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','30b5d53c-d247-4f04-9b50-c0f728e65cf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','76e95535-f965-4685-a7a6-55ae26aa202c','a7a59e81-de3d-4893-b56a-b2218732a25b','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"물에 다시팩을 넣고 20분간 중불에 끓여 육수를 만들고, 오징어는 껍질을 벗겨 솔방울 모양으로 썰고 홍합은 수염을 제거하고 새우는 몸통의 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"토마토는 껍질을 벗겨 5×5mm 크기로 썰고, 알배추, 표고버섯, 청양고추, 양파, 우목심, 깻잎은 채 썰고 청경채는 어슷 썬다.","imageUrl":null},{"step":3,"text":"팬에 토마토 페이스트를 볶다가 토마토를 넣고 끓이고 고춧가루, 다시마 육수(200ml)를 넣고 살짝 끓여 토마토 소스를 만든다.","imageUrl":null},{"step":4,"text":"팬에 식용유를 두르고 대파, 편 마늘을 볶고, 우목심, 새우, 오징어, 홍합, 알배추, 양파, 표고버섯, 건고추를 넣어 볶다가 후추로 간하고, 간장을 넣는다.","imageUrl":null},{"step":5,"text":"토마토 소스를 함께 넣어 5분간 끓인다.","imageUrl":null},{"step":6,"text":"청경채, 팽이버섯, 숙주를 넣어 살짝 볶고, 깻잎과 누룽지를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106033231_1699252351417.jpg', 238.9, 28.6, 16.3, 6.6, 585.2),
  ('2968', '삼색나물, 토마토양념장', '반찬', '토마토 35g, 마늘 2g, 양파 20g, 꿀 15g, 식초 15g, 도라지 15g, 시금치 30g, 고사리 20g, 고추장 20g, 소금 2g, 참기름 5g', '["토마토","마늘","양파","꿀","식초","도라지","시금치","고사리","고추장","소금","참기름"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','286d1783-cd34-4aae-ac8b-006529ec8bc5','6c285c60-022a-4a00-b172-87df97f16a2f','09d825b7-c1dc-412a-b253-f59a9d254243','9a7f4da6-531b-4478-89ff-d73beafcad1b','9fb1e8e8-c9d9-41f1-a478-fccf9a335175','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','2cf0c12b-f248-4012-8f53-303c730a7b3d','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"토마토를 데쳐 껍질을 벗겨낸 뒤 잘게 썬다.","imageUrl":null},{"step":2,"text":"마늘과 양파를 잘게 다진 뒤 썰어둔 토마토, 고추장, 꿀, 식초와 골고루 섞는다.","imageUrl":null},{"step":3,"text":"도라지는 껍질을 벗긴 뒤 물에 담궈 쓴맛을 제거하고 길이 5cm, 두께 0.5cm로 찢는다.","imageUrl":null},{"step":4,"text":"시금치는 뿌리를 잘라내고 2~4등분으로 나눈다.","imageUrl":null},{"step":5,"text":"고사리는 깨끗하게 씻은 뒤 물에 불린다.","imageUrl":null},{"step":6,"text":"끓는 물에 소금을 넣고 도라지, 시금치, 고사리 순으로 데친 뒤 찬물에 헹궈 물기를 짜고 양념장을 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110832_1554689312799.jpg', 35.96, 5.71, 1.71, 0.7, 103.32),
  ('3204', '삼색 브레드 스틱', '기타', '강력분 300g, 소금 3g, 드라이이스트 12g, 버터 36g, 식용유 6g, 당근 50g, 참나물 50g, 연근 30g, 견과류 10g, 물 100ml', '["강력분","소금","드라이이스트","버터","식용유","당근","참나물","연근","견과류","물"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','7aabd532-361f-4240-aa33-6bfa1be4bc4e','a7a59e81-de3d-4893-b56a-b2218732a25b','e38c12a7-43cb-421a-a36e-7ef0d32517fa','09065cd3-28cc-4a82-8b3e-5121054c7482','b20f623d-e722-42af-9bd1-7c11b5e15aa6','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"강력분, 소금, 이스트, 물을 넣어 만든 반죽을 3등분 하여 각각 당근, 참나물, 연근을 다져 넣어 섞어준다.","imageUrl":null},{"step":2,"text":"반죽에 글루텐이 형성되면 각각 식용유와 버터를 넣어 섞고, 연근을 넣은 반죽에는 마지막에 견과류를 넣어 섞는다.\r\n★다른 반죽보다 향이 없는 연근 반죽에 견과류를 넣어 맛을 냈어요.","imageUrl":null},{"step":3,"text":"반죽이 완료되면 3-40분 정도 1차 발효를 한다.","imageUrl":null},{"step":4,"text":"1차 발효 후 30g씩 무게를 달아 둥글리기하고 중간 발효 후 길게 밀어 편다.","imageUrl":null},{"step":5,"text":"20분 정도 2차 발효를 한다.","imageUrl":null},{"step":6,"text":"아랫불 160, 윗불 180℃ 오븐에서 18분 동안 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044129_1670485289362.jpg', 315, 51.04, 10.61, 7.55, 1.61),
  ('3242', '양배추말이 김치', '반찬', '양배추(2장), 시금치(20g), 오이(60g), 당근(20g), 고춧가루(1t), 간장(1t), 사과식초(1t), 사과즙(1t)', '["양배추","시금치","오이","당근","고춧가루","간장","사과식초","사과즙"]'::jsonb, ARRAY['fd4254d4-2691-47e1-9367-c2b820ef8d00','9a7f4da6-531b-4478-89ff-d73beafcad1b','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','e38c12a7-43cb-421a-a36e-7ef0d32517fa','84104c49-0af4-4323-a56b-b67002a422d9','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"끓는 물(800㎖)에 양배추와 시금치를 넣어 데친 뒤 찬물에 헹궈 체에 밭쳐 물기를 제거한다.","imageUrl":null},{"step":2,"text":"데친 시금치와 오이, 당근은 얇게 채 썬다.","imageUrl":null},{"step":3,"text":"데친 양배추를 깔고 위에 채 썬 재료를 올려 돌돌 말아준다.","imageUrl":null},{"step":4,"text":"양념장을 만든다.","imageUrl":null},{"step":5,"text":"양배추말이를 한입 크기로 썰어 그릇에 담은 뒤 양념장을 곁들인다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF690', 33.2, 6.1, 1.7, 0.2, 200.2),
  ('3262', '단호박 양고기볶음', '반찬', ' 콜리플라워(50g), 고구마(1개), 양파(1개), 양고기(부채살, 250g), 마늘(7~8쪽), 단호박(1개), 올리브유(5ts), 바질럽드(3Ts), 바질페스토(3ts), 홀그레인 머스터드(2ts), 다진 마늘(2ts)', '["콜리플라워","고구마","양파","양고기","마늘","단호박","올리브유","바질럽드","바질페스토","홀그레인 머스터드","다진 마늘"]'::jsonb, ARRAY['4268226c-9999-4a22-8477-03127720f26f','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','98d652af-a6d6-440c-9653-e22fc5d47d88','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"콜리플라워는 송이 부분만 떼어내고, 고구마와 양파는 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"양고기는 한입 크기로 썰어 밑간한 뒤 15분간 재운다.","imageUrl":null},{"step":3,"text":"재워둔 고기에 손질한 채소와 마늘을 넣어 고루 버무리고, 중간 불로 달군 팬에 올려 고구마가 약간 익을 때까지 볶는다.","imageUrl":null},{"step":4,"text":"양념을 넣어 재료와 고루 섞는다.","imageUrl":null},{"step":5,"text":"단호박은 전자레인지에 5분간 돌리고, 익으면 윗부분을 약간 잘라낸 뒤 씨를 제거하고, 양고기와 볶은 재료를 단호박 속에 채운다.","imageUrl":null},{"step":6,"text":"찜기에 넣어 25분간 쪄낸 뒤 8등분하여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9WFj', 244.3, 21.8, 23.1, 7.2, 157.8),
  ('3463', '채소 프리타타', '반찬', ',  소고기(180g), 단호박(50g), 팽이버섯(20g), 새송이버섯(25g), 느타리버섯(20g), 쌈추(10g), 적근대(10g), 배추(20g), 숙주(20g),  달걀(3개=180g), 우유(75g), 식용유(26g), 소금(2g), 새싹채소(50g), 리코타 치즈(20g), 올리브유(20g)', '["소고기","단호박","팽이버섯","새송이버섯","느타리버섯","쌈추","적근대","배추","숙주","달걀","우유","식용유","소금","새싹채소","리코타 치즈","올리브유"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','98d652af-a6d6-440c-9653-e22fc5d47d88','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','3f94371a-728f-49ae-8ea9-1a1e87b68048','7c91e298-5ace-4242-8619-cdcc80587cd7','e116f85b-0eaa-40cb-8107-df5ec8486ad4','2647e451-e8f5-4fce-91bd-8beabb2384d8','c7d438a6-34d6-423f-905d-446b839e2f39','e937397f-54e2-49df-997a-f393c58360be','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"단호박, 팽이버섯, 새송이버섯, 느타리버섯, 쌈추, 적근대, 배추, 숙주와 소고기를 3cm 크기로 자른다.","imageUrl":null},{"step":2,"text":"팬에 식용유(20g)를 두르고 중간 불에 손질한 채소와 소고기를 차례대로 볶는다.","imageUrl":null},{"step":3,"text":"볼에 달걀을 풀고 소금, 우유를 넣고 섞어 달걀물을 만든다.","imageUrl":null},{"step":4,"text":"타르트 틀에 식용유(6g)를 바르고 볶은 채소, 소고기를 올리고 ③을 넣는다.","imageUrl":null},{"step":5,"text":"140도로 예열한 오븐에 25분 정도 구워 프리타타를 만든다.","imageUrl":null},{"step":6,"text":"프리타타 위에 새싹채소와 리코타 치즈를 올린 후 올리브유를 두르고 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034056_1699252856642.jpg', 467.2, 14.8, 33.3, 30.6, 478.6),
  ('3468', '고등어 라따뚜이 파스타', '일품', ',  고등어(1마리=250g), 시래기(30g), 무(20g), 대파(20g), 청양고추(20g), 양념장(75g),  토마토 홀(200g), 가지(60g), 애호박(90g), 표고버섯(40g), 두부면(50g), 가다랑어포(2g), 바질 잎(2g), 식용유(20g), 물(3컵=600g)', '["고등어","시래기","무","대파","청양고추","양념장","토마토 홀","가지","애호박","표고버섯","두부면","가다랑어포","바질 잎","식용유","물"]'::jsonb, ARRAY['f7f9c0c6-98d6-45b9-bbbe-26b57a62ee2e','f80c9a7d-1510-44e2-a82b-28b9f684e191','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','3e12cf79-2cde-4309-9f7c-4eccce3fde28','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','66458b1b-c92f-43fa-8eba-e428892ce88a','47fc4ccd-d88e-4a88-9b91-e6147e571342','a7a59e81-de3d-4893-b56a-b2218732a25b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"냄비에 물, 무, 대파를 넣고 끓으면 불을 끄고 가다랑어포를 넣고, 30분 후에 체로 걸러 육수를 만든다.","imageUrl":null},{"step":2,"text":"애호박, 가지, 표고버섯은 두께 5mm 크기로 썬다. 시래기는 굵게 다진다.","imageUrl":null},{"step":3,"text":"고등어는 흐르는 물에 씻은 후 키친타월로 물기를 제거하고, 180도로 예열한 팬에 식용유를 두르고 고등어를 껍질부터 앞뒤로 10분 동안 굽는다.","imageUrl":null},{"step":4,"text":"고등어를 구운 팬에 남은 기름을 이용해 시래기를 볶고, 토마토 홀을 넣고 주걱으로 으깬다.","imageUrl":null},{"step":5,"text":"육수(500g)와 양념장, 구운 고등어, 손질한 애호박, 가지, 표고버섯을 넣고 중간 불에서 조린다.","imageUrl":null},{"step":6,"text":"청양고추, 두부면을 넣고 2분 정도 더 조리한 후 불을 끄고 접시에 담고, 바질 잎을 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040805_1699254485787.jpg', 420.7, 13.8, 24.3, 29.9, 551.5),
  ('3574', '과카몰리 갈치구이', '반찬', ',
 갈치(70g(1토막)), 아보카도(35g), 토마토(10g), 양파(10g), 마늘(10g), 레몬(10g), 라임(10g), 바질(5g),
 올리브유(12g), 소금(1g), 후추(1g)', '["갈치)","아보카도","토마토","양파","마늘","레몬","라임","바질","올리브유","소금","후추"]'::jsonb, ARRAY['906bfef3-a41b-40d3-acda-7d8f23d2bcd2','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','ba9e5a79-cab3-4af0-942b-0b35fd745150','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"아보카도는 반으로 갈라 씨를 제거하고 과육을 으깬다. 레몬은 반으로 갈라 즙을 짜고, 라임은 얇게 자른다.","imageUrl":null},{"step":2,"text":"토마토, 양파, 마늘은 깍둑썰고, 바질은 곱게 다진다","imageUrl":null},{"step":3,"text":"볼에 손질한 아보카도, 토마토, 양파, 마늘, 바질을 넣고 올리브유, 레몬즙, 소금, 후추를 섞어 과카몰리를 만든다.","imageUrl":null},{"step":4,"text":"깨끗이 씻은 갈치는 칼집을 낸 후 달군 팬에 노릇하게 굽는다.","imageUrl":null},{"step":5,"text":"접시에 갈치구이를 담고 과카몰리를 곁들인다.","imageUrl":null},{"step":6,"text":"접시에 손질한 라임을 담고 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120011251_1732075971990.jpg', 73.8, 25, 6.8, 4.1, 54.3),
  ('3691', '초코치즈크림케이크', '후식', ' 우유 875ml, 식초 20ml, 알룰로스① 56g, 소금 1g,  아몬드가루 85g, 무가당 코코아가루① 20g, 알룰로스② 70g, 두유① 25ml, 바나나 175g, 달걀 105g, 두유② 25ml, 무가당 코코아가루② 45g, 땅콩버터 18g', '["우유","식초","알룰로스①","소금","아몬드가루","무가당 코코아가루①","알룰로스②","두유①","바나나","달걀","두유②","무가당 코코아가루②","땅콩버터"]'::jsonb, ARRAY['e937397f-54e2-49df-997a-f393c58360be','6c285c60-022a-4a00-b172-87df97f16a2f','2cf0c12b-f248-4012-8f53-303c730a7b3d','52ba316f-8e7f-415f-8079-9a9d674c9adf','1a4b39f8-b581-46dc-bd7e-289cd6160711','c7d438a6-34d6-423f-905d-446b839e2f39','02c78319-0bf6-45e0-8a7b-7546e1e47ba7']::uuid[], '[{"step":1,"text":"냄비에 우유를 넣고 중불로 끓이다\r\n약한 불에서 식초를 넣어 젓는다.\r\n면보로 유청을 거른 덩어리를 믹서에\r\n넣고 알룰로스①, 소금을 넣고 곱게\r\n갈아 크림치즈를 만든다.","imageUrl":null},{"step":2,"text":"볼에 아몬드가루, 무가당\r\n코코아가루①을 체 쳐서 넣고\r\n알룰로스②, 두유①을 섞어\r\n초코크림을 만든다.","imageUrl":null},{"step":3,"text":"믹서에 바나나, 달걀, 두유②,\r\n무가당 코코아가루②, 땅콩버터를 넣고\r\n갈아 반죽을 만들어 종이컵 높이의\r\n50% 정도 채운다.","imageUrl":null},{"step":4,"text":"전자레인지에서 4~5분 동안 구워\r\n시트를 만든다. 구운 시트는 가로로\r\n3등분한다.","imageUrl":null},{"step":5,"text":"크림치즈와 초코크림을 섞어 시트 위에\r\n올린다.","imageUrl":null},{"step":6,"text":"시트를 겹쳐 케이크를 만들고\r\n무가당 코코아가루를 뿌려 마무리한다","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023110921_1761185361351.jpg', 219.8, 23.9, 9.4, 18.5, 89.6),
  ('3579', '배추겉절이', '반찬', ',
 알배추(23g), 쪽파(5g),통깨(2g), 겉절이 양념(15g),
 찐 감자(20g), 고춧가루(25g), 매실청(5g), 까나리액젓(10g), 새우젓(3g), 무(20g), 양파(30g),생강(1g), 마늘(10g)', '["알배추","쪽파","통깨","겉절이 양념","찐 감자","고춧가루","매실청","까나리액젓","새우젓","무","양파","생강","마늘"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','4b410642-7bf9-45ad-9055-e7d9a34edaa1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','84104c49-0af4-4323-a56b-b67002a422d9','02fd7135-0ec3-49ec-82e3-390536ab2cf5','5fd46a51-6998-4ac9-a1fb-cab1eedf7cd9','8f2077de-dbd0-4372-a4c2-f987388f16b3','f80c9a7d-1510-44e2-a82b-28b9f684e191','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"알배추는 한입 크기로 자른다.","imageUrl":null},{"step":2,"text":"쪽파는 3cm 길이로 썰고, 찐 감자는 한입 크기로 자른다","imageUrl":null},{"step":3,"text":"마늘, 생강, 무, 양파는 깨끗이 씻어 한입 크기로 자른다.","imageUrl":null},{"step":4,"text":"믹서에 찐 감자, 고춧가루, 매실청, 까나리액젓, 새우젓, 무, 양파, 생강, 마늘을 넣고 갈아 겉절이 양념을 만든다.","imageUrl":null},{"step":5,"text":"손질한 알배추, 쪽파, 겉절이 양념(15g)을 버무린다.","imageUrl":null},{"step":6,"text":"접시에 담고 통깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120014935_1732078175251.jpg', 2, 2, 0.6, 0.1, 85),
  ('2971', '홍시에이드', '후식', '홍시 50g, 배 20g, 탄산수 50g, 사이다 50g', '["홍시","배","탄산수","사이다"]'::jsonb, ARRAY['2db5cf59-b4ac-4d7b-8e13-68d143e5f34a','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','20a151f5-d44f-48d8-bd67-958886b649d6']::uuid[], '[{"step":1,"text":"홍시를 반으로 가르고 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"씨를 제거한 뒤 3등분으로 썬다.","imageUrl":null},{"step":3,"text":"배는 1/4로 나눠 껍질을 벗긴다.","imageUrl":null},{"step":4,"text":"믹서에 배, 홍시를 넣고 간다.","imageUrl":null},{"step":5,"text":"4를 냉동실에서 살짝 얼린다.","imageUrl":null},{"step":6,"text":"반쯤 얼었을 때 탄산수와 사이다를 섞는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112605_1554690365803.jpg', 42.14, 10.3, 0.18, 0.02, 2.06),
  ('3060', '낙지묵은지콩나물국', '국&찌개', '낙지 50g, 묵은지 20g, 콩나물 40g, 무 40g, 대파 5g, 마늘 5g, 국멸치 3g, 대두유 5g, 간장 1.5g, 쌀뜨물 300ml , 고춧가루 5g', '["낙지","묵은지","콩나물","무","대파","마늘","국멸치","대두유","간장","쌀뜨물","고춧가루"]'::jsonb, ARRAY['bd61e0e7-ed60-47e9-9a29-95dcc8ca68af','133f214e-50f4-431d-af36-d97f6c9d4f9b','2db049b2-f39c-47ba-857f-fa02b3b0c610','f80c9a7d-1510-44e2-a82b-28b9f684e191','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','dd2eee03-8bbf-44ff-8a7f-ed1443986711','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9']::uuid[], '[{"step":1,"text":"쌀뜨물과 국멸치로 육수를 우리고 멸치를 건져낸다.","imageUrl":null},{"step":2,"text":"무는 나박썰기, 대파는 어슷썰기, 마늘은 다진다.","imageUrl":null},{"step":3,"text":"묵은지는 물에 헹구어 짠맛을 빼주고 기름에 살짝 볶는다.","imageUrl":null},{"step":4,"text":"멸치육수에 묵은지, 낙지, 고춧가루, 무, 마늘을 넣고 끓인다.","imageUrl":null},{"step":5,"text":"콩나물을 넣고 국간장으로 간을 하여 끓인다.","imageUrl":null},{"step":6,"text":"대파를 얹어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309010557_1583726757270.jpg', 71.7, 9.4, 6.3, 1, 280.5),
  ('3202', '자색고구마 버터크림 빵', '기타', ' 강력분 290g, 박력분 70g, 이스트 4g, 소금 5g, 달걀 50g(1개), 무염버터 30g , 바나나 180g, 밤고구마 130g, 물 150g 
 삶은 밤고구마 380g, 바나나 180g, 바나나슬라이스 
(버터크림재료) 삶은 자색고구마 190g, 삶은 밤고구마 100g, 박력분 30g,  달걀 50g(1개) ,버터120g, 물 100g', '["강력분","박력분","이스트","소금","달걀","무염버터","바나나","밤고구마","물","삶은 밤고구마","바나나슬라이스","삶은 자색고구마","버터"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','325279ee-6de6-4d84-96a0-16af87dfdbc6','2cf0c12b-f248-4012-8f53-303c730a7b3d','c7d438a6-34d6-423f-905d-446b839e2f39','7aabd532-361f-4240-aa33-6bfa1be4bc4e','1a4b39f8-b581-46dc-bd7e-289cd6160711','94786475-832c-4f97-aab7-bf6fbbe2236b','4b4f0113-01cf-4dc6-ae1f-30f09e99746b']::uuid[], '[{"step":1,"text":"(속재료) 삶은 밤고구마와 바나나를 섞은 앙금을 35g씩 둥글리기 해주고 여유분 바나나는 0.5두께로 슬라이스한다.","imageUrl":null},{"step":2,"text":"(버터크림) 삶은 자색고구마와 밤고구마를 으깬 후 물을 넣어 반죽하다가 박력분, 달걀 1개를 풀어 잘 섞어 준 후 버터를 넣고 덩어리가 생기지 않게 섞어 짤주머니에 담는다.","imageUrl":null},{"step":3,"text":"체에 내린 강력분과 박력분에 소금,이스트를 넣어 섞어주고 밤고구마 130g, 바나나 180g, 달걀 1개를 섞어 반죽이 한 덩이가 되면 무염버터 30g을 넣어 치댄다.","imageUrl":null},{"step":4,"text":"반죽이 2배가 되도록 1차 발효 후 50g 분할해 둥글리기 해서 10분 정도 중간 발효한다.","imageUrl":null},{"step":5,"text":"반죽에 앙금과 바나나슬라이스를 넣어 동그랗게 모양을 만들어 2차 발효 시키고 굽기 전에 고구마 버터크림을 올려준다.\r\n★이음새가 벌어지면 구우면서 반죽이 터져지니 꼼꼼히 붙여주세요.","imageUrl":null},{"step":6,"text":"윗불 180℃ 아랫불 160℃로 예열된 오븐에서 20분 구워낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112435_1612405475440.jpg', 929, 34.64, 6.42, 14.21, 7.54),
  ('3205', '치아바타 피자빵', '기타', ' 블루베리 발효원종 250g, 강력분 250g, 소금 3g, 물 100ml
(소스) 토마토 150g, 양송이 버섯 50g, 양파 50g, 파프리카 50g, 로즈마리 5g, 식용유 10g , 물 50ml
(토핑) 저염치즈 200g', '["블루베리 발효원종","강력분","소금","물","토마토","양송이 버섯","양파","파프리카","로즈마리","식용유","저염치즈"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','a7a59e81-de3d-4893-b56a-b2218732a25b','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c']::uuid[], '[{"step":1,"text":"(소스) 소스에 들어가는 재료는 전부 다진 후 기름 두른 팬에 양파를 먼저 볶다가 남은 재료를 넣고 볶아 준 뒤 물을 넣고 끓여 조린다.","imageUrl":null},{"step":2,"text":"반죽 재료를 넣고 27℃ 최종단계 까지 믹싱한 후 1차 발효는 고온발효로 27℃에서 1시간 발효한다.","imageUrl":null},{"step":3,"text":"150g씩 분할하여 모양을 성형한 후 면포 위에 팬닝한다.\r\n★반죽이 많이 질어요. 손에 묻으면 덧밀가루를 뿌려가며 진행하세요.","imageUrl":null},{"step":4,"text":"2차 발효는 온도는 30℃, 수분은 75%에서 60분간 발효한 후 오븐팬에 팬닝한다.","imageUrl":null},{"step":5,"text":"반죽 위에 만들어 놓은 토마토 소스를 바르고 스팀 160℃/230℃에서 13분간 굽는다.","imageUrl":null},{"step":6,"text":"치즈를 올리고 4분간 구워낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044531_1670485531889.jpg', 237, 29.14, 12.79, 7.65, 1.7),
  ('3209', '코코넛워터 토마토카레', '일품', '양파(75g), 감자(50g), 당근(40g), 닭가슴살(100g), 토마토(150g), 코코넛워터(100㎖), 우유(100㎖), 현미밥(150g), 올리브유(10g), 후춧가루(3g), 카레가루(10g), 물(3T), 그릭요거트(45g), 소금(0.5g), 올리브유(10g), 올리고당(10g), 다진 마늘(15g), 카레가루(10g), 파슬리가루(0.5g)', '["양파","감자","당근","닭가슴살","토마토","코코넛워터","우유","현미밥","올리브유","후춧가루","카레가루","물","그릭요거트","소금","올리고당","다진 마늘","파슬리가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','20894da1-739d-4d52-b5fe-4943bd3492d5','e38c12a7-43cb-421a-a36e-7ef0d32517fa','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','e937397f-54e2-49df-997a-f393c58360be','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','495b9f1e-aa3b-4506-9bb8-feb0a493901e','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','fc6e31ce-388e-45cd-956b-b238b9134eb1','4362c386-a37c-44cd-9254-fafd74712a09']::uuid[], '[{"step":1,"text":"양파(30g)는 다지고, 나머지 양파와 감자, 당근, 닭가슴살은 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"닭가슴살은 밑간해 고루 버무려 재운다.","imageUrl":null},{"step":3,"text":"끓는 물에 토마토를 넣어 20초간 데쳐 건진 뒤 껍질을 벗겨 8등분한다.","imageUrl":null},{"step":4,"text":"중간 불로 달군 팬에 올리브유(10g)를 두른 뒤 다진 양파와 올리고당, 다진 마늘, 카레가루를 넣어 2분간 볶다가 손질한 토마토를 넣고 으깨듯 볶는다.","imageUrl":null},{"step":5,"text":"손질한 채소와 밑간한 닭가슴살을 넣고 2분간 볶은 뒤 코코넛워터와 우유를 부어 끓인다.","imageUrl":null},{"step":6,"text":"그릇에 현미밥을 담고 카레를 부은 뒤 요거트소스와 파슬리가루(0.5g)를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105005_1612835405539.jpg', 583.9, 88.6, 25.2, 14.3, 601.2),
  ('3244', '치즈 단호박', '일품', '단호박(1개=800g), 달걀(1개), 맛술(1T), 우유(1T), 모차렐라치즈(30g), 그라나파다노치즈(1Ts), 아몬드 플레이크(2Ts), 꿀(1Ts), 파슬리가루(약간)', '["단호박","달걀","맛술","우유","모차렐라치즈","그라나파다노치즈","아몬드 플레이크","꿀","파슬리가루"]'::jsonb, ARRAY['98d652af-a6d6-440c-9653-e22fc5d47d88','c7d438a6-34d6-423f-905d-446b839e2f39','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','e937397f-54e2-49df-997a-f393c58360be','286d1783-cd34-4aae-ac8b-006529ec8bc5','4362c386-a37c-44cd-9254-fafd74712a09']::uuid[], '[{"step":1,"text":"단호박은 3mm 정도 윗부분을 도려내 씨를 제거한 뒤 전자레인지에 5분간 돌려 익힌다.","imageUrl":null},{"step":2,"text":"단호박 씨를 제거한 뒤 속(50g)을 파서 덜어놓는다.","imageUrl":null},{"step":3,"text":"달걀은 곱게 풀어 체에 내린 뒤 맛술, 우유, 모차렐라치즈(20g), 덜어 놓은 호박과 함께 믹서에 넣어 간다.","imageUrl":null},{"step":4,"text":"속을 파낸 단호박에 간 재료를 넣은 뒤 뚜껑을 닫고 전자레인지에 8분간 돌려 익힌다.","imageUrl":null},{"step":5,"text":"뚜껑을 열고 모차렐라치즈(10g)를 올려 전자레인지에 3분간 돌려 녹인다.","imageUrl":null},{"step":6,"text":"단호박을 6~7등분해 그릇에 담고 꿀과 그라나파다노치즈, 아몬드 플레이크, 파슬리가루를 뿌린다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF7wm', 379.3, 49, 19, 11.9, 248.5),
  ('3263', '강황 투움바 파스타', '기타', ' 양파(1개), 양송이버섯(6개), 마늘(5쪽), 토마토(3개), 탈리아텔레(200g), 말린 토마토(2개), 다진 파슬리(0.5Ts), 핑크 페퍼(5알), 바질잎(2장), 바게트(약간), 물(1260ml), 무(150g), 양파(1개), 다시마(5×5cm, 2장), 올리브유(2Ts), 강황가루(2ts), 고운 고춧가루(0.5ts), 식물성 생크림(⅔컵), 두유(¼컵), 후춧가루(2ts)', '["양파","양송이버섯","마늘","토마토","탈리아텔레","말린 토마토","다진 파슬리","핑크 페퍼","바질잎","바게트","물","무","다시마","올리브유","강황가루","고운 고춧가루","식물성 생크림","두유","후춧가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','fc6e31ce-388e-45cd-956b-b238b9134eb1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','4362c386-a37c-44cd-9254-fafd74712a09','94786475-832c-4f97-aab7-bf6fbbe2236b','f80c9a7d-1510-44e2-a82b-28b9f684e191','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','a7cf6fb8-b34f-4cfe-a4af-d8e000090dcb','84104c49-0af4-4323-a56b-b67002a422d9','a4e9789c-3090-43d8-ab14-e4e168f8b910','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"양파는 도톰하게 채 썰고, 양송이버섯은 모양대로 썰고, 마늘은 납작 썰고, 토마토는 6~8등분한다.","imageUrl":null},{"step":2,"text":"채소 육수(6컵)에 탈리아텔레를 넣고 13분간 삶아 건진다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 올리브유를 두른 뒤 납작 썬 마늘을 노릇하게 익히고, 양파와 양송이버섯을 넣어 3분간 볶는다.","imageUrl":null},{"step":4,"text":"면수(1컵), 강황가루, 고운 고춧가루를 넣어 고루 섞고, 토마토를 넣어 볶다가 식물성 생크림과 두유를 넣어 끓어 오르면 말린 토마토를 넣고 1분간 끓인다.","imageUrl":null},{"step":5,"text":"삶은 탈리아텔레를 넣고, 소스가 면에 잘 배어들게 고루 볶은 뒤 후춧가루를 뿌린다.","imageUrl":null},{"step":6,"text":"그릇에 담고 다진 파슬리와 핑크 페퍼를 뿌리고, 바질잎과 바게트를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9WOj', 392.5, 60.4, 11.7, 11.6, 221.7),
  ('3464', '깻잎 쌈두부 라자냐', '반찬', ',  쌈두부(18g), 소고기 양지(120g), 숙주(80g), 청경채(30g), 배추(60g), 당면(30g),  쌈두부(1팩=100g), 모차렐라 치즈(1컵=100g), 깻잎(10g), 완숙 토마토(80g), 양파(80g), 소고기 다짐육(100g), 화이트 와인(50g), 오레가노(5g), 월계수 잎(1g), 다진 마늘(20g), 식용유(30g), 소금(5g), 후추(3g)', '["쌈두부","소고기 양지","숙주","청경채","배추","당면","모차렐라 치즈","깻잎","완숙 토마토","양파","소고기 다짐육","화이트 와인","오레가노","월계수 잎","다진 마늘","식용유","소금","후추"]'::jsonb, ARRAY['2647e451-e8f5-4fce-91bd-8beabb2384d8','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','e116f85b-0eaa-40cb-8107-df5ec8486ad4','b85df3ba-e324-47fa-b25d-d5bb552b8590','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e16eaf50-ebd3-4933-a774-3ce6fc92593f','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6','043a9631-bb6e-42e6-9673-4943457502fb','fc6e31ce-388e-45cd-956b-b238b9134eb1','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"껍질 벗긴 토마토는 주사위 모양으로 썰고, 양파, 배추, 청경채, 숙주는 잘게 썬다.","imageUrl":null},{"step":2,"text":"팬에 소고기 양지를 구운 뒤 꺼내고, 같은 팬에 식용유를 두르고 다진 마늘과 손질한 채소를 넣고 물기가 없어질 때까지 볶는다.","imageUrl":null},{"step":3,"text":"②에 소고기 다짐육을 넣어 볶다가 손질한 완숙 토마토, 월계수 잎, 화이트 와인, 오레가노를 넣어 끓이고 소금, 후추로 간하여 소스를 만든다.","imageUrl":null},{"step":4,"text":"당면은 6cm 길이로 잘라 끓는 물에 7분간 삶아 ③에 넣는다.","imageUrl":null},{"step":5,"text":"쌈두부 → 구운 소고기 양지 → 소스 → 모차렐라 치즈 순으로 켜켜이 올리고 180도로 예열한 오븐에 8분간 익힌다.","imageUrl":null},{"step":6,"text":"깻잎을 돌돌 말아 채 썰어 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034746_1699253266204.jpg', 601.9, 24.3, 37.8, 39.3, 450.2),
  ('3568', '참깨가지말이밥', '밥', '1인분기준,
닭다리살(25g), 닭안심살(30g), 토마토(35g), 방울토마토(15g), 시금치(5g), 양파(10g), 감자(7g), 스파게티면(건면)(5g),
고추장(5g), 고춧가루(3g), 다진 마늘(3g), 진간장(4g), 알룰로스(4g),', '["닭다리살","닭안심살","토마토","방울토마토","시금치","양파","감자","스파게티면","고추장","고춧가루","다진 마늘","진간장","알룰로스"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','9a7f4da6-531b-4478-89ff-d73beafcad1b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','20894da1-739d-4d52-b5fe-4943bd3492d5','b85df3ba-e324-47fa-b25d-d5bb552b8590','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','84104c49-0af4-4323-a56b-b67002a422d9','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"가지는 0.3cm 두께로 얇게 썰고 방울토마토, 파프리카, 양파는 잘게 자른다.","imageUrl":null},{"step":2,"text":"손질한 가지는 오븐에 굽는다. (180℃, 10분)","imageUrl":null},{"step":3,"text":"달군 팬에 올리브유(6g)를 두르고 양파를 볶다가 현미밥, 방울토마토, 파프리카를 넣고 볶는다.","imageUrl":null},{"step":4,"text":"채소가 익으면 약한 불로 줄이고 토마토 페이스트, 쿠민가루를 넣어 볶음밥을 만든다.","imageUrl":null},{"step":5,"text":"믹서에 참깨, 올리브유(6g)를 넣어 갈고 요거트, 다진 마늘을 섞어 참깨 소스를 만든다.","imageUrl":null},{"step":6,"text":"구운 가지 위에 볶음밥을 올려 돌돌 말고, 참깨 소스를 얹어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120104724_1732067244359.jpg', 575.9, 92.2, 12.9, 17.3, 55.6),
  ('2972', '코다리 뿌리채소 들깨탕', '국&찌개', '코다리 150g, 무 60g, 연근 20g, 호박 20g, 우엉 10g, 느타리버섯 10g, 표고버섯 10g, 대파 5g, 양파 10g, 청양고추 2g, 쑥갓 1g, 홍고추 1g, 다시멸치 1g, 다시마 1g, 들깨가루 15g, 마늘 1.5g, 생강 0.5g, 후추가루 0.5g, 천일염 0.2g', '["코다리","무","연근","호박","우엉","느타리버섯","표고버섯","대파","양파","청양고추","쑥갓","홍고추","다시멸치","다시마","들깨가루","마늘","생강","후추가루","천일염"]'::jsonb, ARRAY['f80c9a7d-1510-44e2-a82b-28b9f684e191','b20f623d-e722-42af-9bd1-7c11b5e15aa6','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','6b3a8bca-adc3-48f5-813b-6b06630e11dd','7c91e298-5ace-4242-8619-cdcc80587cd7','66458b1b-c92f-43fa-8eba-e428892ce88a','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','184687ba-0cba-4fec-bb21-33fe300c2073','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"생강과 마늘을 잘게 다진다.","imageUrl":null},{"step":2,"text":"코다리를 세척 후 다진마늘, 다진생강, 소금, 후추로 밑간한다.","imageUrl":null},{"step":3,"text":"냄비에 다시멸치, 다시마를 넣고 끓여 육수를 우린 뒤 건져낸다.","imageUrl":null},{"step":4,"text":"무, 대파, 양파, 연근, 우엉, 호박, 느타리버섯, 표고버섯, 청양고추를 깨끗이 씻어 먹기좋은 크기로 썬다.","imageUrl":null},{"step":5,"text":"육수에 대파, 청양고추, 쑥갓을 뺀 야채를 넣고 끓이다가 들깨가루와 천일염을 넣어 간 한다.","imageUrl":null},{"step":6,"text":"마지막으로 코다리를 넣고 거품을 걷어가며 끓인 뒤 대파, 청양고추, 쑥갓을 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113144_1554690704520.jpg', 93.33, 3.64, 14.75, 2.2, 155.11),
  ('3206', '찹쌀 흰살 생선찜', '일품', '배추(30g), 대파(12g), 가자미(70g), 찹쌀가루(5g), 식초(3g), 맛술(5g), 새우젓(2g), 다진 마늘(2g), 다진 파(2g), 월계수잎(1장), 불린 찹쌀(30g), 고운 고춧가루(2g), 백후추(1g), 잘게 다진 새우젓(1g)', '["배추","대파","가자미","찹쌀가루","식초","맛술","새우젓","다진 마늘","다진 파","월계수잎","불린 찹쌀","고운 고춧가루","백후추","잘게 다진 새우젓"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','4b410642-7bf9-45ad-9055-e7d9a34edaa1','4cb11562-015f-4ab5-969f-0ea8483a0b42','6c285c60-022a-4a00-b172-87df97f16a2f','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','8f2077de-dbd0-4372-a4c2-f987388f16b3','fc6e31ce-388e-45cd-956b-b238b9134eb1','043a9631-bb6e-42e6-9673-4943457502fb','84104c49-0af4-4323-a56b-b67002a422d9']::uuid[], '[{"step":1,"text":"배추는 한입 크기로 썰고, 대파는 6cm 길이로 썰어 길게 2등분하고, 가자미는 먹기 좋은 크기로 자른다.","imageUrl":null},{"step":2,"text":"가자미에 밑간을 고루 버무린 뒤 냉장실에서 20분간 재운다.","imageUrl":null},{"step":3,"text":"찹쌀싸라기 재료를 고루 섞는다.","imageUrl":null},{"step":4,"text":"재워둔 가자미에 찹쌀가루(5g)를 고루 바른 뒤 찹쌀싸라기를 촘촘히 입힌다.","imageUrl":null},{"step":5,"text":"찜기에 배추와 대파를 깔고 가자미를 올린 뒤 12분간 찌고 불을 꺼 5분간 뜸 들인다.","imageUrl":null},{"step":6,"text":"그릇에 담아 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209103625_1612834585653.jpg', 206.1, 20, 16.4, 6.8, 284.6),
  ('3210', '깻잎퓌레를 곁들인 삼치새우', '일품', '깻잎(20장), 청경채(1단), 새우(3마리), 삼치(75g), 생크림(230㎖), 식용 꽃(약간), 삶은 감자(150g), 녹인 무염 버터(15㎖), 우유(15㎖), 레몬즙(3g), 소금(2g), 후춧가루(3g), 건로즈메리(2g), 찹쌀가루(3g), 전분(12g), 올리브유(3㎖), 설탕(3g), 후춧가루(3g), 식용유(185㎖)', '["깻잎","청경채","새우","삼치","생크림","식용 꽃","삶은 감자","녹인 무염 버터","우유","레몬즙","소금","후춧가루","건로즈메리","찹쌀가루","전분","올리브유","설탕","식용유"]'::jsonb, ARRAY['3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','6f10b4ad-53a2-4a07-ba89-19a6b074373d','40ebc656-16c3-42f6-b601-656230d5d160','af187077-b7f6-4b0e-9e99-f844f6359ac2','20894da1-739d-4d52-b5fe-4943bd3492d5','e937397f-54e2-49df-997a-f393c58360be','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','4cb11562-015f-4ab5-969f-0ea8483a0b42','6613d1d9-80a2-4ce4-9d3d-647203197e53','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','06e6f3e7-0293-469d-a338-11a610f3e71b','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"깻잎은 깨끗이 씻고, 청경채는 2등분하고, 새우는 머리를 제거한 뒤 껍질을 벗기고, 삼치는 밑간한다.","imageUrl":null},{"step":2,"text":"냄비에 깻잎과 생크림, 올리브유(3㎖)를 넣어 끓어오르면 믹서에 넣어 곱게 간 뒤 체에 걸러 퓌레를 만든다.","imageUrl":null},{"step":3,"text":"삶은 감자는 으깬 뒤 녹인 무염 버터와 설탕(3g),후춧가루(3g)를 고루 섞고 체에 한 번 걸러 우유를 섞어 매시드 포테이토를 만든다.","imageUrl":null},{"step":4,"text":"손질한 새우에 튀김옷을 입혀 180℃로 달군 식용유(180㎖)에 3분간 튀겨 건지고, 마른 팬에 손질한 청경채를 볶은 뒤 토치로 불맛을 낸다.","imageUrl":null},{"step":5,"text":"중간 불로 달군 팬에 식용유(5㎖)를 두른 뒤 밑간한 삼치를 5분간 앞뒤로 노릇하게 구워 꺼낸다.","imageUrl":null},{"step":6,"text":"그릇에 깻잎퓌레 → 구운 삼치 → 매시드 포테이토 → 청경채 → 튀긴 새우 → 꽃잎 순으로 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105401_1612835641196.jpg', 575.2, 40.5, 27.3, 33.8, 655.6),
  ('3245', '참나물페스토 파스타', '일품', ' 참나물(45g), 방울토마토(2개), 스파게티면(90g)
, 참나물(18g), 잣(4g), 올리브유(4g), 소금(1g)
, 올리브유(2g)', '["참나물","방울토마토","스파게티면","잣","올리브유","소금"]'::jsonb, ARRAY['09065cd3-28cc-4a82-8b3e-5121054c7482','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','b85df3ba-e324-47fa-b25d-d5bb552b8590','bbbbd533-8922-4dac-9e4c-cd93ea710c92','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"참나물은 얇게 썰고, 방울토마토는 2등분하고, 잣은 곱게 빻아 잣가루를 만든다.","imageUrl":null},{"step":2,"text":"믹서에 참나물 페스토 재료를 넣고 갈아 페스토를 만든다.","imageUrl":null},{"step":3,"text":"끓는 소금물(물 8컵과 소금 1g 비율)에 스파게티를 넣어 8분간 삶아 건진다.","imageUrl":null},{"step":4,"text":"스파게티에 페스토를 넣어 버무린다.","imageUrl":null},{"step":5,"text":"그릇에 스파게티를 담은 뒤 손질한 참나물을 올리고 올리브유, 잣가루를 뿌린다.","imageUrl":null},{"step":6,"text":"손질한 방울토마토를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309094407_1678322647562.jpg', 462.2, 54.5, 11.8, 21.9, 60.8),
  ('3265', '카레삼겹살 파니니', '기타', ' 방울토마토(4개), 아보카도(1개), 로메인(4장), 양파(¼개), 대파(15cm), 미나리(⅓줌=50g), 마늘(5쪽), 대패삼겹살(100g), 치아바타(2개), 올리브유(0.5Ts), 후춧가루(약간), 간장(1Ts), 꿀(1Ts), 카레가루(1Ts), 고운 고춧가루(0.3Ts), 플레인 요거트(2Ts) + 꿀(1Ts)', '["방울토마토","아보카도","로메인","양파","대파","미나리","마늘","대패삼겹살","치아바타","올리브유","후춧가루","간장","꿀","카레가루","고운 고춧가루","플레인 요거트 + 꿀"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','906bfef3-a41b-40d3-acda-7d8f23d2bcd2','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','dc7b2b73-74de-4fb8-9274-a5967ca444f9','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f175019d-5a93-4cd4-aabc-e7e79445f15a','286d1783-cd34-4aae-ac8b-006529ec8bc5','495b9f1e-aa3b-4506-9bb8-feb0a493901e','84104c49-0af4-4323-a56b-b67002a422d9']::uuid[], '[{"step":1,"text":"방울토마토는 4등분하고, 아보카도는 얇게 모양대로 썰고, 로메인은 깨끗하게 씻어 물기를 제거하고, 양파, 대파, 미나리는 4cm 길이로 썰고, 마늘은 납작 썬다.","imageUrl":null},{"step":2,"text":"중간 불로 달군 팬에 올리브유를 두른 뒤 납작 썬 마늘, 양파, 대파를 넣어 1분간 볶는다.","imageUrl":null},{"step":3,"text":"대패삼겹살과 후춧가루를 넣어 겉면이 노릇해질 때까지 볶고, 미나리, 간장, 꿀을 넣어 1분 정도 볶고, 카레가루, 고운 고춧가루를 넣어 고루 섞으며 볶는다.","imageUrl":null},{"step":4,"text":"허니요거트소스를 만든다.","imageUrl":null},{"step":5,"text":"치아바타는 마른 팬에 안쪽 면을 노릇하게 구워 꺼내고, 빵 안쪽에 허니 요거트소스를 바른다.","imageUrl":null},{"step":6,"text":"로메인, 삼겹살볶음, 허니요거트소스, 아보카도, 방울토마토, 후춧가루 순으로 올려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJetjt', 655.5, 80.1, 23.9, 26.6, 738.3),
  ('3282', '어린잎채소 건두부말이', '기타', ' 어린잎채소(4컵), 견과류(1컵), 건두부(10장), 슈레드 모차렐라치즈(1컵), 라임청(3ts), 후춧가루(약간), 올리브유(2ts), 다진 마늘(0.3ts)', '["어린잎채소","견과류","건두부","슈레드 모차렐라치즈","라임청","후춧가루","올리브유","다진 마늘"]'::jsonb, ARRAY['bc0ebb76-798a-40fe-be99-557ca2b9a9b4','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"어린잎채소는 깨끗하게 씻어 물기를 제거하고, 견과류는 굵게 다진다.","imageUrl":null},{"step":2,"text":"건두부는 끓는 물에 데쳐 건져낸 뒤 물기를 제거한다.","imageUrl":null},{"step":3,"text":"건두부 위에 어린잎채소(3컵)를 올리고, 돌돌 말아 한입 크기로 썬다.","imageUrl":null},{"step":4,"text":"남은 어린잎채소에 다진 견과류와 슈레드모차렐라치즈를 고루 섞는다.","imageUrl":null},{"step":5,"text":"라임청의 라임을 얇게 다지고, 나머지 라임청드레싱 재료와 고루 섞는다.","imageUrl":null},{"step":6,"text":"그릇에 건두부말이와 샐러드를 담고, 라임청 드레싱을 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr97uZ', 233.8, 7.3, 12.7, 17.1, 156.7),
  ('3465', '해산물 완자볼을 곁들인 양장피 콩국수', '일품', ',  새우(50g), 오징어(60g), 양장피 면(60g), 건목이버섯(10g), 참기름(4g), 양파(110g), 볶음 소스(20g), 크레미(40g), 당근(40g), 피망(45g), 붉은 파프리카(45g), 달걀지단(20g),  콩국물(1컵=200g), 딜(1g), 올리브유(35g), 달걀흰자(15g), 식용유(700g)', '["새우","오징어","양장피 면","건목이버섯","참기름","양파","볶음 소스","크레미","당근","피망","붉은 파프리카","달걀지단","콩국물","딜","올리브유","달걀흰자","식용유"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','4d148f68-08e0-4599-8953-595db492bf23','0c0ade94-cfd8-4104-b44c-40e942cac482','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','df459e6f-3515-45d5-8c9a-9d37b6249379','c7d438a6-34d6-423f-905d-446b839e2f39','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"오징어, 새우, 당근, 양파를 믹서에 갈아 달걀흰자를 넣어 치댄 후 완자를 만들어 160도로 예열한 식용유에 4분 정도 튀긴다.","imageUrl":null},{"step":2,"text":"붉은 파프리카와 피망은 올리브유에 살짝 볶는다.","imageUrl":null},{"step":3,"text":"양장피 면은 끓는 물에 5분간 데치고, 같은 냄비에 건목이버섯을 데친다.","imageUrl":null},{"step":4,"text":"양장피 면이 서로 달라붙지 않게 참기름에 버무리고 돌돌 말아 접시 위에 올린다.","imageUrl":null},{"step":5,"text":"크레미, 데친 건목이버섯, 달걀지단을 면 위에 올리고, 튀겨낸 완자, 딜, 볶은 파프리카와 피망을 올린다.","imageUrl":null},{"step":6,"text":"콩국물을 붓고 볶음 소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035211_1699253531583.jpg', 265.6, 49, 10.2, 3.2, 360),
  ('3569', '토마토를 곁들인 마늘밥', '밥', ',
현미(60g), 백미(30g), 마늘(30g), 토마토(60g),
 올리브유(24g), 후추(1g), 파슬리가루(1g)', '["현미","백미","마늘","토마토","올리브유","후추","파슬리가루"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','fc6e31ce-388e-45cd-956b-b238b9134eb1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','4362c386-a37c-44cd-9254-fafd74712a09']::uuid[], '[{"step":1,"text":"현미는 1시간, 백미는 30분 동안 불린다.","imageUrl":null},{"step":2,"text":"마늘의 절반은 편으로 썰고, 나머지는 통으로 준비한다.","imageUrl":null},{"step":3,"text":"냄비에 불린 쌀, 마늘을 넣고 물을 맞춰 센 불에서 끓어오르면 중약 불로 줄이고 15분 동안 끓인다.","imageUrl":null},{"step":4,"text":"약한 불로 줄이고 뜸을 들여 마늘밥을 만든다.","imageUrl":null},{"step":5,"text":"칼집을 낸 토마토를 뜨거운 물에 살짝 데쳐 껍질과 씨를 제거하고, 잘게 다진다.","imageUrl":null},{"step":6,"text":"접시에 마늘밥을 담고 손질한 토마토를 올린 후 올리브유, 후추, 파슬리가루를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105532_1732067732591.jpg', 427.8, 85.8, 8.8, 5.5, 3.6),
  ('3570', '낙전새 카레볶음밥', '밥', '백미 60g, 잡곡 15g, 콩 15g, 전복 15g, 낙지 15g, 칵테일 새우 15g,  양파 15g, 대파 15g, 마늘 10g, 브로콜리 30g
강황가루 15g, 올리브유 30g, 후추 3g, 굴소스 3g, 파슬리가루 3g', '["백미","잡곡","콩","전복","낙지","칵테일 새우","양파","대파","마늘","브로콜리","강황가루","올리브유","후추","굴소스","파슬리가루"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','f82b8382-3b65-4839-9f45-524168f3da07','5678a9c5-5df5-4a97-8f95-77df12578956','bd61e0e7-ed60-47e9-9a29-95dcc8ca68af','6f10b4ad-53a2-4a07-ba89-19a6b074373d','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','9bf64924-ce53-42bb-849e-7294416e95d6','a7cf6fb8-b34f-4cfe-a4af-d8e000090dcb','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','4362c386-a37c-44cd-9254-fafd74712a09']::uuid[], '[{"step":1,"text":"밥솥에 백미, 잡곡, 콩을 넣어 잡곡밥을 만든다.","imageUrl":null},{"step":2,"text":"양파, 대파, 마늘, 브로콜리를 잘게 다진다.","imageUrl":null},{"step":3,"text":"낙지, 전복을 끓는 물에 데친다.","imageUrl":null},{"step":4,"text":"낙지, 전복을 잘게 자른다.","imageUrl":null},{"step":5,"text":"달군 팬에 올리브유를 두르고 마늘, 대파, 칵테일 새우, 낙지, 전복, 양파, 브로콜리 순으로 볶는다.","imageUrl":null},{"step":6,"text":"재료가 익으면 잡곡밥을 넣고 굴소스, 강황가루, 후추를 넣고 볶은 후 파슬리가루를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112421_1732069461131.jpg', 568.5, 95.7, 23.4, 10.2, 451),
  ('2973', '토마토 채소 계란찜', '반찬', '방울토마토 20g, 양파 5g, 브로콜리 10g, 그린빈스 10g, 계란 80g, 파마산치즈 3g, 생크림 20g, 마늘 0.1g, 후추 0.1g', '["방울토마토","양파","브로콜리","그린빈스","계란","파마산치즈","생크림","마늘","후추"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9bf64924-ce53-42bb-849e-7294416e95d6','c7d438a6-34d6-423f-905d-446b839e2f39','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','af187077-b7f6-4b0e-9e99-f844f6359ac2','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"볼에 계란을 푼다.","imageUrl":null},{"step":2,"text":"마늘을 다져 계란과 섞고 파마산치즈, 후추를 넣어 간을 맞춘다.","imageUrl":null},{"step":3,"text":"양파는 채 썰고 브로콜리는 깍둑썰고 그린빈스는 2cm 길이로 자른다.","imageUrl":null},{"step":4,"text":"3의 재료를 볶은 뒤 계란물과 섞는다.","imageUrl":null},{"step":5,"text":"방울토마토를 반으로 잘라 4에 넣는다.","imageUrl":null},{"step":6,"text":"그릇에 옮겨 담아 찐다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113717_1554691037799.jpg', 181.76, 4, 11.68, 13.23, 159.3),
  ('3011', '배 깍두기', '반찬', '배 400g, 쪽파 5g, 고춧가루 8g, 액젓 15g, 마늘 3g', '["배","쪽파","고춧가루","액젓","마늘"]'::jsonb, ARRAY['eccf67f1-41f0-4a25-b238-6b9e7332c9e1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','84104c49-0af4-4323-a56b-b67002a422d9','5fd46a51-6998-4ac9-a1fb-cab1eedf7cd9','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"배 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"껍질 벗긴 배를 깍둑썰기 한다.","imageUrl":null},{"step":3,"text":"쪽파를 송송 썬다.","imageUrl":null},{"step":4,"text":"마늘을 곱게 다진다.","imageUrl":null},{"step":5,"text":"고춧가루, 액젓, 다진마늘, 쪽파를 섞어 양념을 만든다.","imageUrl":null},{"step":6,"text":"깍둑썰기한 배와 양념을 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410011724_1554869844830.jpg', 31.66, 6.33, 0.72, 0.39, 284.48),
  ('3063', '바지락가자미완탕국', '국&찌개', '가자미살 40g, 두부 20g, 양파 10g, 대파 5g, 후추 1.1g, 전분 3g, 바지락 60g, 무우 40g, 마늘 2g, 쑥갓 1g, 청홍고추 0.1g, 팽이버섯 0.1g, 물 300ml', '["가자미살","두부","양파","대파","후추","전분","바지락","무우","마늘","쑥갓","청홍고추","팽이버섯","물"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6613d1d9-80a2-4ce4-9d3d-647203197e53','b6047d76-6c94-4757-b1d1-9175aea0c84a','f80c9a7d-1510-44e2-a82b-28b9f684e191','fc6e31ce-388e-45cd-956b-b238b9134eb1','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"가시를 제거한 가자미와 양파, 대파는 다진다.","imageUrl":null},{"step":2,"text":"①에 으깬두부와 후추를 넣어 동그랗게 완자를 만든다.","imageUrl":null},{"step":3,"text":"무는 나박 썰기, 청?홍고추는 어슷썰기한다.","imageUrl":null},{"step":4,"text":"바지락은 해감 후 무와 함께 끓인다.","imageUrl":null},{"step":5,"text":"바지락 육수에 완자를 넣어 한소끔 끊인다.","imageUrl":null},{"step":6,"text":"마지막에 쑥갓, 청홍고추, 팽이버섯을 넣어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012513_1583727913803.jpg', 126.6, 14.8, 15.5, 0.6, 177.5),
  ('3163', '저염보쌈김치', '반찬', '"배추 17g, 배 3.0g, 대추슬라이스 0.2g, 깐밤 1.1g, 당근 1.0g 
(저염양념) 조선무 1.1g, 미나리 1.0g, 깐양파 1.1g,  파프리카 1.1g, 황설탕 0.1g, 잣 0.2g,  깐마늘 1.1g, 깐생강 0.2g, 멸치액젓 0.1g, 고춧가루 0.8g, 굵은소금 0.5g, 건표고버섯 0.1g, 국멸치 0.3g , 물 50ml"', '["\"배추","배","대추슬라이스","깐밤","당근","조선무","미나리","깐양파","파프리카","황설탕","잣","깐마늘","깐생강","멸치액젓","고춧가루","굵은소금","건표고버섯","국멸치","물"]'::jsonb, ARRAY['eccf67f1-41f0-4a25-b238-6b9e7332c9e1','e38c12a7-43cb-421a-a36e-7ef0d32517fa','dc7b2b73-74de-4fb8-9274-a5967ca444f9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','06e6f3e7-0293-469d-a338-11a610f3e71b','bbbbd533-8922-4dac-9e4c-cd93ea710c92','fc6e31ce-388e-45cd-956b-b238b9134eb1','5fd46a51-6998-4ac9-a1fb-cab1eedf7cd9','84104c49-0af4-4323-a56b-b67002a422d9','2cf0c12b-f248-4012-8f53-303c730a7b3d','66458b1b-c92f-43fa-8eba-e428892ce88a','dd2eee03-8bbf-44ff-8a7f-ed1443986711','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"배추는 손질하여 심심하게 절인다.","imageUrl":null},{"step":2,"text":"국멸치, 건표고버섯으로 육수를 낸다.","imageUrl":null},{"step":3,"text":"파프리카는 갈아서 즙을 짜서 준비한다.","imageUrl":null},{"step":4,"text":"식힌 육수에 파프리카 즙과 무, 미나리, 양파를 채쳐서 넣고 저염 양념을 만든다.","imageUrl":null},{"step":5,"text":"배, 대추, 밤, 당근은 마지막에 채쳐 섞는다.","imageUrl":null},{"step":6,"text":"저염 양념에 ⑤를 섞어서 절인 배추에 켜켜로 바른다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050101_1611561661950.JPG', 9.97, 1.96, 0.3, 0.11, 112.95),
  ('3207', '새우게살 파프리카롤', '일품', '크래비(20g), 냉동 새우살(20g), 파프리카(빨강, 주황, 노랑 각각 10g), 냉동 아보카도(15g), 절임 올리브(그린, 블랙 5g), 다진 파(2g), 다진 마늘(1g), 후춧가루(약간), 간 파르메산치즈(5g), 홀그레인 머스터드(5g), 요플레(20g), 올리고당(5g)', '["크래비","냉동 새우살","파프리카","냉동 아보카도","절임 올리브","다진 파","다진 마늘","후춧가루","간 파르메산치즈","홀그레인 머스터드","요플레","올리고당"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','5e79d288-1400-4817-bd20-e5e6041821b1','906bfef3-a41b-40d3-acda-7d8f23d2bcd2','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"크래비는 꼭 짜 물기를 제거하고, 새우살은 끓는 물에 1분간 데쳐 건진다.","imageUrl":null},{"step":2,"text":"파프리카는 약한 불에 구워 껍질을 검게 태운 뒤 찬물에 씻어 탄 부분을 제거한다.","imageUrl":null},{"step":3,"text":"구운 파프리카는 얇게 포를 뜨고, 아보카도와 크래비, 데친 새우살은 굵게 다진다.","imageUrl":null},{"step":4,"text":"손질한 아보카도, 크래비, 새우살에 다진 파, 다진 마늘, 후춧가루, 간 파르메산치즈, 파프리카 피클을 넣어 고루 섞어 소를 만든다.","imageUrl":null},{"step":5,"text":"비닐랩 위에 포 뜬 파프리카를 올린 뒤 가운데에 소를 넣어 돌돌 말아준다.","imageUrl":null},{"step":6,"text":"그릇에 소스를 담고 비닐랩을 제거한 롤을 올린 뒤 홀그레인 머스터드와 절임 올리브를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104030_1612834830514.jpg', 108.3, 8.9, 6.8, 5, 366),
  ('3247', '콩국물소스를 곁들인 게살 냉채', '일품', '게살(50g), 수박(70g), 가지(30g), 적채(20g), 브로콜리(20g), 두부(100g), 우유(100㎖), 꿀(5g), 소금(1g), 후춧가루(2g), 올리브유(5㎖)', '["게살","수박","가지","적채","브로콜리","두부","우유","꿀","소금","후춧가루","올리브유"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','fd4254d4-2691-47e1-9367-c2b820ef8d00','9bf64924-ce53-42bb-849e-7294416e95d6','4566cac5-9166-4c0d-906a-bfc7360f8f5b','e937397f-54e2-49df-997a-f393c58360be','286d1783-cd34-4aae-ac8b-006529ec8bc5','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"게살은 잘게 찢고, 수박, 가지, 적채, 브로콜리는 5cm 길이로 채 썬다.","imageUrl":null},{"step":2,"text":"끓는 물(5컵)에 손질한 브로콜리를 1분간 데쳐 찬물에 담가 체에 밭친다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 올리브유(5㎖)를 두른 뒤 가지를 2분간 볶는다.","imageUrl":null},{"step":4,"text":"믹서에 콩국물소스 재료를 넣고 갈아 콩국물소스를 만든다.","imageUrl":null},{"step":5,"text":"그릇에 수박 → 가지 → 브로콜리 → 적채 → 게살 순으로 쌓는다.","imageUrl":null},{"step":6,"text":"콩국물소스를 부어 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9c7', 231.6, 14.5, 16.3, 12, 475.4),
  ('3266', '방아잎 닭고기말이', '반찬', ' 아스파라거스(2개), 닭다릿살(400g), 방울토마토(4개), 방아잎(⅓줌=30g), 파르메산 치즈(1Ts), 레몬즙(0.5Ts), 맛간장(2Ts), 잣(1Ts), 마늘(3쪽), 올리브유(⅔컵), 간장(1컵), 물(½컵), 사과(½개), 양파(½개), 마늘(4쪽), 대파(½대), 플레인 요거트(½컵), 레몬즙(0.5ts), 무가당 아보카도 마요네즈(2Ts), 파르메산 치즈(1Ts), 스테이크 시즈닝(1ts), 파슬리가루(약간)', '["아스파라거스","닭다릿살","방울토마토","방아잎","파르메산 치즈","레몬즙","맛간장","잣","마늘","올리브유","간장","물","사과","양파","대파","플레인 요거트","무가당 아보카도 마요네즈","스테이크 시즈닝","파슬리가루"]'::jsonb, ARRAY['a8462d27-4ef1-4919-ae9b-10c8f8b9545f','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','f175019d-5a93-4cd4-aabc-e7e79445f15a','bbbbd533-8922-4dac-9e4c-cd93ea710c92','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','94786475-832c-4f97-aab7-bf6fbbe2236b','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','bb41a88a-ea2b-4830-876d-91fe7f640296','4362c386-a37c-44cd-9254-fafd74712a09']::uuid[], '[{"step":1,"text":"아스파라거스는 두꺼운 밑동을 잘라내고, 방아잎은 깨끗이 씻어 물기를 제거한다.","imageUrl":null},{"step":2,"text":"믹서에 방아잎 페스토 재료를 넣어 곱게 갈고, 요거트 소스 재료를 모두 섞는다.","imageUrl":null},{"step":3,"text":"닭다릿살을 넓게 편 뒤 방아잎 페스토 (4Ts)를 올리고, 파르메산 치즈를 올린 뒤 스테이크 시즈닝과 파슬리가루를 넣어 돌돌 말고, 풀리지 않도록 실로 묶는다.","imageUrl":null},{"step":4,"text":"중간 불로 달군 팬에 식용유를 두르고, 돌돌 만 닭다릿살을 넣어 5분간 튀기듯 굽는다.","imageUrl":null},{"step":5,"text":"같은 팬에 아스파라거스와 방울토마토를 넣어 2분간 볶는다.","imageUrl":null},{"step":6,"text":"그릇에 구운 닭다릿살과 아스파라거스, 방울토마토를 올리고 요거트 소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9XmD', 501.9, 4.8, 43.8, 34.2, 344.1),
  ('3278', '새우 카레 빠에야', '밥', ' 양파(½개), 토마토(2개), 새우(8마리), 쌀(1½컵), 카레가루(1Ts), 황태 머리(1개), 다시마(5×5cm, 1장), 다진 마늘(1Ts), 파슬리가루(0.3Ts), 후춧가루(0.3Ts)', '["양파","토마토","새우","쌀","카레가루","황태 머리","다시마","다진 마늘","파슬리가루","후춧가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','6f10b4ad-53a2-4a07-ba89-19a6b074373d','a5bc0b46-0192-496a-b429-d2cb90b2bca9','495b9f1e-aa3b-4506-9bb8-feb0a493901e','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','fc6e31ce-388e-45cd-956b-b238b9134eb1','4362c386-a37c-44cd-9254-fafd74712a09','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"양파는 얇게 채 썰고, 토마토는 윗부분을 약간 자른 뒤 속을 파내고, 새우는 머리와 껍질을 제거한다.","imageUrl":null},{"step":2,"text":"냄비에 물(3컵)과 육수 재료를 넣어 중간 불에 15분간 끓여 육수를 만든다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 식용유를 두르고, 양파와 다진 마늘을 넣어 양파가 갈색이 될 때까지 볶는다.","imageUrl":null},{"step":4,"text":"토마토 속을 넣어 3분간 더 볶고, 쌀과 육수(2컵)를 넣어 끓으면 약한 불로 줄인 뒤 뚜껑을 덮어 15분간 더 끓인다.","imageUrl":null},{"step":5,"text":"뚜껑을 열어 새우를 올리고, 뚜껑을 다시 덮어 5분간 더 끓이고, 불을 꺼 5분간 뜸을 들인다.","imageUrl":null},{"step":6,"text":"파슬리가루와 후춧가루를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr94dA', 366.9, 60.6, 14.9, 7.2, 370.6),
  ('3367', '오징어 가라아게&칠리소스', '반찬', ' 오징어(80g), 대파(20g), 마늘(10g), 달걀노른자(25g), 밀가루(20g), 식용유(3g)
, 토마토(20g), 고춧가루(15g), 식초(50g), 설탕(15g), 전분(10g)', '["오징어","대파","마늘","달걀노른자","밀가루","식용유","토마토","고춧가루","식초","설탕","전분"]'::jsonb, ARRAY['4d148f68-08e0-4599-8953-595db492bf23','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c7d438a6-34d6-423f-905d-446b839e2f39','aab3b0b9-d346-4697-a1c8-1b1530153788','a7a59e81-de3d-4893-b56a-b2218732a25b','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','84104c49-0af4-4323-a56b-b67002a422d9','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','6613d1d9-80a2-4ce4-9d3d-647203197e53']::uuid[], '[{"step":1,"text":"오징어는 채 썰고, 마늘과 대파는 곱게 다진다.","imageUrl":null},{"step":2,"text":"오징어, 대파, 마늘, 달걀노른자, 밀가루, 물(10g)을 섞어 반죽한 뒤 동그랗게 빚는다.","imageUrl":null},{"step":3,"text":"가라아게를 180℃ 온도의 기름에서 튀긴다.","imageUrl":null},{"step":4,"text":"토마토는 껍질을 제거한 뒤 잘게 다진다.","imageUrl":null},{"step":5,"text":"냄비에 다진 토마토, 식초, 설탕, 물(50g), 고춧가루, 전분을 넣고 끓여 칠리소스를 만든다.","imageUrl":null},{"step":6,"text":"오징어 가라아게에 칠리소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032043_1678342843593.jpg', 595.1, 30.4, 25.1, 41.5, 307.7),
  ('3466', '토마토 채소 가지롤', '반찬', ',  순두부(1/2봉지=175g), 팽이버섯(150g), 애호박(30g), 양파(40g), 파(30g), 청양고추(8g), 느타리버섯(33g), 마늘(18g), 차돌박이(87g),  토마토(260g), 가지(120g), 올리브유(50g), 레몬즙(8g), 소금(15g), 후추(6g)', '["순두부","팽이버섯","애호박","양파","파","청양고추","느타리버섯","마늘","차돌박이","토마토","가지","올리브유","레몬즙","소금","후추"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','7c91e298-5ace-4242-8619-cdcc80587cd7','fc6e31ce-388e-45cd-956b-b238b9134eb1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','3e12cf79-2cde-4309-9f7c-4eccce3fde28','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"껍질을 벗긴 토마토, 마늘, 파, 양파, 애호박, 느타리버섯, 팽이버섯을 다진다.","imageUrl":null},{"step":2,"text":"팬에 올리브유(20g)를 두르고 마늘, 양파를 넣고 볶다가 토마토를 넣고 소금(4g), 후추(3g)로 간하고 졸여 토마토 소스를 만든다.","imageUrl":null},{"step":3,"text":"믹서에 순두부, 올리브유(10g), 소금(4g), 레몬즙을 넣고 갈아 순두부크림 소스를 만든다.","imageUrl":null},{"step":4,"text":"팬에 올리브유(5g)를 두르고 차돌박이를 구운 후, 같은 팬에 올리브유(15g)를 두르고 파, 애호박, 느타리버섯, 팽이버섯을 볶고 소금(7g)으로 간한다.","imageUrl":null},{"step":5,"text":"가지를 얇게 잘라 팬에 가볍게 굽고 ④를 올리고 돌돌 말아준다.","imageUrl":null},{"step":6,"text":"토마토 소스를 아래에 깔고 ⑤를 올리고, 순두부크림 소스를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035912_1699253952214.jpg', 414.6, 19.2, 9.6, 33.3, 361.3),
  ('3571', '토마토시금치 닭볶음탕', '반찬', ',
닭다리살(25g), 닭안심살(30g), 토마토(35g), 방울토마토(15g), 시금치(5g), 양파(10g), 감자(7g), 스파게티면(건면)(5g),
l고추장(5g), 고춧가루(3g), 다진 마늘(3g), 진간장(4g), 알룰로스(4g)', '["닭다리살","닭안심살","토마토","방울토마토","시금치","양파","감자","스파게티면","l고추장","고춧가루","다진 마늘","진간장","알룰로스"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','9a7f4da6-531b-4478-89ff-d73beafcad1b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','20894da1-739d-4d52-b5fe-4943bd3492d5','b85df3ba-e324-47fa-b25d-d5bb552b8590','84104c49-0af4-4323-a56b-b67002a422d9','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"닭다리살, 닭안심살은 키친타월로 물기를 제거하고 끓는 물에 데쳐 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"칼집을 낸 토마토를 뜨거운 물에 살짝 데치고 껍질을 제거하여 깍둑썰고, 방울토마토는 모양을 살려 반으로 자른다.","imageUrl":null},{"step":3,"text":"양파, 감자는 껍질을 제거하고 깍둑썬다. 시금치는 밑동을 제거하고 깨끗이 씻어 한입 크기로 썬다.","imageUrl":null},{"step":4,"text":"볼에 손질한 닭고기, 양파, 감자를 담고, 고추장, 고춧가루, 다진 마늘, 진간장, 알룰로스를 넣어 버무린다.","imageUrl":null},{"step":5,"text":"달군 팬에 넣고 중약 불로 살짝 볶은 후 물을 부어 끓인다. 채소가 익으면 불을 끄고 시금치를 넣어 잔열로 익힌다.","imageUrl":null},{"step":6,"text":"접시에 담고 삶은 스파게티면을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120010619_1732075579019.jpg', 90.1, 8.2, 8.2, 2.7, 76.1),
  ('2976', '콜라비 깍두기', '반찬', ' 콜라비(80g), 쪽파(5g), 홍고추(0.5g), 생강(0.1g), 양파(0.1g), 마늘(1g)
, 고춧가루(4g), 액젓(1g), 매실청(0.2g)
, 천일염(0.1g)', '["콜라비","쪽파","홍고추","생강","양파","마늘","고춧가루","액젓","매실청","천일염"]'::jsonb, ARRAY['715e97fc-4781-4f58-8be6-fbfe30b9abe6','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','84104c49-0af4-4323-a56b-b67002a422d9','5fd46a51-6998-4ac9-a1fb-cab1eedf7cd9','02fd7135-0ec3-49ec-82e3-390536ab2cf5','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"콜라비는 껍질을 벗긴 뒤 깍둑 썬다.","imageUrl":null},{"step":2,"text":"손질한 콜라비에 천일염을 뿌려 1시간 동안 절인다.","imageUrl":null},{"step":3,"text":"홍고추, 양파, 생강, 마늘을 믹서에 곱게 간다.","imageUrl":null},{"step":4,"text":"갈아 낸 채소에 양념장 재료를 넣어 양념장을 만든다.","imageUrl":null},{"step":5,"text":"절여 놓은 콜라비는 물기를 제거하고, 쪽파는 적당한 길이로 썬다.","imageUrl":null},{"step":6,"text":"콜라비에 쪽파, 양념장을 넣고 버무려 하루 동안 숙성해 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044956_1678175396907.jpg', 14, 2.6, 0.6, 0.2, 40.5),
  ('2981', '비타 오이 물김치', '반찬', '오이 30g, 무 50g, 홍고추 10g, 파프리카 20g, 당근 20g, 미나리 10g, 식초 30g, 배 30g, 고춧가루 10g, 설탕 5g', '["오이","무","홍고추","파프리카","당근","미나리","식초","배","고춧가루","설탕"]'::jsonb, ARRAY['9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','f80c9a7d-1510-44e2-a82b-28b9f684e191','30b5d53c-d247-4f04-9b50-c0f728e65cf9','5e79d288-1400-4817-bd20-e5e6041821b1','e38c12a7-43cb-421a-a36e-7ef0d32517fa','dc7b2b73-74de-4fb8-9274-a5967ca444f9','6c285c60-022a-4a00-b172-87df97f16a2f','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','84104c49-0af4-4323-a56b-b67002a422d9','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"오이와 무를 필러로 길게 슬라이스 한다.","imageUrl":null},{"step":2,"text":"설탕물을 만들어 무가 잘 구부러질 때 까지 재운 뒤 씻어낸다.","imageUrl":null},{"step":3,"text":"당근과 홍고추, 파프리카는 5cm 길이로 채 썬다.","imageUrl":null},{"step":4,"text":"미나리를 데쳐 식힌 뒤 한 줄씩 찢는다.","imageUrl":null},{"step":5,"text":"오이, 무를 겹쳐 채 썬 재료를 넣고 말아준 뒤 데친 미나리로 묶는다.","imageUrl":null},{"step":6,"text":"배를 갈아 물, 식초, 고춧가루와 섞어 양념장을 만든 뒤 5를 넣고 재운다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408013158_1554697918452.jpg', 13.46, 2.99, 0.34, 0.02, 30.88),
  ('3065', '감자미역국', '국&찌개', '건미역 1.5g, 감자 40g, 다진마늘 1g, 참기름 1g, 국간장 2g, 물 300ml', '["건미역","감자","다진마늘","참기름","국간장","물"]'::jsonb, ARRAY['6565cc3a-c3d6-45b5-a7fb-05a3c03015bf','20894da1-739d-4d52-b5fe-4943bd3492d5','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482','f175019d-5a93-4cd4-aabc-e7e79445f15a','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"미역을 물에 불리고 건져내 물기를 제거한다.","imageUrl":null},{"step":2,"text":"감자는 껍질을 제거하고 한입 크기로 자른다.","imageUrl":null},{"step":3,"text":"냄비에 참기름을 두르고 미역을 볶다가 물을 부어 끓인다.","imageUrl":null},{"step":4,"text":"국물이 우러나면 감자를 넣고 익을 때까지 끓인다.","imageUrl":null},{"step":5,"text":"국간장을 넣어 간을 맞춘다.","imageUrl":null},{"step":6,"text":"다진마늘을 넣고 한소끔 더 끓여서 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309015125_1583729485543.JPG', 35.4, 2.5, 1.1, 2.3, 174.6),
  ('3164', '청경채 김치', '반찬', ' 청경채(60g), 배(10g)
, 매실액(5g), 고춧가루(5g), 저염간장(3g), 다진마늘(1g), 다진생강(2g)
, 소금(2g), 찹쌀가루(10g)', '["청경채","배","매실액","고춧가루","저염간장","다진마늘","다진생강","소금","찹쌀가루"]'::jsonb, ARRAY['7ac59c14-e767-4f32-a2e5-d558c1a29dfb','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','02fd7135-0ec3-49ec-82e3-390536ab2cf5','84104c49-0af4-4323-a56b-b67002a422d9','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','2cf0c12b-f248-4012-8f53-303c730a7b3d','4cb11562-015f-4ab5-969f-0ea8483a0b42']::uuid[], '[{"step":1,"text":"청경채는 반으로 자른 후 줄기 부분에 칼집을 넣는다.","imageUrl":null},{"step":2,"text":"청경채에 소금을 뿌려 30~40분 정도 절인다.","imageUrl":null},{"step":3,"text":"배는 껍질을 벗긴 후 강판에 갈아 즙을 만든다.","imageUrl":null},{"step":4,"text":"냄비에 물(30g)과 찹쌀가루를 넣고 끓여 찹쌀풀을 만들고, 충분히 식힌다.","imageUrl":null},{"step":5,"text":"볼에 식힌 찹쌀풀, 배즙, 양념장 재료를 넣고 고루 섞어 양념장을 만든다.","imageUrl":null},{"step":6,"text":"절인 청경채의 물기를 제거하고, 양념장을 버무려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030413_1678341853588.jpg', 53.7, 9.9, 1.9, 0.7, 382.6),
  ('3208', '두부 새우볼', '일품', '두부(100g), 냉동 새우살(90g), 양파(30g), 새송이버섯(100g), 생강가루(1g), 후춧가루(1g), 소금(1g), 소금(1g), 후춧가루(1g), 파슬리가루(2g), 식용유(25ml), 버터(10g), 밀가루(10g), 우유(360㎖)', '["두부","냉동 새우살","양파","새송이버섯","생강가루","후춧가루","소금","파슬리가루","식용유","버터","밀가루","우유"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','6f10b4ad-53a2-4a07-ba89-19a6b074373d','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','3f94371a-728f-49ae-8ea9-1a1e87b68048','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d','4362c386-a37c-44cd-9254-fafd74712a09','a7a59e81-de3d-4893-b56a-b2218732a25b','7aabd532-361f-4240-aa33-6bfa1be4bc4e','aab3b0b9-d346-4697-a1c8-1b1530153788','e937397f-54e2-49df-997a-f393c58360be']::uuid[], '[{"step":1,"text":"두부는 물기를 제거한 뒤 칼등으로 으깨고, 새우와 양파는 잘게 다지고, 새송이버섯은 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"으깬 두부와 잘게 다진 새우, 양파는 밑간해 고루 버무린 뒤 적당량(25g)씩 떼어 동그랗게 빚는다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 식용유(25㎖)를 둘러 10~15분간 두부새우볼을 골고루 익혀 꺼낸다.","imageUrl":null},{"step":4,"text":"같은 팬에 새송이버섯을 5분간 볶아 꺼낸다.","imageUrl":null},{"step":5,"text":"약한 불로 줄인 뒤 같은 팬에 버터와 밀가루를 넣고 3~5분간 볶아 블론드 루를 만들고 우유를 부은 뒤 10분간 끓인다.","imageUrl":null},{"step":6,"text":"구운 두부새우볼과 버섯, 소금(1g), 후춧가루(1g)를 넣은 뒤 그릇에 담고 파슬리가루(2g)를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104612_1612835172747.jpg', 187.1, 8.4, 15.3, 10.3, 288.1),
  ('3248', '소고기육전과 전복내장소스', '일품', '부챗살(150g), 쪽파(5g), 홍고추(5g), 익힌 전복내장(5g), 다진 건새우(5g), 밀가루(20g), 달걀물(50g), 생강(1g), 저염 간장(5g), 맛술(2g), 식초(2g), 참기름(1g), 후춧가루(2g), 식용유(10ml)', '["부챗살","쪽파","홍고추","익힌 전복내장","다진 건새우","밀가루","달걀물","생강","저염 간장","맛술","식초","참기름","후춧가루","식용유"]'::jsonb, ARRAY['4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6f10b4ad-53a2-4a07-ba89-19a6b074373d','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','f175019d-5a93-4cd4-aabc-e7e79445f15a','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','6c285c60-022a-4a00-b172-87df97f16a2f','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"부챗살은 3mm로 썰어 후춧가루를 뿌려 버무리고, 쪽파, 홍고추, 익힌 전복내장은 잘게 다진다.","imageUrl":null},{"step":2,"text":"밀가루에 다진 건새우를 섞은 뒤, 부챗살에 밀가루 → 달걀물 순으로 입힌다.","imageUrl":null},{"step":3,"text":"다진 쪽파, 홍고추, 익힌 전복내장에 초간장 재료를 섞어 전복내장소스를 만든다.","imageUrl":null},{"step":4,"text":"중간 불로 달군 팬에 식용유(10㎖)를 두른 뒤 옷을 입힌 부챗살을 앞뒤로 4분간 굽는다.","imageUrl":null},{"step":5,"text":"그릇에 구운 부챗살을 담고 전복내장소스를 곁들인다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9m5', 341.6, 11.8, 16.6, 25.3, 191.6),
  ('3267', '라이스페이퍼 수제소시지', '반찬', ' 다진 돼지고기(600g), 사각 라이스페이퍼(8장), 새우젓(0.5Ts), 저염 간장(0.5Ts), 버섯가루(1Ts), 스테비아(0.3Ts), 찹쌀가루(2Ts), 후춧가루(0.3Ts), 훈제 파프리카파우더(1.5Ts), 카옌 페퍼(0.5Ts), 커민(0.5Ts), 다진 양파(1Ts), 다진 마늘(0.5Ts)', '["다진 돼지고기","사각 라이스페이퍼","새우젓","저염 간장","버섯가루","스테비아","찹쌀가루","후춧가루","훈제 파프리카파우더","카옌 페퍼","커민","다진 양파","다진 마늘"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','8f2077de-dbd0-4372-a4c2-f987388f16b3','f175019d-5a93-4cd4-aabc-e7e79445f15a','49b48723-2e40-46b0-9588-00f41a6a02c2','4cb11562-015f-4ab5-969f-0ea8483a0b42','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"다진 돼지고기(300g)에 밑간한 뒤 얼음물(¼컵)을 넣어 찰기가 생길 때까지 치대 소시지 반죽을 만든다.","imageUrl":null},{"step":2,"text":"남은 다진 돼지고기(300g)에 양념과 얼음물(¼컵)을 넣고 고루 섞어 치대 다른 소시지 반죽을 만든다.","imageUrl":null},{"step":3,"text":"두 가지 소시지 반죽은 짤주머니에 각각 담아 냉장실에서 30분간 숙성한다.","imageUrl":null},{"step":4,"text":"라이스페이퍼 양면에 물을 약간 묻히고, 소시지 반죽을 일정하게 짠 뒤 돌돌 말아 소시지를 만든다.","imageUrl":null},{"step":5,"text":"약한 불로 달군 팬에 식용유를 두르고, 소시지를 돌려가며 5분간 골고루 익힌다.","imageUrl":null},{"step":6,"text":"센 불로 올려 1분간 더 익혀 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeu8m', 542.8, 38.3, 38.6, 26.1, 451.7),
  ('3277', '치즈토마토 가지구이', '일품', ' 새송이버섯(1개), 양파(½개), 토마토(2~3개), 가지(2개), 돼지고기(목살, 200g), 슈레드 모차렐라치즈(½컵), 올리브유(1Ts), 다진 마늘(2Ts), 쌈장(0.5Ts), 파프리카가루(약간), 바질잎(3~4장)', '["새송이버섯","양파","토마토","가지","돼지고기","슈레드 모차렐라치즈","올리브유","다진 마늘","쌈장","파프리카가루","바질잎"]'::jsonb, ARRAY['3f94371a-728f-49ae-8ea9-1a1e87b68048','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','3e12cf79-2cde-4309-9f7c-4eccce3fde28','70e914d4-0d03-4202-8b66-81bd8499aa08','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','fc6e31ce-388e-45cd-956b-b238b9134eb1','5e79d288-1400-4817-bd20-e5e6041821b1']::uuid[], '[{"step":1,"text":"새송이버섯, 양파, 토마토는 굵게 다지고, 가지는 모양대로 길게 썰고, 돼지고기는 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"중간 불로 달군 마른 팬에 가지를 올려 앞뒤로 노릇하게 굽는다.","imageUrl":null},{"step":3,"text":"같은 팬에 올리브유를 두르고 다진 마늘을 넣어 노릇하게 볶고, 양파와 새송이버섯을 넣어 양파가 투명해질 때까지 볶는다.","imageUrl":null},{"step":4,"text":"중간 불로 올린 뒤 목살을 넣어 겉면의 색이 변할 때까지 볶고, 토마토를 넣어 으깬다.","imageUrl":null},{"step":5,"text":"쌈장과 파프리카가루를 넣어 고루 섞고, 토마토 국물이 배어 나오면 바질을 손으로 뜯어 넣은 뒤 국물이 자작해질 때까지 끓인다.","imageUrl":null},{"step":6,"text":"그릇에 ⑤의 재료를 담은 뒤 가지를 엇갈려 올리고, 치즈를 얹은 뒤 전자레인지에 넣어 모차렐라치즈가 녹을 때까지 조리해 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr94St', 263.6, 9.4, 14.8, 18.5, 200.7),
  ('3288', '묵은지 밀푀유나베', '국&찌개', ' 묵은지(¼포기), 배추(6장), 깻잎(10장), 소고기(샤브샤브용, 150g), 콩나물(1줌=20g), 북어채(1줌=10g)', '["묵은지","배추","깻잎","소고기","콩나물","북어채"]'::jsonb, ARRAY['133f214e-50f4-431d-af36-d97f6c9d4f9b','e116f85b-0eaa-40cb-8107-df5ec8486ad4','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','1c49d1f4-5781-474d-818d-bd7002a4dc0b','2db049b2-f39c-47ba-857f-fa02b3b0c610','a6228d2a-6158-4542-bb52-b4f41a06f448']::uuid[], '[{"step":1,"text":"묵은지는 흐르는 물에 헹군 뒤 찬물에 30분간 담가둔다.","imageUrl":null},{"step":2,"text":"배추, 깻잎, 소고기, 묵은지 순으로 층층이 쌓는다.","imageUrl":null},{"step":3,"text":"쌓은 재료를 3~4cm 크기로 자른다.","imageUrl":null},{"step":4,"text":"냄비에 재료를 둘러 담고, 가운데에 콩나물과 북어채를 담는다.","imageUrl":null},{"step":5,"text":"물(3컵)을 넣는다.","imageUrl":null},{"step":6,"text":"중간 불로 10분간 끓여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr99W1', 115.5, 5.2, 12.1, 5.2, 356.5),
  ('3363', '생선까스&타르타르소스', '반찬', ' 명태포(40g), 튀김가루(20g), 달걀(1/4개), 식용유(5g), 물(30g)
, 후춧가루(1g), 레몬즙(3g)
, 삶은 달걀(1/2개), 마요네즈(5g), 홍고추(1g), 청양고추(1g), 양파(3g), 후추(2g), 레몬즙(10g)', '["명태포","튀김가루","달걀","식용유","물","후춧가루","레몬즙","삶은 달걀","마요네즈","홍고추","청양고추","양파","후추"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','a7a59e81-de3d-4893-b56a-b2218732a25b','94786475-832c-4f97-aab7-bf6fbbe2236b','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','549c7365-28e9-491f-9040-412558f93a5c','30b5d53c-d247-4f04-9b50-c0f728e65cf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742']::uuid[], '[{"step":1,"text":"명태포는 키친타월에 올려 물기를 제거한다.","imageUrl":null},{"step":2,"text":"후춧가루와 레몬즙을 뿌려 비린내를 제거한다.","imageUrl":null},{"step":3,"text":"볼에 튀김가루와 달걀, 식용유, 물을 섞어 튀김옷을 만든다","imageUrl":null},{"step":4,"text":"명태포에 튀김옷을 입힌 뒤 170℃ 기름에서 두 번 튀긴다.","imageUrl":null},{"step":5,"text":"삶은 달걀, 홍고추, 청양고추, 양파를 다져 볼에 섞은 뒤 마요네즈와 레몬즙, 후춧가루를 섞어 소스를 만든다","imageUrl":null},{"step":6,"text":"생선까스에 타르타르소스를 곁들여 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313013838_1678682318628.jpg', 277.3, 8, 14.5, 20.8, 201.2),
  ('3469', '미옹 카레', '반찬', ',  커리 소스(80g), 홍새우 튀김(150g), 컬리플라워(50g), 감자튀김(100g),  감자(2개=360g), 불린 미역(70g, 마른 미역 10g), 양파(110g), 식용유(10g), 물(100g)', '["커리 소스","홍새우 튀김","컬리플라워","감자튀김","감자","불린 미역","양파","식용유","물"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','a7a59e81-de3d-4893-b56a-b2218732a25b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"감자로 만든 옹심이 반죽을 숟가락의 절반 크기로 동그랗게 모양을 만든다.","imageUrl":null},{"step":2,"text":"180도로 예열한 에어프라이어에 홍새우 튀김을 15분 동안 익힌다.","imageUrl":null},{"step":3,"text":"팬에 식용유를 두르고 양파를 채 썰어 넣고 갈색이 나도록 볶는다.","imageUrl":null},{"step":4,"text":"컬리플라워, 감자튀김, 불린 미역을 넣고 3분 동안 더 볶는다.","imageUrl":null},{"step":5,"text":"커리 소스, 물(1/2컵=100g), 옹심이를 넣고 3분 동안 끓인다.","imageUrl":null},{"step":6,"text":"접시에 담고 홍새우 튀김을 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041400_1699254840769.jpg', 298.6, 30.7, 6.8, 16.6, 579.7),
  ('2978', '곤약 감자조림', '반찬', '곤약 100g, 감자 50g, 풋고추 5g, 홍고추 5g, 다시마 10g, 간장 15g, 설탕 10g, 미림 15g, 참기름 3g, 식초 10g, 물 200g', '["곤약","감자","풋고추","홍고추","다시마","간장","설탕","미림","참기름","식초","물"]'::jsonb, ARRAY['54a52322-b4df-4354-a7a5-2a7b0c41f7bd','20894da1-739d-4d52-b5fe-4943bd3492d5','30b5d53c-d247-4f04-9b50-c0f728e65cf9','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','0c0ade94-cfd8-4104-b44c-40e942cac482','6c285c60-022a-4a00-b172-87df97f16a2f','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"곤약과 감자는 2cm ? 2cm 크기로 썰고 풋고추와 홍고추는 송송 썰어 씨를 제거한다.","imageUrl":null},{"step":2,"text":"물(200g)에 다시마를 넣고 끓여 육수를 만든 뒤 다시마를 건진다.","imageUrl":null},{"step":3,"text":"육수에 간장, 설탕, 미림을 섞어 조림장을 만든다.","imageUrl":null},{"step":4,"text":"곤약과 감자를 끓는 물에 넣고 80% 정도 익힌 뒤 건져 식힌다.","imageUrl":null},{"step":5,"text":"4에 조림장 50g을 넣고 살짝 졸인다.","imageUrl":null},{"step":6,"text":"불을 끄고 참기름을 섞는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011910_1554697150266.jpg', 37.8, 8.78, 0.64, 0.01, 305),
  ('3067', '배추된장국', '국&찌개', '배추 20g, 두부 30g, 양파 20g, 대파 10g, 다시멸치 5g, 청양고추 1g, 다진마늘 0.5g, 생강즙 0.5g, 된장 2g, 쌀뜨물 60ml, 물 300ml', '["배추","두부","양파","대파","다시멸치","청양고추","다진마늘","생강즙","된장","쌀뜨물","물"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','4566cac5-9166-4c0d-906a-bfc7360f8f5b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','392236b1-82e9-4e38-bd12-6a53b80bf463','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"배추, 양파, 두부는 한입 크기로 썰고 대파와 청양고추는 어슷썰어 준비한다.","imageUrl":null},{"step":2,"text":"전처리 후 남은 양파껍질, 대파뿌리와 다시멸치를 넣고 육수를 우린 후 거른다.","imageUrl":null},{"step":3,"text":"두부는 끓는 물에 10분정도 넣어서 염분기를 빼준다.","imageUrl":null},{"step":4,"text":"냄비에 참기름과 배추를 넣어 볶다가 쌀뜨물과 육수를 넣어 끓인다.","imageUrl":null},{"step":5,"text":"두부와 양파, 대파, 고추를 넣는다.","imageUrl":null},{"step":6,"text":"된장, 간마늘, 생강즙을 넣어 간을 맞춘다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309022612_1583731572075.JPG', 44.9, 4, 4.2, 1.3, 52.1),
  ('3070', '한우굴라쉬', '국&찌개', '쇠고기 등심 17.5g, 양파 7.5g, 감자 15g, 파프리카 3.2g, 토마토 25g, 마늘 1.7g, 밀가루 1.7g, 토마토페이스트 13.7g, 케첩 9g, 버터 5g, 올리브유 1g, 월계수잎 0.1g, 소금 0.1g, 후추 0.1g, 물 300ml', '["쇠고기 등심","양파","감자","파프리카","토마토","마늘","밀가루","토마토페이스트","케첩","버터","올리브유","월계수잎","소금","후추","물"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','20894da1-739d-4d52-b5fe-4943bd3492d5','5e79d288-1400-4817-bd20-e5e6041821b1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','fc6e31ce-388e-45cd-956b-b238b9134eb1','aab3b0b9-d346-4697-a1c8-1b1530153788','76e95535-f965-4685-a7a6-55ae26aa202c','0136fc6a-3a80-4f4c-8057-10bbf34ea572','7aabd532-361f-4240-aa33-6bfa1be4bc4e','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','043a9631-bb6e-42e6-9673-4943457502fb','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"쇠고기 등심은 큐브 모양으로 썰어 소금, 후추 간을 하고 밀가루를 묻힌다.","imageUrl":null},{"step":2,"text":"감자, 토마토는 한 입 크기로 썰고, 마늘은 편썰기, 파프리카는 채썰기, 양파는 다진다.","imageUrl":null},{"step":3,"text":"팬에 버터와 올리브유를 넣고 양파, 마늘을 볶다가 쇠고기를 넣어 볶는다.","imageUrl":null},{"step":4,"text":"쇠고기가 익으면 감자, 토마토, 파프리카를 넣는다.","imageUrl":null},{"step":5,"text":"토마토 페이스트, 케찹을 넣어 볶다가 물과 월계수잎을 넣어 끓인다.","imageUrl":null},{"step":6,"text":"소금, 후추로 간을 하고 푹 익혀준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309035140_1583736700730.jpg', 86.7, 9.6, 4.4, 3.4, 178.5),
  ('3165', '요거트강화순무김치', '반찬', '순무 40g, 쪽파 0.2g, 고운 고춧가루 1g, 굵은 고춧가루 1g, 다진마늘 1g, 플레인요거트 2g, 소금 0.2g', '["순무","쪽파","고운 고춧가루","굵은 고춧가루","다진마늘","플레인요거트","소금"]'::jsonb, ARRAY['4b410642-7bf9-45ad-9055-e7d9a34edaa1','84104c49-0af4-4323-a56b-b67002a422d9','fc6e31ce-388e-45cd-956b-b238b9134eb1','bb41a88a-ea2b-4830-876d-91fe7f640296','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"순무는 2.5*2.5*0.3 cm 크기로 나박 모양으로 썬다.","imageUrl":null},{"step":2,"text":"고운 고춧가루, 굵은 고춧가루, 다진마늘, 소금, 요거트를 섞어 양념장을 만든다.","imageUrl":null},{"step":3,"text":"쪽파는 0.2cm 크기로 송송 썰어 준비한다.","imageUrl":null},{"step":4,"text":"순무에 양념장을 넣고 버무려 준다.","imageUrl":null},{"step":5,"text":"양념된 순무를 하루 정도 냉장보관하여 숙성시킨다.","imageUrl":null},{"step":6,"text":"숙성된 순무김치에 쪽파를 고명으로 얹어 제공한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050922_1611562162968.jpg', 15.87, 2.75, 0.9, 0.14, 29.8),
  ('3211', '크림카레소스를 곁들인 함초두부스테이크', '기타', '양파(30g), 당근(20g), 양송이버섯(20g), 불린 함초(15g), 으깬 두부(120g), 닭가슴살(60g), 달걀(40g), 빵가루(5g), 밀가루(10g), 버터(10g), 우유(250g), 강황가루(10g), 함초소금(0.5g), 다진 마늘(5g), 저염 간장(3g), 식용유(10ml)', '["양파","당근","양송이버섯","불린 함초","으깬 두부","닭가슴살","달걀","빵가루","밀가루","버터","우유","강황가루","함초소금","다진 마늘","저염 간장","식용유"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','4566cac5-9166-4c0d-906a-bfc7360f8f5b','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','c7d438a6-34d6-423f-905d-446b839e2f39','45080597-55fa-42dc-aa65-12d7694e4b7e','aab3b0b9-d346-4697-a1c8-1b1530153788','7aabd532-361f-4240-aa33-6bfa1be4bc4e','e937397f-54e2-49df-997a-f393c58360be','a7cf6fb8-b34f-4cfe-a4af-d8e000090dcb','2cf0c12b-f248-4012-8f53-303c730a7b3d','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"양파와 당근, 양송이버섯, 불린 함초는 잘게 다진다.","imageUrl":null},{"step":2,"text":"으깬 두부는 물기를 제거한 뒤 닭가슴살과 믹서에 넣어 곱게 갈고 다진 양파(20g), 당근(10g), 함초(7.5g), 달걀, 빵가루, 함초소금(0.25g)을 넣어 버무린다.","imageUrl":null},{"step":3,"text":"두부 반죽은 동그랗게 만들어 중간 불로 달군 팬에 식용유(10㎖)를 두른 뒤 4분간 앞뒤로 노릇하게 구워 꺼낸다.","imageUrl":null},{"step":4,"text":"약한 불로 달군 냄비에 밀가루, 버터를 넣어 루를 만들고 우유, 강황가루, 다진 양파(10g)와 당근(10g), 양송이버섯, 다진 마늘(5g)을 넣어 섞은 뒤 저염 간장(3g), 함초소금(0.25g)으로 간한다.","imageUrl":null},{"step":5,"text":"믹서에 소스와 다진 함초(7.5g)를 넣어 곱게 간다.","imageUrl":null},{"step":6,"text":"그릇에 함초두부스테이크를 올리고 소스를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210102914_1612920554422.jpg', 289.9, 13.4, 28.7, 13.5, 349.6),
  ('3268', '레몬등갈비구이', '반찬', ' 등갈비(150g), 마늘(10g), 레몬(15g)
, 소주(10g), 로즈메리(1g), 다진마늘(1g), 후춧가루(1g), 올리브유(5g)
, 요거트(10g), 꿀(2g), 레몬즙(2g)', '["등갈비","마늘","레몬","소주","로즈메리","다진마늘","후춧가루","올리브유","요거트","꿀","레몬즙"]'::jsonb, ARRAY['fc6e31ce-388e-45cd-956b-b238b9134eb1','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','bb41a88a-ea2b-4830-876d-91fe7f640296','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"등갈비는 찬물(5컵)에 담가 1시간 이상 핏물을 제거한다.","imageUrl":null},{"step":2,"text":"등갈비는 한 쪽씩 썬다.","imageUrl":null},{"step":3,"text":"손질한 등갈비는 밑간한 뒤 마늘, 로즈메리와 함께 버무려 30분 정도 재운다.","imageUrl":null},{"step":4,"text":"재운 등갈비는 190℃로 예열한 오븐에 40분간 굽고, 뒤집어서 같은 온도에 30분간 더 굽는다.","imageUrl":null},{"step":5,"text":"디핑소스를 만든다.","imageUrl":null},{"step":6,"text":"그릇에 등갈비구이를 담은 뒤 레몬을 짜 즙을 뿌리고, 디핑 소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308013049_1678249849873.jpg', 281.4, 2, 24.4, 19.5, 74.3),
  ('3470', '밀푀유 채소 웰링턴', '반찬', ',  배추(200g), 소고기(200g), 숙주(80g), 청경채(30g), 표고버섯(20g), 새송이버섯(50g), 백목이버섯(3g), 다시마(10g), 깻잎(5g),  두부(150g), 머스타드(17g), 마늘(10g), 양파(35g), 토마토(200g), 우유(60g), 들깨가루(30g), 올리브유(60g), 간장(30g), 로즈메리(2잎=10g), 소금(8g), 후추(4g), 전분(15g), 물(2컵=400g)', '["배추","소고기","숙주","청경채","표고버섯","새송이버섯","백목이버섯","다시마","깻잎","두부","머스타드","마늘","양파","토마토","우유","들깨가루","올리브유","간장","로즈메리","소금","후추","전분","물"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','1c49d1f4-5781-474d-818d-bd7002a4dc0b','2647e451-e8f5-4fce-91bd-8beabb2384d8','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','66458b1b-c92f-43fa-8eba-e428892ce88a','3f94371a-728f-49ae-8ea9-1a1e87b68048','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','4566cac5-9166-4c0d-906a-bfc7360f8f5b','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','e937397f-54e2-49df-997a-f393c58360be','184687ba-0cba-4fec-bb21-33fe300c2073','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6613d1d9-80a2-4ce4-9d3d-647203197e53','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"표고버섯, 양파, 마늘은 다지고, 끓는 물에 배추, 숙주, 청경채를 데친다. 토마토는 껍질을 벗기고, 소고기는 키친타월로 핏물을 제거하고 두부는 물기를 제거한다.","imageUrl":null},{"step":2,"text":"팬에 올리브유(20g)를 두르고 손질한 표고버섯, 양파(15g), 마늘을 볶은 뒤 간장(15g), 들깨가루, 우유를 넣어 덕셀을 만들고 식힌다.","imageUrl":null},{"step":3,"text":"양파(20g)를 볶은 뒤 물을 붓고 다시마, 새송이버섯, 백목이버섯, 토마토를 넣고 중약 불에서 15분 동안 끓여 갈고 간장(15g), 소금(3g)으로 간해 브라운 소스를 만든다.","imageUrl":null},{"step":4,"text":"소고기에 머스타드, 덕셀을 바르고 깻잎, 두부, 숙주, 청경채를 넣어 감싸준 후 소금(5g), 후추를 뿌리고, 팬에 올리브유(20g)를 두르고 소고기를 굽고, 로즈메리를 넣는다.","imageUrl":null},{"step":5,"text":"종이 포일에 올리브유(20g)를 뿌리고, 데친 배추를 올린 후 위에 구운 고기와 덕셀(30g)을 올리고 돌돌 말아 에어프라이어에 200도, 10분간 굽는다.","imageUrl":null},{"step":6,"text":"접시에 웰링턴을 담고 여분의 덕셀, 브라운 소스를 올리고 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041905_1699255145380.jpg', 216.4, 7.2, 14.6, 14.2, 647.7),
  ('3572', '참나물 매콤함박스테이크', '반찬', ',
 참나물(5g), 부침두부(15g), 닭가슴살(40g), 청양고추(2g),
 올리브유(12g), 고추장(10g), 고춧가루(2g), 알룰로스(5g), 후추(1g), 다진 마늘(4g), 깨(1g), 소금(1g), 물(15m)', '["참나물","부침두부","닭가슴살","청양고추","올리브유","고추장","고춧가루","알룰로스","후추","다진 마늘","깨","소금","물"]'::jsonb, ARRAY['09065cd3-28cc-4a82-8b3e-5121054c7482','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','30b5d53c-d247-4f04-9b50-c0f728e65cf9','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','84104c49-0af4-4323-a56b-b67002a422d9','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','fc6e31ce-388e-45cd-956b-b238b9134eb1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"닭가슴살, 부침두부, 참나물, 청양고추를 잘게 다진다.","imageUrl":null},{"step":2,"text":"볼에 담아 소금으로 밑간하고 4등분하여 둥글게 다져 함박스테이크를 만든다.","imageUrl":null},{"step":3,"text":"달군 팬에 올리브유를 두르고 함박스테이크를 굽는다.","imageUrl":null},{"step":4,"text":"고추장, 고춧가루, 알룰로스, 후추, 다진 마늘, 물을 넣어 소스를 만든다.","imageUrl":null},{"step":5,"text":"달군 팬에 소스를 넣고 살짝 졸인다.","imageUrl":null},{"step":6,"text":"접시에 함박스테이크를 담고 소스를 올린 후 깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120011100_1732075860462.jpg', 99.6, 3.9, 13.2, 3.5, 135.5),
  ('2979', '과일 먹은 닭탕수', '반찬', '닭고기(다리살) 300g, 포도 15g, 미니사과 30g, 파인애플 15g, 전분 80g, 설탕 20g, 레몬 70g, 청주 10g, 후추 0.2g, 소금 2g, 물 200g', '["닭고기","포도","미니사과","파인애플","전분","설탕","레몬","청주","후추","소금","물"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','483ecbd5-47a4-4fb5-bfee-852bded6c1dd','c97290bd-7146-45bc-8e7f-28390e7a95b0','6613d1d9-80a2-4ce4-9d3d-647203197e53','06e6f3e7-0293-469d-a338-11a610f3e71b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"닭다리의 살만 발라내 4cm ? 1cm 크기로 썬다.","imageUrl":null},{"step":2,"text":"1에 소금, 후추로 밑간한 뒤 청주를 넣어 재운다.","imageUrl":null},{"step":3,"text":"포도알은 2등분하고 사과, 파인애플은 한 입 크기로 썬다.","imageUrl":null},{"step":4,"text":"2에 녹말을 입혀 기름에 2번 튀긴다.","imageUrl":null},{"step":5,"text":"팬에 물, 설탕, 레몬즙을 넣고 한소끔 끓인다.","imageUrl":null},{"step":6,"text":"소스에 물전분을 넣어 농도를 맞추고 썰어둔 과일을 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012615_1554697575394.jpg', 104.12, 11.33, 5.07, 4.28, 25.88),
  ('3068', '콜리플라워미역국', '국&찌개', '콜리플라워 25g, 건미역 2g, (육수) 물 500ml, 디포리 2g, 양파 20g, 무 20g, (양념) 저염간장 1g, 건표고버섯 3g, 건새우 3g, 물 300ml', '["콜리플라워","건미역","물","디포리","양파","무","저염간장","건표고버섯","건새우"]'::jsonb, ARRAY['4268226c-9999-4a22-8477-03127720f26f','6565cc3a-c3d6-45b5-a7fb-05a3c03015bf','94786475-832c-4f97-aab7-bf6fbbe2236b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','f80c9a7d-1510-44e2-a82b-28b9f684e191','f175019d-5a93-4cd4-aabc-e7e79445f15a','66458b1b-c92f-43fa-8eba-e428892ce88a','6f10b4ad-53a2-4a07-ba89-19a6b074373d']::uuid[], '[{"step":1,"text":"디포리를 살짝 볶아 물, 양파, 무를 넣고 육수를 낸다.","imageUrl":null},{"step":2,"text":"건새우를 볶아서 건표고버섯과 함께 곱게 간다.","imageUrl":null},{"step":3,"text":"콜리플라워는 먹기 좋은 크기로 썰어 볶는다.","imageUrl":null},{"step":4,"text":"냄비에 불려서 손질해 놓은 미역과 참기름을 넣어 볶는다.","imageUrl":null},{"step":5,"text":"육수를 넣고 푹 끓이다가 ②와 저염간장으로 간을 맞춘다.","imageUrl":null},{"step":6,"text":"마지막으로 콜리플라워를 넣어 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309023204_1583731924541.JPG', 20.9, 0.6, 1.3, 1.5, 113.1),
  ('3080', '구기자모듬장조림', '반찬', '한돈(사태) 30g, 메추리알 30g, 당근 10g, 곤약 10g, 구기자 5g, 양파 10g, 파 10g, 다시마 5g, 마늘 10g, 표고버섯 10g, 저염간장 15g', '["한돈","메추리알","당근","곤약","구기자","양파","파","다시마","마늘","표고버섯","저염간장"]'::jsonb, ARRAY['0697c442-1209-4aa5-931d-722f60cf2c2f','e38c12a7-43cb-421a-a36e-7ef0d32517fa','54a52322-b4df-4354-a7a5-2a7b0c41f7bd','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','fc6e31ce-388e-45cd-956b-b238b9134eb1','66458b1b-c92f-43fa-8eba-e428892ce88a','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"한돈은 사태로 준비하여 깍둑썰기하여 세척한다.","imageUrl":null},{"step":2,"text":"양파, 파, 다시마, 표고버섯, 마늘은 깨끗이 세척 후 적당한 크기로 자르고, 당근, 곤약은 깍뚝썰기하여 준비한다.","imageUrl":null},{"step":3,"text":"냄비에 물과 저염간장을 2:1 비율로 조림장을 준비한다.","imageUrl":null},{"step":4,"text":"조림장에 구기자 및 양파, 파, 다시마, 표고버섯, 마늘을 넣고 끓인다.","imageUrl":null},{"step":5,"text":"조림장이 끓으면 사태, 메추리알, 당근, 곤약을 넣고 조린다.","imageUrl":null},{"step":6,"text":"접시에 담아서 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313011138_1584072698244.jpg', 59.2, 5.3, 4.3, 2.3, 215.6),
  ('3166', '오미자저염나박김치', '반찬', '배추 10g, 콜라비 5g, 오이 2g, 당근 2g, 실파 1g, 청,홍고추 1g, 레몬 5g, 오미자엑기스 5g, 식초 30g, 설탕 5g, 물 10ml', '["배추","콜라비","오이","당근","실파","청","홍고추","레몬","오미자엑기스","식초","설탕","물"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','715e97fc-4781-4f58-8be6-fbfe30b9abe6','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','e38c12a7-43cb-421a-a36e-7ef0d32517fa','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"배추, 콜라비, 오이, 당근을 나박모양으로 썬다.","imageUrl":null},{"step":2,"text":"레몬은 은행잎썰기, 홍고추는 어슷썰기, 실파는 1.5cm 길이로 썬다.","imageUrl":null},{"step":3,"text":"식초, 설탕, 오미자청으로 단촛물을 만든다.","imageUrl":null},{"step":4,"text":"단촛물에 야채, 레몬, 고추, 실파를 넣고 숙성시킨다.","imageUrl":null},{"step":5,"text":"숙성 후 색을 보고 오미자청을 더 첨가한다.","imageUrl":null},{"step":6,"text":"숙성된 오미자 나박김치를 그릇에 담아준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051842_1611562722531.JPG', 43.05, 9.8, 0.42, 0.24, 7.24),
  ('3212', '메밀면 샐러드', '일품', '양상추(40g), 당근(10g), 방울토마토(30g), 닭가슴살(60g), 메밀면(90g), 어린잎채소(10g), 식초(20g), 간장(15g), 올리브유(15g), 다진 마늘(3g), 올리고당(5g), 유자청(10g)', '["양상추","당근","방울토마토","닭가슴살","메밀면","어린잎채소","식초","간장","올리브유","다진 마늘","올리고당","유자청"]'::jsonb, ARRAY['1389717e-81e4-4350-96d4-d627d851aa10','e38c12a7-43cb-421a-a36e-7ef0d32517fa','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','b85df3ba-e324-47fa-b25d-d5bb552b8590','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','6c285c60-022a-4a00-b172-87df97f16a2f','f175019d-5a93-4cd4-aabc-e7e79445f15a','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','fc6e31ce-388e-45cd-956b-b238b9134eb1','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','ff5b6cbe-7985-4ca2-94ad-5525717cddf1']::uuid[], '[{"step":1,"text":"양상추는 한입 크기로 찢고, 당근은 채 썰고, 방울토마토는 4등분한다.","imageUrl":null},{"step":2,"text":"끓는 물(2컵)에 닭가슴살을 넣어 10분간 익힌 뒤 건져 결대로 찢는다.","imageUrl":null},{"step":3,"text":"끓는 물(2컵)에 메밀면을 넣어 5분간 삶아 건진 뒤 찬물에 헹궈 체에 밭쳐 물기를 제거한다.","imageUrl":null},{"step":4,"text":"유자오리엔탈소스를 만든다.","imageUrl":null},{"step":5,"text":"그릇에 준비한 재료와 어린잎채소를 담고 유자오리엔탈소스를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210110714_1612922834280.jpg', 201.5, 26.9, 9.4, 6.2, 308.8),
  ('3214', '치즈 두부 튀김', '일품', '고구마(50g), 호두(15g), 우유(10㎖), 두부(150g), 빵가루(50g), 모차렐라치즈(15g), 식용유(100ml)', '["고구마","호두","우유","두부","빵가루","모차렐라치즈","식용유"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','7651578f-1206-499d-a04c-15f034d4cae2','e937397f-54e2-49df-997a-f393c58360be','4566cac5-9166-4c0d-906a-bfc7360f8f5b','45080597-55fa-42dc-aa65-12d7694e4b7e','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"고구마는 끓는 물(2컵)에 4분간 삶아 껍질을 제거한 뒤 곱게 으깬다.","imageUrl":null},{"step":2,"text":"호두는 굵게 부순다.","imageUrl":null},{"step":3,"text":"으깬 고구마에 호두, 우유를 넣어 고루 섞는다.","imageUrl":null},{"step":4,"text":"키친타월을 이용해 두부의 물기를 제거한 뒤 곱게 으깨고 빵가루(15g)를 넣어 섞는다.","imageUrl":null},{"step":5,"text":"두부를 얇게 편 뒤 고구마와 모차렐라치즈를 넣어 동그랗게 빚는다.","imageUrl":null},{"step":6,"text":"두부를 얇게 편 뒤 고구마와 모차렐라치즈를 넣어 동그랗게 빚는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111559_1612923359198.jpg', 355.4, 24.7, 19.4, 19.9, 172.9),
  ('3269', '단호박 라타투이', '반찬', ' 가지(1개), 주키니호박(½개), 토마토(1½개), 단호박(1개), 훈제 오리(400g), 마늘(6쪽), 다진 양파(½컵), 다진 토마토(1컵), 다진 파프리카(1컵), 올리브유(2Ts), 소금(0.3Ts), 후춧가루(0.3Ts)', '["가지","주키니호박","토마토","단호박","훈제 오리","마늘","다진 양파","다진 토마토","다진 파프리카","올리브유","소금","후춧가루"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','98d652af-a6d6-440c-9653-e22fc5d47d88','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"가지, 주키니호박, 토마토는 0.3mm 두께로 썬다.","imageUrl":null},{"step":2,"text":"단호박은 전자레인지에 5분간 돌리고, 익으면 윗부분을 약간 잘라낸 뒤 씨를 제거한다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 훈제오리와 마늘을 넣어 고루 볶은 뒤 단호박 속에 채운다.","imageUrl":null},{"step":4,"text":"팬에 올리브유를 두른 뒤 약한 불로 올리고, 라타투이 소스 재료, 소금, 후춧가루를 넣어 10분간 볶아 라타투이 소스를 만든다.","imageUrl":null},{"step":5,"text":"높이가 낮은 냄비에 라타투이 소스를 넓게 깔고, 손질한 채소를 둘러 담는다.","imageUrl":null},{"step":6,"text":"오리로 채운 단호박을 가운데 올린 뒤 6~8등분하여 펼치고, 중간 불로 15분간 쪄 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeuf4', 235.4, 9.1, 21.7, 12.5, 682.6),
  ('3364', '느타리버섯볶음', '반찬', ' 느타리버섯(25g), 파프리카(빨간색, 노란색 각 10g), 청피망(10g), 크래미(10g), 식용유(3g)
, 소금(1g), 후추(3g), 간장(1g)', '["느타리버섯","파프리카","청피망","크래미","식용유","소금","후추","간장"]'::jsonb, ARRAY['7c91e298-5ace-4242-8619-cdcc80587cd7','5e79d288-1400-4817-bd20-e5e6041821b1','df459e6f-3515-45d5-8c9a-9d37b6249379','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"느타리버섯은 밑동을 자르고 가닥가닥 찢어 데쳐서 찬물에 헹궈 물기를 제거한다.","imageUrl":null},{"step":2,"text":"파프리카와 청피망은 채 썰고, 크래미는 잘게 찢는다.","imageUrl":null},{"step":3,"text":"팬에 기름을 두르고 손질한 파프리카와 피망을 넣어 볶는다.","imageUrl":null},{"step":4,"text":"느타리버섯을 넣어 볶는다.","imageUrl":null},{"step":5,"text":"게살을 넣어 볶다가 간장으로 색을 낸다.","imageUrl":null},{"step":6,"text":"소금과 후추로 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051519_1678090519731.jpg', 51.5, 3.8, 2.4, 3, 158.2),
  ('3573', '오리들깨 겨자소스 초무침', '반찬', ',
오리고기(90g), 양파(10g), 당근(10g), 오이(10g),
들깻가루(8g), 겨잣가루(4g), 식초(10g), 레몬즙(5g), 물(15ml)', '["오리고기","양파","당근","오이","들깻가루","겨잣가루","식초","레몬즙","물"]'::jsonb, ARRAY['813c3e8f-245d-4007-b9e2-4b135809e9ed','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','184687ba-0cba-4fec-bb21-33fe300c2073','6c285c60-022a-4a00-b172-87df97f16a2f','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"달군 팬에 오리고기를 넣고 센 불에서 볶는다.","imageUrl":null},{"step":2,"text":"들깻가루, 겨잣가루, 식초, 레몬즙, 물을 섞어 양념장을 만든다.","imageUrl":null},{"step":3,"text":"양파, 당근, 오이는 채 썬다.","imageUrl":null},{"step":4,"text":"볶은 오리고기는 한 김 식힌다.","imageUrl":null},{"step":5,"text":"볼에 오리고기, 손질한 채소, 양념장을 넣고 버무린다.","imageUrl":null},{"step":6,"text":"접시에 담아 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120011152_1732075912579.jpg', 179.7, 3.1, 17.8, 10.7, 45.2),
  ('849', '닭고기 바비큐', '반찬', '닭가슴살 60g, 홍피망 24g, 양파 30g, 노랑파프리카 24g, 양송이버섯 9g ,양파다진것 6g, 마늘다진것 1.2g, 케첩 9g, 홍토마토 12g, 설탕 3g, 물 18g, 이탈리안시즈닝:타임 0.9g, 로즈마리 0.9g, 바질 1.2g, 오레가노 1.2g', '["닭가슴살","홍피망","양파","노랑파프리카","양송이버섯","양파다진것","마늘다진것","케첩","홍토마토","설탕","물","이탈리안시즈닝:타임","로즈마리","바질","오레가노"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','df459e6f-3515-45d5-8c9a-9d37b6249379','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','fc6e31ce-388e-45cd-956b-b238b9134eb1','0136fc6a-3a80-4f4c-8057-10bbf34ea572','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','ba9e5a79-cab3-4af0-942b-0b35fd745150','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6']::uuid[], '[{"step":1,"text":"닭가슴살은 3cm 주사위모양으로 썰고 식용유와 이탈리안 시즈닝으로 양념한다.","imageUrl":null},{"step":2,"text":"홍피망, 노랑파프리카, 양파는 3cm 크기로 썰고 양송이버섯은 반으로 썬다.","imageUrl":null},{"step":3,"text":"소스 재료를 넣고 끓인다.","imageUrl":null},{"step":4,"text":"닭가슴살은 구워서 반만 익히고 꼬치에 채소와 함께 꽂는다.","imageUrl":null},{"step":5,"text":"그릴에서 완전히 굽는다.","imageUrl":null},{"step":6,"text":"소스를 끼얹어 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053447_1416213287870.jpg', 174.7, 11.9, 13.1, 8.5, 73),
  ('851', '닭고기 편육', '반찬', '닭고기가슴살 100g ,요구르트 6g, 식용유 1g, 후춧가루 0.03g, 조림장:간장 3g, 설탕 5g, 꿀 1g, 홍고추마른것 1g, 정종 5g, 참기름 0.8g, 대파 10g', '["닭고기가슴살","요구르트","식용유","후춧가루","조림장:간장","설탕","꿀","홍고추마른것","정종","참기름","대파"]'::jsonb, ARRAY['bb41a88a-ea2b-4830-876d-91fe7f640296','a7a59e81-de3d-4893-b56a-b2218732a25b','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','06e6f3e7-0293-469d-a338-11a610f3e71b','286d1783-cd34-4aae-ac8b-006529ec8bc5','30b5d53c-d247-4f04-9b50-c0f728e65cf9','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','0c0ade94-cfd8-4104-b44c-40e942cac482','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"오븐을 175℃로 예열한다.","imageUrl":null},{"step":2,"text":"닭고기 밑간 양념으로 30분정도 재운다.","imageUrl":null},{"step":3,"text":"재워 놓은 닭고기를 175℃의 오븐에서 15분 굽는다.","imageUrl":null},{"step":4,"text":"조림장을 모두 넣고 끓인다.","imageUrl":null},{"step":5,"text":"닭고기 구운 것을 넣고 10~15분 간 졸인다.","imageUrl":null},{"step":6,"text":"닭고기를 먹기 좋게 잘라 남은 소스를 얹어 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053449_1416213289103.jpg', 262, 8.3, 19.4, 15.5, 238),
  ('852', '돼지고기 찹쌀부침', '반찬', '돼지고기 등심 50g, 젖은 찹쌀가루 50g ,간장 1g, 물엿 3g, 다진마늘 2g, 후춧가루 0.1g, 무순 1g, 레디쉬 0.3g, 깻잎 1.5g, 대파 3g 저나트륨된장소스:된장 1g, 파인애플 15g, 물 30g, 홍고추 0.5g, 통마늘 0.3g', '["돼지고기 등심","젖은 찹쌀가루","간장","물엿","다진마늘","후춧가루","무순","레디쉬","깻잎","대파","파인애플","물","홍고추","통마늘"]'::jsonb, ARRAY['f175019d-5a93-4cd4-aabc-e7e79445f15a','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f09d1d41-602a-441c-a7bc-520311490ceb','f80c9a7d-1510-44e2-a82b-28b9f684e191','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','4b410642-7bf9-45ad-9055-e7d9a34edaa1','c97290bd-7146-45bc-8e7f-28390e7a95b0','94786475-832c-4f97-aab7-bf6fbbe2236b','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"돼지고기는 간장, 물엿, 다진마늘, 후춧가루로 밑간 한다.","imageUrl":null},{"step":2,"text":"레디쉬, 깻잎, 대파는 채썬다.","imageUrl":null},{"step":3,"text":"소스 재료들은 모두 믹서에 간다.","imageUrl":null},{"step":4,"text":"돼지고기에 찹쌀가루를 두 번 입힌다.","imageUrl":null},{"step":5,"text":"가열된 팬에 옷입힌 돼지고기를 지진다.","imageUrl":null},{"step":6,"text":"구운 돼지고기에 썰어둔 채소를 얹은 후 고기를 말아 소스와 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053450_1416213290025.jpg', 343.7, 48.3, 13.4, 10, 120),
  ('853', '등심 배구이', '반찬', '쇠고기등심 38g, 배 12g, 오이 9g, 잣가루 0.5g, 식용유 0.5g ,포도주 2.5g, 후춧가루 0.1g, 저나트륨초간장소스:간장 1.3g, 사과주스 3.8g, 식초 1.3g, 설탕 1.3g, 와사미 0.8g', '["쇠고기등심","배","오이","잣가루","식용유","포도주","후춧가루","저나트륨초간장소스:간장","사과주스","식초","설탕","와사미"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','a7a59e81-de3d-4893-b56a-b2218732a25b','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"소고기등심은 손질하여 칼등으로 부드럽게 두드린 뒤 4cm 길이로 썰어서 재움장에 30분 정도 재운다.","imageUrl":null},{"step":2,"text":"오이는 0.2cm 두께로 동그랗게 썰어 소금에 살짝 절였다 짠다.","imageUrl":null},{"step":3,"text":"배는 껍질과 씨를 제거하고 반달모양으로 0.2cm 두께로 썬다.","imageUrl":null},{"step":4,"text":"팬에 식용유를 두르고 오이는 센불에서 살짝 볶고 배는 노릇하게 지진다.","imageUrl":null},{"step":5,"text":"팬에 재워둔 소고기등심을 지지고 초간장소스를 만든다.","imageUrl":null},{"step":6,"text":"노릇하게 지진 배에 소고기등심을 오이, 잣가루를 얹고 가볍게 싸서 저나트륨 초간장에 찍어 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053450_1416213290929.jpg', 97.2, 3.8, 7.9, 5.1, 241),
  ('855', '버섯소스를 곁들인 돼지 등심 스테이크', '일품', '돼지등심 100g, 양송이버섯 45g, 표고버섯 15g, 애느타리버섯 10g, 파슬리다진것 3g, 버터 5g, 후춧가루 0.1g, 밀가루 4g, 식용유 2g, 화이트와인 50g, 물 50g', '["돼지등심","양송이버섯","표고버섯","애느타리버섯","파슬리다진것","버터","후춧가루","밀가루","식용유","화이트와인","물"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','66458b1b-c92f-43fa-8eba-e428892ce88a','7c91e298-5ace-4242-8619-cdcc80587cd7','4362c386-a37c-44cd-9254-fafd74712a09','7aabd532-361f-4240-aa33-6bfa1be4bc4e','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','aab3b0b9-d346-4697-a1c8-1b1530153788','a7a59e81-de3d-4893-b56a-b2218732a25b','e16eaf50-ebd3-4933-a774-3ce6fc92593f','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"양송이버섯과 표고버섯은 얇게 썰고 애느타리버섯은 잘게 찢어 놓는다.","imageUrl":null},{"step":2,"text":"썰어놓은 돼지고기는 후춧가루와 밀가루로 밑간한다.","imageUrl":null},{"step":3,"text":"가열된 팬에 식용유를 넣고 고기를 굽는다.","imageUrl":null},{"step":4,"text":"고기를 한쪽으로 밀어두고 버섯들을 넣어 볶다가 화이트와인과 물을 넣고 끓인다. 반쯤 졸아지면 고기를 꺼낸다.","imageUrl":null},{"step":5,"text":"팬에 버터를 넣어 소스의 농도를 맞추고 다진 파슬리를 뿌려 소스를 완성한다.","imageUrl":null},{"step":6,"text":"고기에 소스를 얹어 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053454_1416213294458.jpg', 387.7, 8, 20.4, 26.1, 80),
  ('857', '쇠고기 감자찜', '반찬', '알감자 80g, 쇠고기다진것 50g, 육수 50g, 녹말가루 3g ,파다진것 1g, 마늘 다진것 1g, 청고추 다진것 1g, 홍고추 다진것 1g, 간장 1.2g, 설탕 1.2g, 깨소금 0.5g, 참기름 1g, 후춧가루 0.1g, 미나리잎장식', '["알감자","쇠고기다진것","육수","녹말가루","파다진것","마늘 다진것","청고추 다진것","홍고추 다진것","간장","설탕","깨소금","참기름","후춧가루","미나리잎장식"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','a4c37075-c03b-47bb-8aed-5e907620f5d2','6613d1d9-80a2-4ce4-9d3d-647203197e53','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"감자는 껍질을 벗겨 반으로 갈라편편하게 놓일 수 있도록 밑면을 다듬는다.","imageUrl":null},{"step":2,"text":"숟가락으로 감자 윗면을 파낸다.","imageUrl":null},{"step":3,"text":"다진 소고기는 분량의 재료를 넣고 양념한다.","imageUrl":null},{"step":4,"text":"파낸 감자 안에 녹말을 묻히고 양념한 소고기를 채운다.","imageUrl":null},{"step":5,"text":"감자가 잠길 정도로 육수를 붓고 끓인다.","imageUrl":null},{"step":6,"text":"찜이 완성되면 물녹말을 부어 걸쭉하게 만든다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053456_1416213296253.jpg', 183.6, 16.5, 12.9, 7.3, 200),
  ('859', '양송이버섯과 포도주스를 가미한 등심구이', '일품', '쇠고기등심 50g, 양송이버섯 20g, 포도주스 50g, 토마토 80g, 물 15g, 바질 2.5g, 설탕 1.3g, 오레가노 2g,마늘가루 0.5g, 소금 0.4g, 파슬리다진것 5g, 월계수잎 0.2g, 로즈마리 2.5g, 통후추 1g, 타임 2.5g', '["쇠고기등심","양송이버섯","포도주스","토마토","물","바질","설탕","오레가노","마늘가루","소금","파슬리다진것","월계수잎","로즈마리","통후추","타임"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','483ecbd5-47a4-4fb5-bfee-852bded6c1dd','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','94786475-832c-4f97-aab7-bf6fbbe2236b','ba9e5a79-cab3-4af0-942b-0b35fd745150','06e6f3e7-0293-469d-a338-11a610f3e71b','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6','2cf0c12b-f248-4012-8f53-303c730a7b3d','4362c386-a37c-44cd-9254-fafd74712a09','043a9631-bb6e-42e6-9673-4943457502fb','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"유리볼에 고기를 담고 로즈마리, 통후추 으깬 것, 양송이버섯 썬 것, 월계수잎, 포도주스를 넣고 절인다.","imageUrl":null},{"step":2,"text":"작은 유리볼에 토마토소스와 소고기육수, 바질, 오레가노, 설탕, 마늘가루를 넣고 섞는다.","imageUrl":null},{"step":3,"text":"재워둔 고기를 꺼내 가열된 팬에 앞 뒷면을 익힌다.","imageUrl":null},{"step":4,"text":"고기를 구웠던 팬에 1의 남은 국물과 2의 토마토소스를 붓는다.","imageUrl":null},{"step":5,"text":"팬에 붙은 고기 조각들을 긁어내 함께 중불에서 끓여 양송이버섯 소스를 만든다.","imageUrl":null},{"step":6,"text":"스테이크를 썰어 그릇에 담고 양송이버섯 소스를 끼얹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053458_1416213298111.jpg', 182.5, 15.3, 11.3, 10.3, 163),
  ('2980', '비타 오이 물김치', '반찬', '오이 30g, 무 50g, 홍고추 10g, 파프리카 20g, 당근 20g, 미나리 10g, 식초 30g, 배 30g, 고춧가루 10g, 설탕 5g', '["오이","무","홍고추","파프리카","당근","미나리","식초","배","고춧가루","설탕"]'::jsonb, ARRAY['9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','f80c9a7d-1510-44e2-a82b-28b9f684e191','30b5d53c-d247-4f04-9b50-c0f728e65cf9','5e79d288-1400-4817-bd20-e5e6041821b1','e38c12a7-43cb-421a-a36e-7ef0d32517fa','dc7b2b73-74de-4fb8-9274-a5967ca444f9','6c285c60-022a-4a00-b172-87df97f16a2f','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','84104c49-0af4-4323-a56b-b67002a422d9','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408013158_1554697918452.jpg', 13.46, 2.99, 0.34, 0.02, 30.88),
  ('3069', '새우살토마토스튜', '국&찌개', '새우살 30g, 토마토 20g, 양파 15g, 당근 10g, 애호박 15g, 건다시마 3g, 버터 3g, 케찹 5g,10g, 후추 0.1g, 소금 0.2g, 물 300ml', '["새우살","토마토","양파","당근","애호박","건다시마","버터","케찹","후추","소금","물"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','7aabd532-361f-4240-aa33-6bfa1be4bc4e','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"다시마로 육수를 낸다.","imageUrl":null},{"step":2,"text":"새우살은 데치고 토마토는 칼집을 내어 데친 후 껍질을 벗긴다.","imageUrl":null},{"step":3,"text":"토마토, 양파, 당근, 호박은 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":4,"text":"새우살과 당근, 호박을 버터에 볶아 준다.","imageUrl":null},{"step":5,"text":"기름을 두른 팬에 토마토와 양파를 넣고 조린다.","imageUrl":null},{"step":6,"text":"⑤에 ④와 육수, 케첩을 넣고 끓인 후 후추를 넣고 소금으로 간을 하여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309025909_1583733549459.JPG', 67.1, 6.1, 5.5, 2.3, 280.4),
  ('3072', '견과류문어떡갈비', '반찬', '돈민찌 80g, 우민찌 30g, 떡 40g, 문어 3g, 배 5g, 호두 3g, 아몬드 3g, 다진마늘 5g, 다진파 5g, 찹쌀가루 5g, 참기름 1g, 후추 1g, 밀가루 0.5g, 식용유 5g, 대추 2g, 잣 2g', '["돈민찌","우민찌","떡","문어","배","호두","아몬드","다진마늘","다진파","찹쌀가루","참기름","후추","밀가루","식용유","대추","잣"]'::jsonb, ARRAY['af336608-1eeb-4b10-9a3a-1df0ad140ccb','55a34ec2-28ee-407c-8ad5-7462cbe99d55','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','7651578f-1206-499d-a04c-15f034d4cae2','52ba316f-8e7f-415f-8079-9a9d674c9adf','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','4cb11562-015f-4ab5-969f-0ea8483a0b42','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','aab3b0b9-d346-4697-a1c8-1b1530153788','a7a59e81-de3d-4893-b56a-b2218732a25b','b371c5d2-f12b-47ee-9a87-26efd09db09d','bbbbd533-8922-4dac-9e4c-cd93ea710c92']::uuid[], '[{"step":1,"text":"삶은 문어, 배, 호두, 아몬드는 작게 자르고, 파와 마늘은 다진다.","imageUrl":null},{"step":2,"text":"대추는 돌려 깍기 하여 돌돌 말아 자른다.","imageUrl":null},{"step":3,"text":"돈민찌, 우민찌는 잘 섞어주고 ①재료와 참기름, 후추, 찹쌀가루를 넣어 치대어 준다.","imageUrl":null},{"step":4,"text":"데쳐서 익힌 떡에 밀가루를 얇게 입히고 ③의 반죽을 붙혀 떡갈비를 만든다.","imageUrl":null},{"step":5,"text":"떡갈비를 팬에 올려 속이 익을 때까지 굽는다.","imageUrl":null},{"step":6,"text":"잘라놓은 대추와 잣을 고명으로 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102240_1584062560564.JPG', 329, 24.5, 27.1, 13.6, 156),
  ('3167', '배물김치', '반찬', '배 30g, 미나리 1g, 청홍고추 0.2g, 감자 4g, 설탕 3g, 마늘 2g, 생강 1g, 물 100ml', '["배","미나리","청홍고추","감자","설탕","마늘","생강","물"]'::jsonb, ARRAY['eccf67f1-41f0-4a25-b238-6b9e7332c9e1','dc7b2b73-74de-4fb8-9274-a5967ca444f9','20894da1-739d-4d52-b5fe-4943bd3492d5','06e6f3e7-0293-469d-a338-11a610f3e71b','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"감자를 삶아 물과 함께 갈아 감자풀을 만든다.","imageUrl":null},{"step":2,"text":"배는 나박썬다.","imageUrl":null},{"step":3,"text":"청홍고추는 어슷썬다.","imageUrl":null},{"step":4,"text":"미나리는 고추와 비슷한 크기로 썰어준다.","imageUrl":null},{"step":5,"text":"준비된 재료에 감자 전분물, 설탕, 마늘, 생강을 넣고 섞어 물김치를 만든다.","imageUrl":null},{"step":6,"text":"하루 정도 숙성시킨 다음 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125052704_1611563224561.JPG', 27.93, 6.42, 0.41, 0.07, 3.37),
  ('3168', '성주참외동치미', '반찬', '참외 20g, 양파 10g, 배 5g, 대파 3g, 마늘 3g, 홍고추 1g, 생강 1g, 식초 4g, 설탕 3g, , 누룩소금 0.5g, 물 150ml', '["참외","양파","배","대파","마늘","홍고추","생강","식초","설탕","누룩소금","물"]'::jsonb, ARRAY['7dd9d8bc-46ee-40cb-974c-6fb77702e323','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"참외는 껍질과 속을 제거하고 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":2,"text":"배와 마늘은 편 썰기, 양파와 대파는 채썰기, 홍고추와 생강은 다진다.","imageUrl":null},{"step":3,"text":"물에 식초, 설탕, 누룩소금을 넣어 국물을 만든다.","imageUrl":null},{"step":4,"text":"만들어 놓은 국물에 참외, 배, 양파를 넣어 잘 섞어 준다.","imageUrl":null},{"step":5,"text":"마지막으로 마늘, 홍고추, 생강을 넣어 섞어 준다.","imageUrl":null},{"step":6,"text":"동치미를 그릇에 담아 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125054438_1611564278881.jpg', 37.47, 8.1, 0.9, 0.16, 80.06),
  ('3213', '애호박 순대', '일품', '두부(8g), 생새우(45g), 팽이버섯(3g), 당근(3g), 깻잎(1g), 파프리카(3g), 다진 소고기(8g), 감자전분(50g), 달걀흰자(60g), 애호박(1개), 저염 간장(1g), 식초(1g), 적양파(2g)', '["두부","생새우","팽이버섯","당근","깻잎","파프리카","다진 소고기","감자전분","달걀흰자","애호박","저염 간장","식초","적양파"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','e38c12a7-43cb-421a-a36e-7ef0d32517fa','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','5e79d288-1400-4817-bd20-e5e6041821b1','1c49d1f4-5781-474d-818d-bd7002a4dc0b','6613d1d9-80a2-4ce4-9d3d-647203197e53','c7d438a6-34d6-423f-905d-446b839e2f39','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742']::uuid[], '[{"step":1,"text":"저염 간장, 식초, 물(10㎖)을 섞은 뒤 얇게 채 썬 적양파를 넣어 30분간 숙성해 양파장아찌를 만든다.","imageUrl":null},{"step":2,"text":"두부와 생새우, 팽이버섯, 당근, 깻잎, 파프리카는 믹서에 넣어 곱게 간다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 다진 소고기를 살짝 볶은 뒤 곱게 간 재료와 감자전분(45g), 달걀흰자와 섞어 소를 만든다.","imageUrl":null},{"step":4,"text":"애호박은 양끝을 자른 뒤 속을 파내고 안쪽에 감자전분(5g)을 고루 묻힌다.","imageUrl":null},{"step":5,"text":"애호박에 소를 채운 뒤 찜기에 넣어 8분간 찐다.","imageUrl":null},{"step":6,"text":"애호박 순대를 1cm 두께로 썰어 그릇에 담고 양파장아찌를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111134_1612923094669.jpg', 165.4, 30.9, 6.7, 1.7, 129.2),
  ('3270', '버터치킨카레', '반찬', ' 양파(1개), 당근(½개), 토마토(2개), 닭고기(가슴살, 다릿살 각 200g), 생크림(200g), 파프리카(빨강, 노랑 각 1개), 바게트(약간), 월계수잎(1장), 통후추(5알), 정향(1개), 요거트(1컵), 가람마살라(2Ts), 코리앤더파우더(2Ts), 커민파우더(2Ts), 다진 마늘(3Ts), 파프리카가루(2Ts), 소금(1ts), 버터(2Ts)', '["양파","당근","토마토","닭고기","생크림","파프리카","바게트","월계수잎","통후추","정향","요거트","가람마살라","코리앤더파우더","커민파우더","다진 마늘","파프리카가루","소금","버터"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','af187077-b7f6-4b0e-9e99-f844f6359ac2','5e79d288-1400-4817-bd20-e5e6041821b1','043a9631-bb6e-42e6-9673-4943457502fb','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','bb41a88a-ea2b-4830-876d-91fe7f640296','fc6e31ce-388e-45cd-956b-b238b9134eb1','2cf0c12b-f248-4012-8f53-303c730a7b3d','7aabd532-361f-4240-aa33-6bfa1be4bc4e']::uuid[], '[{"step":1,"text":"양파, 당근, 토마토, 파프리카는 한입 크기로 썰고, 닭고기는 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"닭고기는 요거트(1컵), 가람마살라(1Ts), 코리앤더파우더(1Ts), 커민파우더(1Ts), 다진 마늘(1Ts), 파프리카가루(1Ts), 소금(0.5ts)에 버무려 15분간 재운다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 버터(2Ts)를 녹이고, 다진 마늘(1Ts), 양파, 당근, 토마토를 넣어 5분간 볶는다.","imageUrl":null},{"step":4,"text":"물(⅓컵), 육수 재료, 생크림을 넣어 끓이고, 당근이 익으면 핸드 믹서로 곱게 간 뒤 체로 거른다.","imageUrl":null},{"step":5,"text":"갈아 낸 카레를 냄비에 붓고, 가람마살라 (1Ts), 코리앤더파우더(1Ts), 커민파우더, (1Ts), 다진 마늘(1Ts), 파프리카가루(1Ts), 소금(0.5ts)을 넣어 걸쭉하게 끓인다.","imageUrl":null},{"step":6,"text":"꼬치에 파프리카와 닭을 번갈아 끼운 뒤 중간 불로 달군 팬에 닭이 익을 때까지 굽고, 그릇에 카레를 담은 뒤 닭꼬치와 바게트를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJewLo', 493.1, 22.4, 34.3, 29.6, 204.5),
  ('3273', '소고기찜과 검은콩수제비', '일품', ' 팽이버섯(½봉), 느타리버섯(½줌), 알배추(½개), 쪽파(3대), 가지(½개), 당근(¼개), 흰다리새우(7마리), 관자(4개), 삶은 검은콩(½컵), 소고기(불고기용 부채살, 200g), 숙주(⅓줌), 달걀노른자(2개), 쑥갓(⅓줌), 미니 단호박(½개), 생표고버섯(5개), 청경채(2개), 소금(0.3Ts), 통밀가루(¼컵), 돼지감자가루(¼컵), 현미쌀가루(¼컵), 저염 간장(2Ts), 맛술(0.3Ts), 꿀(1Ts), 레몬즙(1Ts), 다진 쪽파(1Ts), 다진 청양고추(0.5Ts)', '["팽이버섯","느타리버섯","알배추","쪽파","가지","당근","흰다리새우","관자","삶은 검은콩","소고기","숙주","달걀노른자","쑥갓","미니 단호박","생표고버섯","청경채","소금","통밀가루","돼지감자가루","현미쌀가루","저염 간장","맛술","꿀","레몬즙","다진 쪽파","다진 청양고추"]'::jsonb, ARRAY['cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','7c91e298-5ace-4242-8619-cdcc80587cd7','e116f85b-0eaa-40cb-8107-df5ec8486ad4','4b410642-7bf9-45ad-9055-e7d9a34edaa1','3e12cf79-2cde-4309-9f7c-4eccce3fde28','e38c12a7-43cb-421a-a36e-7ef0d32517fa','5b1f2880-4947-495e-81f3-b6dca1cbe265','f82b8382-3b65-4839-9f45-524168f3da07','1c49d1f4-5781-474d-818d-bd7002a4dc0b','2647e451-e8f5-4fce-91bd-8beabb2384d8','c7d438a6-34d6-423f-905d-446b839e2f39','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','98d652af-a6d6-440c-9653-e22fc5d47d88','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','2cf0c12b-f248-4012-8f53-303c730a7b3d','aab3b0b9-d346-4697-a1c8-1b1530153788','f175019d-5a93-4cd4-aabc-e7e79445f15a','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','286d1783-cd34-4aae-ac8b-006529ec8bc5','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"팽이버섯과 느타리버섯은 밑동을 잘라 낱낱이 가르고, 알배추는 한입 크기로 썰고, 쑥갓과 쪽파는 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"가지와 당근은 어슷 썰고, 단호박은 씨 제거 후 7~8쪽으로 썰고, 표고버섯은 별모양 칼집을 내고, 새우는 깨끗하게 씻고, 관자는 한입 크기로 썬다.","imageUrl":null},{"step":3,"text":"믹서에 삶은 검은콩과 물(1컵)을 넣어 갈고, 볼에 담은 뒤 검은콩 수제비 반죽 재료와 고루 섞어 치대고, 냉장실에서 30분간 숙성한다.","imageUrl":null},{"step":4,"text":"불고기용 소고기를 펼치고, 팽이버섯과 쪽파를 위에 올려 돌돌 만다.","imageUrl":null},{"step":5,"text":"대나무 찜기에 손질한 채소, 해산물,  숙주 순으로 깔아준다.","imageUrl":null},{"step":6,"text":"그 위에 고기 버섯말이를 올려 중간 불에서 10분간 쪄내고, 달걀노른자와 양념장을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr906p', 264.2, 16.1, 30.8, 8.5, 437.1),
  ('3575', '소고기 김말이', '반찬', ',
 소고기(치맛살)(100g), 김(6g(3장)), 튀김가루(20g)
, 식용유(45g), 다진 쪽파(10g), 다진 마늘(12g), 저염간장(4g), 고춧가루(12g), 깨(20g), 후추(3g), 물(반죽용)(15ml), 물(양념장용)(4ml)', '["소고기","김)","튀김가루","식용유","다진 쪽파","다진 마늘","저염간장","고춧가루","깨","후추","물"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','aab3b0b9-d346-4697-a1c8-1b1530153788','a7a59e81-de3d-4893-b56a-b2218732a25b','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"소고기는 키친타월로 핏물을 제거한다.","imageUrl":null},{"step":2,"text":"다진 쪽파, 다진 마늘, 저염간장, 고춧가루, 깨(18g), 물(4ml)을 섞어 양념장을 만든다.","imageUrl":null},{"step":3,"text":"튀김가루와 물(15ml)을 섞어 반죽을 만든다","imageUrl":null},{"step":4,"text":"손질한 소고기는 후추로 밑간하여 한입 크기로 다지고 김 위에 올려 돌돌 말아 김말이를 만든다.","imageUrl":null},{"step":5,"text":"김말이에 반죽을 묻히고 달군 팬에 식용유를 두르고 김말이를 앞뒤로 굽는다.","imageUrl":null},{"step":6,"text":"접시에 담고 양념장, 깨를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120012450_1732076690467.jpg', 255.8, 11.8, 16.4, 15.9, 135.2),
  ('3683', '땅콩 밀푀유 샌드', '후식', ' 박력 밀가루 65g, 강력 밀가루 65g, 무염버터 120g, 물 65ml, 소금① 3g, 땅콩 분태 5g, 그릭요거트 45g, 크림치즈 30g, 꿀 4g, 구운 땅콩 45g, 소금② 1g, 계피가루 1g', '["박력 밀가루","강력 밀가루","무염버터","물","소금①","땅콩 분태","그릭요거트","크림치즈","꿀","구운 땅콩","소금②","계피가루"]'::jsonb, ARRAY['7aabd532-361f-4240-aa33-6bfa1be4bc4e','94786475-832c-4f97-aab7-bf6fbbe2236b','b42c6eac-0afb-4d87-8942-ed1a9c294b09','286d1783-cd34-4aae-ac8b-006529ec8bc5','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','5205f393-c02b-4b09-a2d6-42629f7401b9']::uuid[], '[{"step":1,"text":"볼에 체 친 박력 밀가루, 강력 밀가루,\r\n잘게 자른 무염버터를 넣고 콩알\r\n크기가 될 때까지 잘라가며 섞는다.","imageUrl":null},{"step":2,"text":"차가운 물, 소금①을 넣고 고루 섞은 후\r\n비닐에 담아 납작하게 편 상태로\r\n냉장고에서 30분 동안 휴지시켜\r\n반죽을 만든다.","imageUrl":null},{"step":3,"text":"반죽을 밀대로 밀어 3번 접고\r\n냉장고에서 20분 동안 휴지한다.\r\n같은 작업을 2번 반복한다.","imageUrl":null},{"step":4,"text":"반죽을 5mm 두께로 밀고, 가장자리를\r\n잘라 오븐 팬에 올린다. 포크로 구멍을\r\n뚫고, 종이 포일을 올린 뒤 무거운 팬을\r\n올려 부풀지 않게 한다. ① 200°C로\r\n예열한 오븐에서 10분, ② 190°C에서 20분\r\n동안 굽고 식힌 뒤 적당한 크기로 자른다.","imageUrl":null},{"step":5,"text":"그릭요거트, 크림치즈, 꿀을 섞어 크림\r\n스프레드를 만든다. 믹서에 구운 땅콩,\r\n소금②, 계피가루를 넣고 갈아 땅콩\r\n스프레드를 만든다.","imageUrl":null},{"step":6,"text":"밀푀유에 크림 스프레드, 땅콩\r\n스프레드를 바르고 땅콩 분태를 뿌려\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020071112_1760955072877.jpg', 181.9, 17.9, 4.4, 10.3, 90.4),
  ('861', '케이준 스타일 닭고기 요리', '반찬', '닭가슴살 100g, 식용유 8g, 파프리카가루 2g, 키엔페퍼 1g, 양파가루 1g, 마늘가루 1g, 후추 1g, 흰후춧가루 1g, 오레가노마른것 0.5g, 타임 마른것 0.5g, 바질마른것 1g, 로즈마리마른것 0.5g ,황설탕 1g', '["닭가슴살","식용유","파프리카가루","키엔페퍼","양파가루","마늘가루","후추","흰후춧가루","오레가노마른것","타임 마른것","바질마른것","로즈마리마른것","황설탕"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','a7a59e81-de3d-4893-b56a-b2218732a25b','5e79d288-1400-4817-bd20-e5e6041821b1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6','ba9e5a79-cab3-4af0-942b-0b35fd745150','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"식용유를 제외한 모든 향신료를 섞어준다.","imageUrl":null},{"step":2,"text":"닭가슴살에 식용유를 바른다.","imageUrl":null},{"step":3,"text":"1의 향신료를 닭가슴살의 한면에만 잘 발라준다.","imageUrl":null},{"step":4,"text":"가열된 식용유를 두르고 닭가슴살의 향신료 묻는 면이 팬에 닿도록 놓는다.","imageUrl":null},{"step":5,"text":"앞 뒷면이 노릇하게 되도록 구워준다.","imageUrl":null},{"step":6,"text":"그릇에 담아 마무리 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053459_1416213299404.jpg', 303, 4.2, 19.8, 22, 62),
  ('863', '헝가리안 폭찹', '반찬', '돼지등심 100g, 물 50g, 사워크림 30g, 실파다진것 4g ,파프리카가루 3g, 머스터드 씨드 2.5g, 코리앤더 씨드 1g, 양파즙 13g, 마늘가루 1g', '["돼지등심","물","사워크림","실파다진것","파프리카가루","머스터드 씨드","코리앤더 씨드","양파즙","마늘가루"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','94786475-832c-4f97-aab7-bf6fbbe2236b','1cab0c39-b27a-4e4e-b125-fd5216fe8b24','4b410642-7bf9-45ad-9055-e7d9a34edaa1','5e79d288-1400-4817-bd20-e5e6041821b1']::uuid[], '[{"step":1,"text":"작은 불에 양념 재료를 넣고 섞어 절반은 돼지고기에 밑간한다.","imageUrl":null},{"step":2,"text":"달라붙지 않는 팬을 중간불고 가열한다.","imageUrl":null},{"step":3,"text":"양념한 돼지고기의 앞·뒷면을 익혀 고기의 중간이 핑크빛이 날 때까지 익히고 그릇에 옮겨담아 뚜껑을 덮어둔다.","imageUrl":null},{"step":4,"text":"강한불에 팬을 놓고 물 1컵을 부어 팬 바닥에 남아 있는 성분들을 녹여 2분정도 끓인다.","imageUrl":null},{"step":5,"text":"물이 1/4컵으로 줄어들면 불을 낮추고 사워크림을 넣고 거품기로 저으면서 끓지 않게 2~3분 간 조리한다.","imageUrl":null},{"step":6,"text":"접시에 돼지고기 폭찹을 담고 스푼으로 소스를 위에 얹고 실파를 뿌려준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053501_1416213301131.jpg', 314.1, 3.5, 18.6, 20.6, 110),
  ('865', '구운 닭고기 샐러드와 저나트륨 과일 드레싱', '반찬', '닭가슴살 60g, 양상추 18g, 방울토마토 18g, 브로컬리 20g ,파인애플통조림 40g, 키위 20g, 사과 10g, 양파 4g, 올리브오일 6g, 레몬즙 3.2g, 설탕 3.2g, 소금 0.4g', '["닭가슴살","양상추","방울토마토","브로컬리","파인애플통조림","키위","사과","양파","올리브오일","레몬즙","설탕","소금"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','1389717e-81e4-4350-96d4-d627d851aa10','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','9bf64924-ce53-42bb-849e-7294416e95d6','c97290bd-7146-45bc-8e7f-28390e7a95b0','e748d9a5-9c62-4d33-918a-b1b8e9a1f00b','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"닭가슴살을 170℃의 오븐에서 20분간 구운 후 잘게 찢는다.","imageUrl":null},{"step":2,"text":"양상추는 한 잎 크기로 뜯어 차가운 물에 담갔다가 물기를 뺀다.","imageUrl":null},{"step":3,"text":"방울토마토는 꼭지를 뗀 후 반으로 가른다.","imageUrl":null},{"step":4,"text":"브로콜리는 송이송이 떼어 끓는 물에 데친다.","imageUrl":null},{"step":5,"text":"저나트륨 과일드레싱 재료를 믹서에 넣고 곱게 간다.","imageUrl":null},{"step":6,"text":"준비된 재료를 한데 섞고 저나트륨 과일드레싱을 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053502_1416213302505.jpg', 246.5, 17.3, 13.1, 14.5, 175),
  ('867', '돼지고기 수육 부추부침', '반찬', '돼지고기 삼겹살 40g, 대파 5g, 마늘 5g, 생강 1.5g, 통후추 0.5g, 영양부추 10g,양파 2.5g, 무 15g, 소금 0.1g, 식초 1.5g, 설탕 1g ,고추기름 1g, 간장 2g, 발사믹식초 10g, 설탕 5g 저나트륨 두부 된장소스:두부 15g, 된장 2g, 청·홍고추다진것 1g, 물 2.5g', '["돼지고기 삼겹살","대파","마늘","생강","통후추","영양부추","양파","무","소금","식초","설탕","고추기름","간장","발사믹식초","된장","청·홍고추다진것","물"]'::jsonb, ARRAY['4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','058648c3-fd8e-476d-952f-b15dc67f1877','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','f80c9a7d-1510-44e2-a82b-28b9f684e191','2cf0c12b-f248-4012-8f53-303c730a7b3d','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','3a2bfe83-465c-4aaf-bde6-1c34303b15b7','f175019d-5a93-4cd4-aabc-e7e79445f15a','392236b1-82e9-4e38-bd12-6a53b80bf463','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"돼지고기는 덩어리로 준비해 충분히 무르도록 대파, 마늘, 생강, 통후추를 넣어 삶는다.","imageUrl":null},{"step":2,"text":"부추와 양파는 3cm 길이로 썰어 매운 소스 양념에 가볍게 무친다.","imageUrl":null},{"step":3,"text":"무는 채썰어 소금, 설탕, 식초에 절였다가 꼭 짠다.","imageUrl":null},{"step":4,"text":"삶은 돼지고기를 건져 얇게 저민다.","imageUrl":null},{"step":5,"text":"저민 돼지고기와 양념한 부추, 무를 곁들여 접시에 담는다.","imageUrl":null},{"step":6,"text":"두부를 곱게 다져 분량의 소스 재료와 섞어 저나트륨 두부 된장소스를 만들어 수육과 함께 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053504_1416213304243.jpg', 202.4, 10.3, 9.4, 13.2, 257),
  ('868', '쇠고기 채소볶음', '반찬', '쇠고기 40g, 생표고버섯 16g, 양송이버섯 9g, 애느타리버섯 12g, 흰목이버섯 0.4g, 목이버섯 0.4g, 샐러리 4g, 홍피망 8g, 정종 2g, 간장 2g, 육수 10g, 후춧가루 0.2g, 참기름 1g, 식용유 9g ,전분 2g, 달걀 2g', '["쇠고기","생표고버섯","양송이버섯","애느타리버섯","흰목이버섯","목이버섯","샐러리","홍피망","정종","간장","육수","후춧가루","참기름","식용유","전분","달걀"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','7c91e298-5ace-4242-8619-cdcc80587cd7','aad7c333-f1f0-46c1-8313-37cc64d689dc','12d2d4c9-705a-47f1-b628-30e042a970f8','df459e6f-3515-45d5-8c9a-9d37b6249379','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','f175019d-5a93-4cd4-aabc-e7e79445f15a','a4c37075-c03b-47bb-8aed-5e907620f5d2','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','0c0ade94-cfd8-4104-b44c-40e942cac482','a7a59e81-de3d-4893-b56a-b2218732a25b','6613d1d9-80a2-4ce4-9d3d-647203197e53','c7d438a6-34d6-423f-905d-446b839e2f39']::uuid[], '[{"step":1,"text":"소고기는 굵게 채썬다.","imageUrl":null},{"step":2,"text":"채썬 소고기에 전분과 달걀을 넣고 밑간을 한다.","imageUrl":null},{"step":3,"text":"버섯과 채소는 씻은 후 0.3cm 두께로 채 썬다.","imageUrl":null},{"step":4,"text":"후라이팬에 소고기를 넣고 볶는다.","imageUrl":null},{"step":5,"text":"채소와 버섯을 넣고 한번 더 볶는다.","imageUrl":null},{"step":6,"text":"육수에 간장, 정종, 후춧가루를 넣고 끓이다가 마지막에 참기름을 넣어 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053505_1416213305070.jpg', 191, 4.7, 9.4, 14.8, 219),
  ('869', '낙지볶음면', '일품', '낙지 20g, 쭈꾸미 20g, 생면 80g, 배추 20g, 양파 13g, 느타리버섯 13g, 표고버섯 13g ,청피망 8g, 홍피망 5g, 청양고추 15g, 대파 13g, 굴소스 1g, 고춧가루 2g, 매운고춧가루 2g, 소금 0.2g', '["낙지","쭈꾸미","생면","배추","양파","느타리버섯","표고버섯","청피망","홍피망","청양고추","대파","굴소스","고춧가루","매운고춧가루","소금"]'::jsonb, ARRAY['bd61e0e7-ed60-47e9-9a29-95dcc8ca68af','e116f85b-0eaa-40cb-8107-df5ec8486ad4','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','7c91e298-5ace-4242-8619-cdcc80587cd7','66458b1b-c92f-43fa-8eba-e428892ce88a','df459e6f-3515-45d5-8c9a-9d37b6249379','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','84104c49-0af4-4323-a56b-b67002a422d9','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"낙지와 쭈꾸미는 각각 소금물에 씻어 손질한다.","imageUrl":null},{"step":2,"text":"낙지는 5cm 길이로 자른다.","imageUrl":null},{"step":3,"text":"채소들은 각각 10cm 길이로 얇게 채 썬다.","imageUrl":null},{"step":4,"text":"소스를 만든다.","imageUrl":null},{"step":5,"text":"생면은 끓는 물에 데친다.","imageUrl":null},{"step":6,"text":"가열된 팬에 식용유를 넣고 채소를 볶다가 면과 소스를 넣고 충분히 볶는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053505_1416213305819.jpg', 154.6, 27.6, 9.8, 0.9, 270),
  ('871', '지중해 소스를 곁들인 도미스테이크', '일품', '도미 100g, 후춧가루 0.1g, 밀가루 4g, 식용유 12g, 화이트와인 50g, 물 50g, 파슬리다진것 1g,토마토 20g, 올리브 10g, 케이퍼 3g, 양파다진것 5g, 마늘다진것 2g, 토마토 15g, 바질 3g', '["도미","후춧가루","밀가루","식용유","화이트와인","물","파슬리다진것","토마토","올리브","케이퍼","양파다진것","마늘다진것","바질"]'::jsonb, ARRAY['bcb746cd-29c8-4bb2-93e4-5832b8adfa94','aab3b0b9-d346-4697-a1c8-1b1530153788','a7a59e81-de3d-4893-b56a-b2218732a25b','e16eaf50-ebd3-4933-a774-3ce6fc92593f','94786475-832c-4f97-aab7-bf6fbbe2236b','4362c386-a37c-44cd-9254-fafd74712a09','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','ba9e5a79-cab3-4af0-942b-0b35fd745150']::uuid[], '[{"step":1,"text":"도미에 후춧가루와 밀가루를 묻혀 놓는다.","imageUrl":null},{"step":2,"text":"토마토는 껍질을 벗겨 썰고 올리브는 0.8cm 주사위모양으로 썬다.","imageUrl":null},{"step":3,"text":"팬에 식용유를 넣고 도미를 넣어 익히다가 화이트와인을 넣는다.","imageUrl":null},{"step":4,"text":"소스 재료들과 물을 넣어 끓이면서 반으로 졸인다.","imageUrl":null},{"step":5,"text":"도미는 건져내고 팬에 남은 소스에 다진 파슬리가루를 뿌린다.","imageUrl":null},{"step":6,"text":"접시에 도미와 소스를 함께 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053508_1416213308021.jpg', 290, 7, 23, 13.8, 81),
  ('872', '해산물 샤브샤브', '국&찌개', '새우 13g, 모시조개 15g, 굴 25g, 패주 5g, 오징어 10g, 당귀잎 2.5g, 배추잎 2.5g, 샐러리잎 2.5g, 백만송이버섯 2.5g, 쑥갓 1.3g, 팽이버섯 1.3g, 곤약 2.5g, 단호박 5g ,다시물 9g, 볶은통깨 3.8g, 피넷버터 5.8g, 맛술 0.5g, 식초 1g, 타비스코 소스 1g, 진간장 1g', '["새우","모시조개","굴","패주","오징어","당귀잎","배추잎","샐러리잎","백만송이버섯","쑥갓","팽이버섯","곤약","단호박","다시물","볶은통깨","피넷버터","맛술","식초","타비스코 소스","진간장"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','b6047d76-6c94-4757-b1d1-9175aea0c84a','842f1298-903f-48e9-93bf-41bd90abfa9a','4d148f68-08e0-4599-8953-595db492bf23','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','54a52322-b4df-4354-a7a5-2a7b0c41f7bd','98d652af-a6d6-440c-9653-e22fc5d47d88','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','6c285c60-022a-4a00-b172-87df97f16a2f','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"새우는 내장을 제거하고 오징어는 껍질을 벗겨 안쪽에 대각선으로 칼집을 넣어 5x6cm로 썬다.","imageUrl":null},{"step":2,"text":"굴은 소금물에 흔들어 씻고 패주는 3등분 하고 모시조개는 소금물에 담가 해감시킨다.","imageUrl":null},{"step":3,"text":"곤약은 2x4cm로 썰어 가운데 칼집을 넣어 꼬아주고 버섯들은 찢어 준비한다.","imageUrl":null},{"step":4,"text":"쑥갓, 셀러리, 당귀잎은 잎만 뜯어 준비하고 배추잎은 저며 썬다.","imageUrl":null},{"step":5,"text":"통깨를 갈고 그 밖에 재료들은 모두 섞어 가는 체에 내려 땅콩 소스를 만든다.","imageUrl":null},{"step":6,"text":"냄비에 다시마 국물을 붓고 소금으로 약하게 간을 한 다음 해산물과 채소를 번갈아 가면서 익혀 소스에 찍어 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053508_1416213308848.jpg', 125, 5.8, 12, 6.1, 144),
  ('873', '고등어구이', '반찬', '고등어 70g, 밀가루 4g,간장 1g, 올리브오일 13g, 발사믹식초 6g, 꿀 4g', '["고등어","밀가루","간장","올리브오일","발사믹식초","꿀"]'::jsonb, ARRAY['f7f9c0c6-98d6-45b9-bbbe-26b57a62ee2e','aab3b0b9-d346-4697-a1c8-1b1530153788','f175019d-5a93-4cd4-aabc-e7e79445f15a','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6c285c60-022a-4a00-b172-87df97f16a2f','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"손질된 고등어는 5cm 길이로 토막낸 뒤 껍질에 칼집을 넣는다.","imageUrl":null},{"step":2,"text":"칼집 낸 고등어에 밀가루를 묻힌다.","imageUrl":null},{"step":3,"text":"오븐을 200℃로 예열한다.","imageUrl":null},{"step":4,"text":"간장, 올리브오일, 발사믹식초, 꿀을 섞어 소스를 완성한다.","imageUrl":null},{"step":5,"text":"고등어를 팬에 넣어 오븐에 굽는다.","imageUrl":null},{"step":6,"text":"저나트륨발사믹소스와 구운 고등어를 함께 제공한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053510_1416213310332.jpg', 279.9, 6.3, 14.7, 20.3, 105),
  ('874', '골뱅이무침', '반찬', '골뱅이 25g, 양파 13g, 대파 0.8g, 오이 25g, 미나리 13g, 깻잎 3g ,고추가루 1g, 생강즙 1g, 사과주스 10g, 설탕 10g, 고추장 2g, 식초 3g, 깨소금 1g, 참기름 1.3g, 마늘다진것 1g, 청고추 5g, 홍고추 5g', '["골뱅이","양파","대파","오이","미나리","깻잎","고추가루","생강즙","사과주스","설탕","고추장","식초","깨소금","참기름","마늘다진것","청고추","홍고추"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','dc7b2b73-74de-4fb8-9274-a5967ca444f9','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','06e6f3e7-0293-469d-a338-11a610f3e71b','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','6c285c60-022a-4a00-b172-87df97f16a2f','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"양파와 대파는 채 썰고 오이는 반달썰기한다.","imageUrl":null},{"step":2,"text":"미나리와 깻잎은 다지듯 썬다.","imageUrl":null},{"step":3,"text":"골뱅이는 물기를 제거하고 한 입 크기로 썬다.","imageUrl":null},{"step":4,"text":"대파 채는 얼음물에 담가 둔다.","imageUrl":null},{"step":5,"text":"저나트륨 초고추장소스를 만든다.","imageUrl":null},{"step":6,"text":"내기 직전에 무친 후 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053511_1416213311553.jpg', 104, 17.5, 5.1, 2.4, 202),
  ('875', '굴 두부 국', '국&찌개', '굴 20g, 두부 20g, 마늘다진것 1g, 실파 2g, 김 0.3g, 새우젓 0.5g, 소금 0.2g, 참기름 1g, 다시마 육수 100g, 홍고추 1g', '["굴","두부","마늘다진것","실파","김","새우젓","소금","참기름","다시마 육수","홍고추"]'::jsonb, ARRAY['842f1298-903f-48e9-93bf-41bd90abfa9a','4566cac5-9166-4c0d-906a-bfc7360f8f5b','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','09229cbc-4574-4002-b726-68c37345bbe9','8f2077de-dbd0-4372-a4c2-f987388f16b3','2cf0c12b-f248-4012-8f53-303c730a7b3d','0c0ade94-cfd8-4104-b44c-40e942cac482','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"굴은 소금으로 깨끗이 씻어 물기를 뺀다.","imageUrl":null},{"step":2,"text":"두부는 2x2x1cm 크기로 썰고, 실파는 2cm 길이로 자른다.","imageUrl":null},{"step":3,"text":"김은 구워서 잘게 찢거나 가위로 자른다.","imageUrl":null},{"step":4,"text":"고추는 채썰어 씨를 제거한다.","imageUrl":null},{"step":5,"text":"다시마 육수를 끓이다가 두부와 굴을 넣고 뭉근히 끓인 뒤 새우젓과 다진 마늘을 넣고 한소끔 끓인다.","imageUrl":null},{"step":6,"text":"실파와 홍고추를 넣고 마지막에 김과 참기름을 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053512_1416213312256.jpg', 49.5, 3.5, 4.8, 2.8, 257),
  ('3073', '과일퓨레수제함박스테이크', '반찬', '쇠고기(우둔) 12g, 돼지고기(전지) 23g, 도라지 1.3g, 사과 2.2g, 배 2.2g, 깐연근 1.7g, 토마토 9g, 깐양파 9.5g, 양송이버섯 1.3g, 당근 11.4g, 청피망 2.3g, 달걀 7g, 빵가루 5g, 파인애플 6.6g, 방울토마토 3g, 버터 1.2g, 밀가루 1.2g, 레몬 0.8g, 후추 1g, 생강 1g, 소금 0.1g', '["쇠고기","돼지고기","도라지","사과","배","깐연근","토마토","깐양파","양송이버섯","당근","청피망","달걀","빵가루","파인애플","방울토마토","버터","밀가루","레몬","후추","생강","소금"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','70e914d4-0d03-4202-8b66-81bd8499aa08','09d825b7-c1dc-412a-b253-f59a9d254243','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','e38c12a7-43cb-421a-a36e-7ef0d32517fa','df459e6f-3515-45d5-8c9a-9d37b6249379','c7d438a6-34d6-423f-905d-446b839e2f39','45080597-55fa-42dc-aa65-12d7694e4b7e','c97290bd-7146-45bc-8e7f-28390e7a95b0','7aabd532-361f-4240-aa33-6bfa1be4bc4e','aab3b0b9-d346-4697-a1c8-1b1530153788','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"도라지, 사과, 배, 연근은 갈아서 뭉근하게 조려 퓨레를 만든다.","imageUrl":null},{"step":2,"text":"연근, 토마토, 양파, 양송이버섯, 당근, 청피망 등 모든 채소는 곱게 다진다.","imageUrl":null},{"step":3,"text":"고기에 퓨레, 달걀, 후추, 생강, 빵가루를 넣어 찰지게 반죽하고 납작하게 빚어서 오븐에 굽는다.","imageUrl":null},{"step":4,"text":"소스제조를 위해 밀가루, 버터를 볶아 루를 만든다.","imageUrl":null},{"step":5,"text":"④에 ②에서 다져놓은 야채를 넣어 끓이고, 소금간과 레몬즙을 뿌려준다.","imageUrl":null},{"step":6,"text":"구운 수제함박스테이크에 새싹채소-파인애플-방울토마토 순으로 장식하고 소스와 함께 제공한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102744_1584062864601.JPG', 166, 14.9, 11.7, 6.6, 377.5),
  ('3169', '달콤과일깍두기', '반찬', ' 무(20g), 배(10g), 참외(10g), 마늘(1g), 새우젓(0.5g), 생강(0.5g), 실파(1g)
, 고춧가루(1g), 통깨(0.5g)', '["무","배","참외","마늘","새우젓","생강","실파","고춧가루","통깨"]'::jsonb, ARRAY['f80c9a7d-1510-44e2-a82b-28b9f684e191','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','7dd9d8bc-46ee-40cb-974c-6fb77702e323','fc6e31ce-388e-45cd-956b-b238b9134eb1','8f2077de-dbd0-4372-a4c2-f987388f16b3','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','84104c49-0af4-4323-a56b-b67002a422d9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"배와 참외는 1~1.5cm 크기로 깍둑 썬다.","imageUrl":null},{"step":2,"text":"무는 1~1.5cm 크기로 깍둑 썬다.","imageUrl":null},{"step":3,"text":"실파는 1cm 길이로 썬다.","imageUrl":null},{"step":4,"text":"새우젓, 마늘, 생강은 곱게 다진다.","imageUrl":null},{"step":5,"text":"고춧가루, 새우젓, 마늘, 생강, 통깨를 버무려 양념장을 만든다.","imageUrl":null},{"step":6,"text":"배, 참외, 무, 실파에 양념장을 넣어 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128052409_1611822249198.JPG', 19.9, 3.8, 0.7, 0.2, 19.8),
  ('3216', '비트 단호박 파스타', '일품', '삶은 스파게티(80g), 감자(10g), 파르메산 치즈가루(약간), 어린잎채소(약간), 비트(40g), 올리브유(30g), 스리라차소스(5g), 마늘(10g), 미니 단호박(70g), 생크림(100g), 설탕(3g)', '["삶은 스파게티","감자","파르메산 치즈가루","어린잎채소","비트","올리브유","스리라차소스","마늘","미니 단호박","생크림","설탕"]'::jsonb, ARRAY['b85df3ba-e324-47fa-b25d-d5bb552b8590','20894da1-739d-4d52-b5fe-4943bd3492d5','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','524e1b82-1f81-4648-b50c-441404a06786','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','fc6e31ce-388e-45cd-956b-b238b9134eb1','98d652af-a6d6-440c-9653-e22fc5d47d88','af187077-b7f6-4b0e-9e99-f844f6359ac2','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"믹서에 비트소스 재료를 넣어 곱게 갈아 삶은 스파게티에 넣어 버무린다.","imageUrl":null},{"step":2,"text":"미니 단호박은 잘게 자른 뒤 끓는 물에 3분간 익혀 건진다.","imageUrl":null},{"step":3,"text":"익힌 미니 단호박은 믹서에 곱게 간 뒤 생크림으로 농도를 맞추고 설탕으로 간하여 단호박소스를 만든다.","imageUrl":null},{"step":4,"text":"감자는 얇게 모양대로 썬다.","imageUrl":null},{"step":5,"text":"중간 불로 달군 팬에 얇게 썬 감자를 2분간 볶아 바삭하게 만들어 잘게 부순다.","imageUrl":null},{"step":6,"text":"그릇에 단호박소스를 붓고, 비트소스를 버무린 스파게티를 담은 뒤 어린잎채소, 파르메산 치즈가루, 잘게 부순 감자를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308042347_1615188227457.jpg', 340.5, 40.5, 6.9, 16.8, 136.4),
  ('3271', '해조비빔국수', '기타', ' 오이(⅓개), 양파(⅓개), 파프리카(빨강, 노랑 각 ½개), 도토리묵(250g), 해조국수(1팩=180g), 스테비아(0.3Ts), 식초(1Ts), 간장(0.5Ts), 스리라차소스(1Ts), 매실청(0.5Ts), 다진 마늘(1.5Ts), 참깨(0.5Ts)', '["오이","양파","파프리카","도토리묵","해조국수","스테비아","식초","간장","스리라차소스","매실청","다진 마늘","참깨"]'::jsonb, ARRAY['9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','6286955d-86b2-4a91-9b23-c49f388a5f45','49b48723-2e40-46b0-9588-00f41a6a02c2','6c285c60-022a-4a00-b172-87df97f16a2f','f175019d-5a93-4cd4-aabc-e7e79445f15a','02fd7135-0ec3-49ec-82e3-390536ab2cf5','fc6e31ce-388e-45cd-956b-b238b9134eb1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"오이, 양파, 파프리카는 같은 길이로 채 썰고, 도토리묵은 2~3cm 두께로 채 썬다.","imageUrl":null},{"step":2,"text":"양파는 찬물에 5분간 담가 매운맛을 제거하고, 해조국수는 찬물에 헹궈 건진다.","imageUrl":null},{"step":3,"text":"양념장을 만든다.","imageUrl":null},{"step":4,"text":"그릇에 해조국수를 가운데 담고, 손질한 채소와 묵을 올린다.","imageUrl":null},{"step":5,"text":"양념장을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJe-oV', 106.2, 21.2, 2.7, 1.2, 357.6),
  ('3276', '닭봉 로제스튜', '일품', ' 양파(3개), 마늘(5쪽), 감자(1개), 파프리카(빨강, 노랑 각 ⅓개), 당근(½개), 브로콜리(½개), 닭봉(20개), 통조림 홀토마토(2캔=822g), 생크림(1컵), 파르메산 치즈가루(1컵) 월계수잎(1장), 소금(0.5Ts), 후춧가루(0.3Ts), 올리브유(5Ts), 화이트와인(⅓컵), 강황(1Ts), 코리앤더가루(0.5Ts), 커민(1Ts), 레드크러쉬드 페퍼(1Ts), 바질가루(0.5Ts), 오레가노가루(1Ts), 버터(2Ts)', '["양파","마늘","감자","파프리카","당근","브로콜리","닭봉","통조림 홀토마토","생크림","파르메산 치즈가루 월계수잎","소금","후춧가루","올리브유","화이트와인","강황","코리앤더가루","커민","레드크러쉬드 페퍼","바질가루","오레가노가루","버터"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','20894da1-739d-4d52-b5fe-4943bd3492d5','5e79d288-1400-4817-bd20-e5e6041821b1','e38c12a7-43cb-421a-a36e-7ef0d32517fa','9bf64924-ce53-42bb-849e-7294416e95d6','af187077-b7f6-4b0e-9e99-f844f6359ac2','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','e16eaf50-ebd3-4933-a774-3ce6fc92593f','ba9e5a79-cab3-4af0-942b-0b35fd745150','7aabd532-361f-4240-aa33-6bfa1be4bc4e']::uuid[], '[{"step":1,"text":"양파와 마늘은 다지고, 감자, 파프리카, 당근은 한입 크기로 썰고, 브로콜리는 송이만 떼어낸다.","imageUrl":null},{"step":2,"text":"닭봉은 밑간해 15분간 재운다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 올리브유를 두르고, 다진 양파와 마늘을 넣어 양파가 갈색이 될 때까지 볶고, 화이트와인을 넣어 자작해질 때까지 볶고, 월계수잎과 홀토마토를 넣어 으깬 뒤 5분간 끓인다.","imageUrl":null},{"step":4,"text":"강황, 코리앤더가루, 커민, 레드크러쉬드 페퍼, 바질가루, 오레가노 가루를 넣어 섞고, 한 김 식힌 뒤 믹서에 곱게 갈아 토마토소스를 만든다.","imageUrl":null},{"step":5,"text":"밑간한 닭봉은 중간 불로 달군 팬에 버터를 둘러 앞뒤로 노릇하게 익혀 꺼낸다.","imageUrl":null},{"step":6,"text":"같은 팬에 손질한 채소를 넣어 볶다가 구운 닭봉, 토마토소스를 넣어 10분간 끓이고, 생크림과 파르메산 치즈가루를 넣어 자작해질 때까지 졸여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr94Gc', 379, 14.3, 28, 23.3, 340.6),
  ('3280', '수제새우소시지', '반찬', ' 양파(½개), 칵테일새우(14마리), 라이스페이퍼(8장), 깻잎(3장), 감자전분(2Ts), 후춧가루(약간), 레몬즙(1ts), 다진 마늘(2Ts), 올리브유(2ts), 다진 마늘(1Ts), 올리고당(1Ts), 파슬리가루(1ts)', '["양파","칵테일새우","라이스페이퍼","깻잎","감자전분","후춧가루","레몬즙","다진 마늘","올리브유","올리고당","파슬리가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','6f10b4ad-53a2-4a07-ba89-19a6b074373d','241e49d7-4aa4-4411-8ded-350a16b41222','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','6613d1d9-80a2-4ce4-9d3d-647203197e53','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','4362c386-a37c-44cd-9254-fafd74712a09']::uuid[], '[{"step":1,"text":"양파와 깻잎은 곱게 다지고, 칵테일새우는 깨끗하게 씻은 뒤 곱게 다진다.","imageUrl":null},{"step":2,"text":"다진 양파, 깻잎, 새우에 양념을 넣어 고루 섞은 뒤 치대 새우반죽을 만든다.","imageUrl":null},{"step":3,"text":"뜨거운 물(4컵)에 라이스페이퍼를 살짝 담갔다 꺼내 식용유를 바른 도마 위에 올린다.","imageUrl":null},{"step":4,"text":"지퍼백에 새우반죽을 넣은 뒤 가위로 끝부분을 잘라 라이스페이퍼 위에 반죽을 짜 올리고, 돌돌 말아 새우소시지를 만든다.","imageUrl":null},{"step":5,"text":"중간 불로 달군 팬에 식용유를 둘러 새우소시지를 올린 뒤 겉면이 하얗게 변할 때까지 노릇하게 굽는다.","imageUrl":null},{"step":6,"text":"그릇에 담고 마늘소스를 윗면에 발라 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr97YW', 266.5, 41.7, 10.1, 6.6, 317),
  ('3576', '감태샐러드말이와 버섯말이깐풍', '반찬', ',
 감태 (2g(2장)), 라이스페이퍼(60g), 양상추(80g), 적채(20g), 건표고버섯(5g), 느타리버섯(10g), 만가닥버섯(10g), 청고추(5g), 홍고추(5g), 대파(5g), 마늘(5g),
 마요네즈(18g), 홀그레인 머스터드(6g), 파인애플청(6g), 진간장(3g), 굴 소스(6g), 올리고당(10g), 식초(8g), 참기름(6g), 식용유(20g)', '["감태 )","라이스페이퍼","양상추","적채","건표고버섯","느타리버섯","만가닥버섯","청고추","홍고추","대파","마늘","마요네즈","홀그레인 머스터드","파인애플청","진간장","굴 소스","올리고당","식초","참기름","식용유"]'::jsonb, ARRAY['241e49d7-4aa4-4411-8ded-350a16b41222','1389717e-81e4-4350-96d4-d627d851aa10','fd4254d4-2691-47e1-9367-c2b820ef8d00','66458b1b-c92f-43fa-8eba-e428892ce88a','7c91e298-5ace-4242-8619-cdcc80587cd7','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','549c7365-28e9-491f-9040-412558f93a5c','f175019d-5a93-4cd4-aabc-e7e79445f15a','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','6c285c60-022a-4a00-b172-87df97f16a2f','0c0ade94-cfd8-4104-b44c-40e942cac482','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"양상추, 적채는 채 썰어 찬물에 담근다. 마요네즈, 홀그레인 머스터드, 파인애플청을 섞어 샐러드 드레싱을 만든다.","imageUrl":null},{"step":2,"text":"데친 느타리버섯, 만가닥버섯과 불린 건표고버섯의 물기를 제거하고 깍둑 썰기하여 예열한 팬에 볶고 진간장,참기름(3g)으로 간한다.","imageUrl":null},{"step":3,"text":"라이스페이퍼에 올리고 한입 크기로 싼다. 예열한 팬에 식용유(10g)를 두르고 굽는다.","imageUrl":null},{"step":4,"text":"물기를 제거한 양상추, 적채를 라이스페이퍼에 올리고 싼 뒤, 감태 위에 올려 돌돌 말고 한입 크기로 썬다.","imageUrl":null},{"step":5,"text":"예열한 팬에 식용유(10g)를 두르고 다진 청고추, 홍고추, 대파, 마늘을 볶아 향을 내고 굴 소스, 올리고당, 식초, 참기름(3g)을 넣어 깐풍 소스를 만든다.","imageUrl":null},{"step":6,"text":"접시에 담고 샐러드 드레싱과 깐풍 소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120012701_1732076821671.jpg', 125.2, 22.9, 2, 2.8, 120.1),
  ('876', '금태찜', '반찬', '금태 50g, 소금 0.1g, 흰후춧가루 0.1g, 청주 3g, 생강즙 3g, 녹말가루 1g, 콩나물 16g, 미나리 12g, 느타리버섯 16g, 홍고추 0.8g, 당근 10g, 대파 4g, 무 16g ,다시마국물 100g, 간장 2g, 맛술 2g, 식초 1g', '["금태","소금","흰후춧가루","청주","생강즙","녹말가루","콩나물","미나리","느타리버섯","홍고추","당근","대파","무","다시마국물","간장","맛술","식초"]'::jsonb, ARRAY['2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','6613d1d9-80a2-4ce4-9d3d-647203197e53','2db049b2-f39c-47ba-857f-fa02b3b0c610','dc7b2b73-74de-4fb8-9274-a5967ca444f9','7c91e298-5ace-4242-8619-cdcc80587cd7','30b5d53c-d247-4f04-9b50-c0f728e65cf9','e38c12a7-43cb-421a-a36e-7ef0d32517fa','4b410642-7bf9-45ad-9055-e7d9a34edaa1','f80c9a7d-1510-44e2-a82b-28b9f684e191','a4c37075-c03b-47bb-8aed-5e907620f5d2','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"금태는 아가미와 내장을 제거 한 후 몸통에 어슷하게 칼집을 넣어 소금, 흰후추, 청주, 생강즙으로 밑간을 해둔다.","imageUrl":null},{"step":2,"text":"밑간 한 금태의 수분을 닦고 녹말가루를 고루 묻힌다.","imageUrl":null},{"step":3,"text":"콩나물은 머리와 꼬리를 떼고 미나리는 7cm 길이로 썰고 느타리버섯은 굵게 찢고 홍고추, 대파, 당근, 무는 채썬다.","imageUrl":null},{"step":4,"text":"다시마 국물에 간장, 맛술, 식초를 섞어 찜소스를 만든다.","imageUrl":null},{"step":5,"text":"찜그릇에 무, 당근 채썬 것을 놓고 녹말 입힌 도미와 찜소스를 얹어 찐다.","imageUrl":null},{"step":6,"text":"중간 중간 소스를 뿌려 주고 느타리버섯, 미나리, 홍고추, 콩나물, 채썬 대파를 얹어 찐다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053513_1416213313394.jpg', 73.8, 7.6, 10.8, 0.6, 305),
  ('877', '김자반', '반찬', '김 10g, 마늘 8g, 생강 5g, 통깨 1.3g ,물 30g, 간장 2g, 설탕 2g, 물엿 1g, 식초 1g, 홍고추 1g', '["김","마늘","생강","통깨","물","간장","설탕","물엿","식초","홍고추"]'::jsonb, ARRAY['09229cbc-4574-4002-b726-68c37345bbe9','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','94786475-832c-4f97-aab7-bf6fbbe2236b','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','6c285c60-022a-4a00-b172-87df97f16a2f','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"김은 티를 골라낸다.","imageUrl":null},{"step":2,"text":"홍고추, 마늘, 생강은 곱게 채썬다.","imageUrl":null},{"step":3,"text":"간장소스의 양념들은 모두 합하여 20분 가량 낮은 불에서 끓여서 식힌다.","imageUrl":null},{"step":4,"text":"김은 먹기 좋은 크기로 12~18등분으로 자른다.","imageUrl":null},{"step":5,"text":"양념간장에 마늘, 생강, 홍고추채를 섞는다.","imageUrl":null},{"step":6,"text":"김을 차곡차곡 쌓은 뒤 양념간장을 위에 부어준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053514_1416213314112.jpg', 45.2, 10.4, 4.8, 0.9, 232),
  ('878', '꽁치 양념구이', '반찬', '꽁치 60g, 후춧가루 0.1g, 밀가루 4g, 녹말가루 8g, 식용유 2g ,토마토케첩 2g, 고추장 2g, 마늘 2g, 생강즙 2.4g, 청고추다진것 4g, 홍고추다진것 2g, 물엿 20g, 간장 1g, 물 75g, 맛술 5g', '["꽁치","후춧가루","밀가루","녹말가루","식용유","토마토케첩","고추장","마늘","생강즙","청고추다진것","홍고추다진것","물엿","간장","물","맛술"]'::jsonb, ARRAY['bcb746cd-29c8-4bb2-93e4-5832b8adfa94','aab3b0b9-d346-4697-a1c8-1b1530153788','6613d1d9-80a2-4ce4-9d3d-647203197e53','a7a59e81-de3d-4893-b56a-b2218732a25b','0136fc6a-3a80-4f4c-8057-10bbf34ea572','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','30b5d53c-d247-4f04-9b50-c0f728e65cf9','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','f175019d-5a93-4cd4-aabc-e7e79445f15a','94786475-832c-4f97-aab7-bf6fbbe2236b','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1']::uuid[], '[{"step":1,"text":"꽁치는 머리와 내장을 제거해 손질하고 칼집을 낸다.","imageUrl":null},{"step":2,"text":"손질한 꽁치에 후춧가루와 청주를 뿌려 밑간해 둔다.","imageUrl":null},{"step":3,"text":"밑간해 둔 꽁치의 수분을 제거하고 밀가루를 묻힌다.","imageUrl":null},{"step":4,"text":"밀가루 묻힌 꽁치를 팬에서 노릇하게 굽는다.","imageUrl":null},{"step":5,"text":"팬에 저나트륨 고추장소스 재료를 넣고 살짝 졸인다.","imageUrl":null},{"step":6,"text":"구워진 꽁치에 소스를 뿌려낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053514_1416213314814.jpg', 234.4, 28.9, 12.7, 7.2, 169),
  ('879', '꽃게강정', '반찬', '꽃게 120g, 후춧가루 0.3g, 청고추 1g, 홍고추 1g, 토마토케첩 4g, 마늘 1.3g, 생강 0.5g, 생강즙 4g, 찹쌀가루 8g, 식용유 10g ,매운 고춧가루 1.3g, 맛술 8g, 간장 2g, 물엿 10g', '["꽃게","후춧가루","청고추","홍고추","토마토케첩","마늘","생강","생강즙","찹쌀가루","식용유","매운 고춧가루","맛술","간장","물엿"]'::jsonb, ARRAY['0c2a6773-2dcd-4ed5-a02c-4a52b1bdeab4','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','30b5d53c-d247-4f04-9b50-c0f728e65cf9','0136fc6a-3a80-4f4c-8057-10bbf34ea572','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','4cb11562-015f-4ab5-969f-0ea8483a0b42','a7a59e81-de3d-4893-b56a-b2218732a25b','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','f175019d-5a93-4cd4-aabc-e7e79445f15a','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"꽃게를 잘 손질한다.","imageUrl":null},{"step":2,"text":"손질한 꽃게에 생강즙과 후춧가루로 간을 한다.","imageUrl":null},{"step":3,"text":"청·홍고추는 사방 0.7cm로 썰고 생강은 다진다.","imageUrl":null},{"step":4,"text":"매운 고추소스의 재료들을 모두 섞고 냄비에 넣어 끓이다가 준비해둔 채소들을 넣고 한소큼 끓여준다.","imageUrl":null},{"step":5,"text":"꽃게에 찹쌀가루를 묻혀 튀긴다.","imageUrl":null},{"step":6,"text":"4의 소스에 넣고 섞는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053515_1416213315658.jpg', 261, 21.9, 17.6, 11.1, 470),
  ('880', '낙지강회', '반찬', '낙지 50g, 실파 30g, 미역마른것 3g, 쌈다시마 0.5g, 당근 10g  고추장 1g, 식초 2g, 설탕 2g, 사과주스 5g, 고춧가루 1g', '["낙지","실파","미역마른것","쌈다시마","당근","식초","설탕","사과주스","고춧가루"]'::jsonb, ARRAY['bd61e0e7-ed60-47e9-9a29-95dcc8ca68af','4b410642-7bf9-45ad-9055-e7d9a34edaa1','6565cc3a-c3d6-45b5-a7fb-05a3c03015bf','e38c12a7-43cb-421a-a36e-7ef0d32517fa','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','84104c49-0af4-4323-a56b-b67002a422d9']::uuid[], '[{"step":1,"text":"낙지는 내장을 손질하고 밀가루로 비벼 씻는다.","imageUrl":null},{"step":2,"text":"씻어낸 낙지는 끓는 소금물에 살짝 데쳐서 다리를 하나씩 떼어 낸다.","imageUrl":null},{"step":3,"text":"실파는 데치고 불린 미역과 다시마도 데쳐서 알맞게 자른다.","imageUrl":null},{"step":4,"text":"당근은 채썰어 준비해 둔다.","imageUrl":null},{"step":5,"text":"데친 낙지를 절반씩 실파와 미역, 다시마로 감는다.","imageUrl":null},{"step":6,"text":"저나트륨 고추장소스를 만들어 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053517_1416213317156.jpg', 51.9, 7.1, 6.8, 0.4, 153),
  ('881', '낙지 잣소스 냉채', '반찬', '낙지 50g, 오이 20g, 밤 15g, 미나리 15g, 배 30g, 홍피망 12g ,잣20g, 배즙 37.5, 흰후춧가루 0.1g레몬즙 5g, 소금 0.3g', '["낙지","오이","밤","미나리","배","홍피망","잣","배즙","흰후춧가루","소금"]'::jsonb, ARRAY['bd61e0e7-ed60-47e9-9a29-95dcc8ca68af','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','5e4a7ae8-e12e-48b6-88d5-fc3521d3dce8','dc7b2b73-74de-4fb8-9274-a5967ca444f9','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','df459e6f-3515-45d5-8c9a-9d37b6249379','bbbbd533-8922-4dac-9e4c-cd93ea710c92','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"낙지는 밀가루를 넣어 주물러 미끈거리는 것을 씻어내고 흐르는 물에 헹군다.","imageUrl":null},{"step":2,"text":"끓는 물에 데쳐 한 입 크기로 썬다.","imageUrl":null},{"step":3,"text":"오이는 가운데 씨를 잘라낸 뒤 눈썹 모양으로 썰고 홍피망과 미나리는 5cm 길이로 썬다.","imageUrl":null},{"step":4,"text":"배는 굵게 채 썰고 밤은 얇게 썬다.","imageUrl":null},{"step":5,"text":"잣은 곱게 다져 분마기에 넣고 배즙을 조금씩 넣어가며 뽀얗게 즙을 내고 레몬즙과 흰후춧가루, 소금을 넣어준다.","imageUrl":null},{"step":6,"text":"준비된 재료를 잣소스에 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053518_1416213318219.jpg', 226.7, 18.5, 10, 14.3, 233),
  ('882', '두부 해산물 꼬치구이', '반찬', '두부 100g, 소라살 16g, 패주 16g, 소금 0.2 ,마늘 0.2g, 올리브유 7g, 바질다진것 0.6g, 방울토마토 8g', '["두부","소라살","패주","소금","마늘","올리브유","바질다진것","방울토마토"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','2cf0c12b-f248-4012-8f53-303c730a7b3d','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','ba9e5a79-cab3-4af0-942b-0b35fd745150','aa597bcd-596b-4cbe-a2c4-3da0d060cb50']::uuid[], '[{"step":1,"text":"두부는 4x1.5x1cm 크기로 썬 후 소금을 뿌려 물기를 제거한다.","imageUrl":null},{"step":2,"text":"소라살은 내장을 뺀 뒤 반으로 가르고 패주는 주위의 지저분한 막을 벗겨 깨끗이 손질한 뒤 2~3등분 한다.","imageUrl":null},{"step":3,"text":"바질 잎은 다진다.","imageUrl":null},{"step":4,"text":"볼에 다진 마늘을 담고 소금 간을 한 뒤 올리브유를 조금씩 넣으면서 한 방향으로 젓다가 다진 바질을 넣어 마늘 올리브유 소스를 만든다.","imageUrl":null},{"step":5,"text":"두부와 해산물을 차례로 꼬치에 끼워 붓으로 소스를 고루 바른다.","imageUrl":null},{"step":6,"text":"예열된 250℃ 오븐이나 그릴에서 노릇하게 구워낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053519_1416213319253.jpg', 182.6, 2.6, 15.6, 12.8, 146),
  ('883', '마 두부 오징어전', '반찬', '두부 60g, 마 60g, 표고버섯마른것 3.5g, 오징어 6g, 소금 0.2g, 후춧가루 0.1g, 녹말 0.8g, 식용유 4.8g, 홍고추 0.5g,간장 1.5g, 조미술 1.5g, 설탕 0.5g, 식초 0.5g', '["두부","마","표고버섯마른것","오징어","소금","후춧가루","녹말","식용유","홍고추","간장","조미술","설탕","식초"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','a988ffbb-92c3-4c68-8cea-a2f10c329015','66458b1b-c92f-43fa-8eba-e428892ce88a','4d148f68-08e0-4599-8953-595db492bf23','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6613d1d9-80a2-4ce4-9d3d-647203197e53','a7a59e81-de3d-4893-b56a-b2218732a25b','30b5d53c-d247-4f04-9b50-c0f728e65cf9','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"두부는 소창에 싸서 으깬다.","imageUrl":null},{"step":2,"text":"마는 껍질을 벗기고 강판에 간다.","imageUrl":null},{"step":3,"text":"홍고추는 다지고 표고버섯은 물에 불린 후 잘게 다진다. 오징어도 손질하여 잘게 다진다.","imageUrl":null},{"step":4,"text":"두부와 마, 다진 재료들을 모두 섞어 소금, 후춧가루로 간한다.","imageUrl":null},{"step":5,"text":"반죽을 한 스푼씩 떠 식용유를 넣은 팬에 노릇하게 구워낸다.","imageUrl":null},{"step":6,"text":"재료를 섞어 양념장을 만들어 함께 낸다","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053520_1416213320408.jpg', 173.3, 16.8, 10.6, 8.8, 159),
  ('884', '멸치 찹쌀양념 튀김', '반찬', '멸치중간것 10g, 찹쌀가루 5g, 식용유 2g, 땅콩 13g ,고추장 2g, 간장 0.5g, 양파즙 10g, 마늘즙 1g, 생강즙 0.5g, 맛술 5g, 설탕 3g, 물엿 3g, 식용유 2g, 참기름 0.3g, 흑임자 4g, 실파 5g', '["멸치중간것","찹쌀가루","식용유","땅콩","고추장","간장","양파즙","마늘즙","생강즙","맛술","설탕","물엿","참기름","흑임자","실파"]'::jsonb, ARRAY['4cb11562-015f-4ab5-969f-0ea8483a0b42','a7a59e81-de3d-4893-b56a-b2218732a25b','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','f175019d-5a93-4cd4-aabc-e7e79445f15a','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','06e6f3e7-0293-469d-a338-11a610f3e71b','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"멸치는 티를 골라내어 선별해 두고 실파는 썬다.","imageUrl":null},{"step":2,"text":"팬에 식용유를 두르고 소스의 양념들을 넣어 최대한 낮은 불에서 서서히 졸여 농도를 낸다.","imageUrl":null},{"step":3,"text":"찹쌀가루 중 1/3분량만 묽게 풀을 쑤어 식힌다.","imageUrl":null},{"step":4,"text":"멸치에 풀을 가볍게 익히고 남은 찹쌀가루를 묻힌다.","imageUrl":null},{"step":5,"text":"튀김기름의 온도를 170~180℃에 맞추어 4의 멸치를 재빨리 튀겨낸다.","imageUrl":null},{"step":6,"text":"식은 후에 (2)의 소스에 버무리거나 끼얹어 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053521_1416213321149.jpg', 212.9, 17.6, 8.8, 13.1, 181),
  ('885', '미역 물오징어 연두부 초회', '반찬', '연두부큰것 25g, 불린미역 25g, 물오징어 25g, 꽈리고추 4.2g ,고추장 2.5g, 간장 0.8g, 물엿 1g, 레몬즙 0.8g, 식초 0.8g, 마늘다진것 0.2g, 생강즙 1g, 파다진것 0.2g, 참기름 0.1g, 통깨 0.2g', '["연두부큰것","불린미역","물오징어","꽈리고추","고추장","간장","물엿","레몬즙","식초","마늘다진것","생강즙","파다진것","참기름","통깨"]'::jsonb, ARRAY['30b5d53c-d247-4f04-9b50-c0f728e65cf9','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','f175019d-5a93-4cd4-aabc-e7e79445f15a','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','6c285c60-022a-4a00-b172-87df97f16a2f','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"연두부는 작은 숟가락으로 떠 놓는다.","imageUrl":null},{"step":2,"text":"불린 미역은 4cm 길이로 썬다.","imageUrl":null},{"step":3,"text":"오징어는 껍질을 벗기고 칼집을 넣어 데친다.","imageUrl":null},{"step":4,"text":"데친 오징어는 솔방울 모양으로 자른다.","imageUrl":null},{"step":5,"text":"꽈리고추는 데친다.","imageUrl":null},{"step":6,"text":"재료를 보기좋게 담고 양념장을 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053521_1416213321929.jpg', 48.3, 3.9, 7, 1.2, 171),
  ('886', '부추조개살 콩비지조림', '반찬', '콩비지 20g, 조갯살 20g, 부추 5g, 당근 5g ,간장 1g, 청주 1g, 조미술 1g, 설탕 1g, 생강즙 1g, 마늘다진것 0.5g', '["콩비지","조갯살","부추","당근","간장","청주","조미술","설탕","생강즙","마늘다진것"]'::jsonb, ARRAY['058648c3-fd8e-476d-952f-b15dc67f1877','e38c12a7-43cb-421a-a36e-7ef0d32517fa','f175019d-5a93-4cd4-aabc-e7e79445f15a','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','06e6f3e7-0293-469d-a338-11a610f3e71b','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"조갯살은 연한 소금물로 헹구어 물기를 뺀다.","imageUrl":null},{"step":2,"text":"부추는 2~3cm 길이로 썰고 당근은 짧게 채 썬다.","imageUrl":null},{"step":3,"text":"냄비에 분량의 조림장 재료를 전부 넣고 한소큼 끓어 오르면 조갯살을 넣어 살짝 데쳐 건져둔다.","imageUrl":null},{"step":4,"text":"3의 냄비에 물 3컵을 더 넣고 당근을 넣어 조림장 분량이 2/3정도가 될 때까지 졸인다.","imageUrl":null},{"step":5,"text":"다른 팬에 기름을 두르지 않고 콩비지를 넣어 보슬보슬해질 때 까지 볶는다.","imageUrl":null},{"step":6,"text":"5에 4를 전부 붓고 채썬 부추와 데친 조갯살도 넣어 간이 고루 들도록 저어가며 볶는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053522_1416213322648.jpg', 36, 5.3, 3.3, 0.5, 62),
  ('888', '연어냉채', '반찬', '훈재연어 40g, 흰후춧가루 0.01g, 녹말가루 2.4g, 오이 3.8g, 래디쉬 15g, 샐러리 7.5g, 배 7.5g ,파인애플 3g, 파인애플 통조림 국물 4.5g, 올리브오일 3.6g, 레몬즙 1.5g, 사과 4.5g, 소금 0.2g, 설탕 1.5g', '["훈재연어","흰후춧가루","녹말가루","오이","래디쉬","샐러리","배","파인애플","파인애플 통조림 국물","올리브오일","레몬즙","사과","소금","설탕"]'::jsonb, ARRAY['bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6613d1d9-80a2-4ce4-9d3d-647203197e53','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','f80c9a7d-1510-44e2-a82b-28b9f684e191','12d2d4c9-705a-47f1-b628-30e042a970f8','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','c97290bd-7146-45bc-8e7f-28390e7a95b0','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','2cf0c12b-f248-4012-8f53-303c730a7b3d','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"연어는 주사위모양으로 썬다.","imageUrl":null},{"step":2,"text":"흰후춧가루를 살짝 뿌린 후 녹말가루를 묻힌다.","imageUrl":null},{"step":3,"text":"녹말을 묻힌 연어는 김 오른 찜통에 찌고 식혀둔다.","imageUrl":null},{"step":4,"text":"오이, 래디쉬, 셀러리, 배는 곱게 채썰어 냉수에 담갔다가 건진다.","imageUrl":null},{"step":5,"text":"캔 파인애플을 잘게 썰어 분량의 재료들과 함께 믹서기에 곱게 간다.","imageUrl":null},{"step":6,"text":"접시에 준비된 채소와 찐 연어를 담고 소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053524_1416213324459.jpg', 129, 7.4, 9.4, 6.7, 398),
  ('889', '오징어말이 케첩조림', '반찬', '오징어 80g, 당근 17g, 시금치 17g, 달걀 19g, 표고버섯마른것 7g, 식용유 1.4g, 밀가루 1.1g ,마늘다진것 1.1g, 양파다진것 1.1g, 토마토케첩 2g, 물 60g, 후춧가루0.1g', '["오징어","당근","시금치","달걀","표고버섯마른것","식용유","밀가루","마늘다진것","양파다진것","토마토케첩","물","후춧가루"]'::jsonb, ARRAY['4d148f68-08e0-4599-8953-595db492bf23','e38c12a7-43cb-421a-a36e-7ef0d32517fa','9a7f4da6-531b-4478-89ff-d73beafcad1b','c7d438a6-34d6-423f-905d-446b839e2f39','66458b1b-c92f-43fa-8eba-e428892ce88a','a7a59e81-de3d-4893-b56a-b2218732a25b','aab3b0b9-d346-4697-a1c8-1b1530153788','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','0136fc6a-3a80-4f4c-8057-10bbf34ea572','94786475-832c-4f97-aab7-bf6fbbe2236b','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"오징어는 껍질을 벗긴 후 안쪽에 대각선으로 칼집을 넣어 데친다.","imageUrl":null},{"step":2,"text":"당근, 시금치, 불린 표고버섯은 0.5cm 두께로 썬다.","imageUrl":null},{"step":3,"text":"시금치는 끓는 물에 데쳐 찬물에 헹군 뒤 물기를 제거한다.","imageUrl":null},{"step":4,"text":"달걀은 잘 풀어 도톰하게 달걀말이를 만 후 당근처럼 썬다.","imageUrl":null},{"step":5,"text":"오징어의 물기를 제거하고 밀가루를 살짝 뿌린후 2, 3의 재료를 모두 넣어 김밥 말듯이 돌돌말아 꼬치로 두군데를 고정시킨다.","imageUrl":null},{"step":6,"text":"토마토케첩소스의 재료를 섞어 팬에서 졸이다가 4의 오징어를 넣고 소스를 끼얹어가며 졸여 1.5cm의 두께로 썬다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053525_1416213325208.jpg', 152.2, 8.8, 20, 4.3, 190),
  ('890', '오징어보쌈과 저나트륨 된장소스', '반찬', '갑오징어 50g, 당근 9g, 오이 9g, 상추 7g ,된장 1.6g, 양파 1.3g, 물 6.6g, 식초 0.4g, 설탕 0.2g, 청고추 0.2g, 홍고추 0.2g', '["갑오징어","당근","오이","상추","된장","양파","물","식초","설탕","청고추","홍고추"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','1389717e-81e4-4350-96d4-d627d851aa10','392236b1-82e9-4e38-bd12-6a53b80bf463','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','94786475-832c-4f97-aab7-bf6fbbe2236b','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"오징어는 반으로 갈라 껍질을 제거하고 몸통 안쪽에 대각선으로 칼집을 넣는다.","imageUrl":null},{"step":2,"text":"칼집 낸 오징어를 끓는 물에 데친다.","imageUrl":null},{"step":3,"text":"데친 오징어는 한 입 크기로 썬다.","imageUrl":null},{"step":4,"text":"오이는 돌려 깎아 3cm 길이로 채썰고 당근도 4cm 길이로 얇게 채썬다.","imageUrl":null},{"step":5,"text":"드레싱에 들어갈 양파, 청·홍고추는 잘게 다져 분량의 재료와 섞어 저나트륨 된장소스를 만든다.","imageUrl":null},{"step":6,"text":"상추에 준비된 오징어와 오이, 당근, 저나트륨 된장소스를 기호에 맞게 곁들여 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053526_1416213326629.jpg', 46.2, 1.8, 8.1, 0.7, 192),
  ('891', '칠리새우', '반찬', '백새우 40g, 케첩 4g, 대파 6g, 녹말가루 3g, 밀가루 6g, 달걀 10g, 완두콩 4g, 식용유 5g, 참기름 0.5g ,두반장 1g, 고추기름 3g, 설탕 6g, 마늘 2g, 생강 0.2g, 청주 2g, 식초 3g', '["백새우","케첩","대파","녹말가루","밀가루","달걀","완두콩","식용유","참기름","두반장","고추기름","설탕","마늘","생강","청주","식초"]'::jsonb, ARRAY['0136fc6a-3a80-4f4c-8057-10bbf34ea572','4b410642-7bf9-45ad-9055-e7d9a34edaa1','6613d1d9-80a2-4ce4-9d3d-647203197e53','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','5fd34bed-4339-4fcc-9221-f082ce6ac652','a7a59e81-de3d-4893-b56a-b2218732a25b','0c0ade94-cfd8-4104-b44c-40e942cac482','fb9d40e3-96b9-4a0f-bd38-734bb6ca6b12','3a2bfe83-465c-4aaf-bde6-1c34303b15b7','06e6f3e7-0293-469d-a338-11a610f3e71b','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"새우는 손질하여 물기를 제거한다.","imageUrl":null},{"step":2,"text":"달걀, 녹말가루, 밀가루로 튀김옷을 만들어 새우에 묻힌다.","imageUrl":null},{"step":3,"text":"튀김옷을 입힌 새우를 170℃ 식용유에 두 번 튀겨낸다.","imageUrl":null},{"step":4,"text":"대파, 마늘, 생강은 다진다.","imageUrl":null},{"step":5,"text":"팬에 고추기름을 두르고 2를 넣고 볶다가 청주, 두반장, 케첩을 첨가하여 볶은 후 물을 넣고 설탕, 식초로 간을 맞춘다.","imageUrl":null},{"step":6,"text":"살짝 졸인 뒤 튀긴 새우와 완두콩을 넣고 물녹말로 농도를 맞추고 마지막으로 참기름을 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053527_1416213327815.jpg', 192.6, 16.3, 10.7, 8.9, 159),
  ('2984', '연근샐러드, 흑임자소스', '반찬', '흑임자 30g, 연근 80g, 레몬 20g, 마요네즈 15g, 플레인요거트 15g, 식초 5g', '["흑임자","연근","레몬","마요네즈","플레인요거트","식초"]'::jsonb, ARRAY['9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','b20f623d-e722-42af-9bd1-7c11b5e15aa6','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','549c7365-28e9-491f-9040-412558f93a5c','bb41a88a-ea2b-4830-876d-91fe7f640296','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"연근은 세척 후 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"연근을 슬라이스 한다.","imageUrl":null},{"step":3,"text":"물에 식초를 넣고 끓으면 연근을 데친다.","imageUrl":null},{"step":4,"text":"레몬즙을 짠다.","imageUrl":null},{"step":5,"text":"흑임자, 마요네즈, 플레인요거트를 믹서 하여 흑임자 소스를 만든다.","imageUrl":null},{"step":6,"text":"연근에 흑임자소스를 곁들여 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190418/20190418111813_1555553893882.jpg', 28.76, 3.82, 0.69, 1.19, 4.9),
  ('3074', '단호박함박스테이크', '반찬', '돼지고기 30g, 소고기 20g, 단호박 20g, 양파 10g, 마늘 1g, 당근 7g, 계란20g, 빵가루 5g, 우유 50ml, 콩기름 2g, 소금 0.4g, 후추 0.1g, 올리고당 3g', '["돼지고기","소고기","단호박","양파","마늘","당근","계란","빵가루","우유","콩기름","소금","후추","올리고당"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','1c49d1f4-5781-474d-818d-bd7002a4dc0b','98d652af-a6d6-440c-9653-e22fc5d47d88','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','e38c12a7-43cb-421a-a36e-7ef0d32517fa','c7d438a6-34d6-423f-905d-446b839e2f39','45080597-55fa-42dc-aa65-12d7694e4b7e','e937397f-54e2-49df-997a-f393c58360be','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"단호박은 쪄서 속을 파내고, 우유와 올리고당을 넣고 끓여 소스를 만든다.","imageUrl":null},{"step":2,"text":"소고기, 돼지고기, 양파, 마늘, 당근은 모두 잘게 다진다.","imageUrl":null},{"step":3,"text":"②에 빵가루, 달걀, 소금, 후추를 넣고 치댄다.","imageUrl":null},{"step":4,"text":"치댄 반죽을 둥글고 납작하게 만들어 준다.","imageUrl":null},{"step":5,"text":"팬에 기름을 두르고 노릇하게 굽는다.","imageUrl":null},{"step":6,"text":"함박스테이크에 단호박 크림소스를 부어 제공한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103624_1584063384791.JPG', 323.8, 36.5, 17.5, 12, 311.5),
  ('3170', '배깍두기', '반찬', '배 80g, 부추 5g, 고춧가루 5g, 매실청 3g, 설탕 2g, 참깨 1g', '["배","부추","고춧가루","매실청","설탕","참깨"]'::jsonb, ARRAY['eccf67f1-41f0-4a25-b238-6b9e7332c9e1','058648c3-fd8e-476d-952f-b15dc67f1877','84104c49-0af4-4323-a56b-b67002a422d9','02fd7135-0ec3-49ec-82e3-390536ab2cf5','06e6f3e7-0293-469d-a338-11a610f3e71b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"배는 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"껍질 벗긴 배를 깍뚝썰기 한다.","imageUrl":null},{"step":3,"text":"부추는 먹기 좋은 길이로 썬다.","imageUrl":null},{"step":4,"text":"배와 부추에 고춧가루를 버무려 색이 베이도록 한다.","imageUrl":null},{"step":5,"text":"매실청과 설탕을 넣어 새콤달콤하게 버무린다.","imageUrl":null},{"step":6,"text":"참깨를 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128052841_1611822521024.JPG', 65.06, 13.74, 0.96, 0.42, 6.56),
  ('3217', '닭고기 찰깨빵', '일품', '방울토마토(60g), 양파(70g), 파프리카(120g), 할라피뇨(10g), 훈제 닭가슴살(40g), 찰깨빵(45g), 모차렐라치즈(30g), 파슬리가루(약간), 설탕(1g), 소금(0.5g), 레몬즙(15㎖), 후춧가루(0.5g)', '["방울토마토","양파","파프리카","할라피뇨","훈제 닭가슴살","찰깨빵","모차렐라치즈","파슬리가루","설탕","소금","레몬즙","후춧가루"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','4362c386-a37c-44cd-9254-fafd74712a09','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"방울토마토, 양파, 파프리카, 할라피뇨, 훈제 닭가슴살은 작게 깍둑썬다.","imageUrl":null},{"step":2,"text":"손질한 재료에 양념을 고루 섞는다.","imageUrl":null},{"step":3,"text":"찰깨빵의 윗부분 1cm를 도려낸다.","imageUrl":null},{"step":4,"text":"빵 안에 버무린 재료를 채운 뒤 모차렐라치즈를 올린다.","imageUrl":null},{"step":5,"text":"180℃로 예열한 오븐에 속을 채운 빵을 넣고 5분간 구워 꺼낸다.","imageUrl":null},{"step":6,"text":"그릇에 구운 빵을 올린 뒤 파슬리가루를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308050056_1615190456312.jpg', 500.6, 80.1, 16.7, 12.6, 852.1),
  ('3272', '레몬연어 파피요트', '일품', ' 브로콜리(¼개), 애호박(½개), 레몬(½개), 양파(½개), 노랑 파프리카(¼개), 방울토마토(5개), 마늘(8쪽), 연어 필레(270g), 로즈메리(3줄기), 올리브유(1Ts), 레몬즙(3.5Ts), 올리브유(7Ts), 소금(약간), 후춧가루(약간), 다진 양파(½컵)', '["브로콜리","애호박","레몬","양파","노랑 파프리카","방울토마토","마늘","연어 필레","로즈메리","올리브유","레몬즙","소금","후춧가루","다진 양파"]'::jsonb, ARRAY['9bf64924-ce53-42bb-849e-7294416e95d6','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"브로콜리는 송이만 떼어내고, 애호박과 레몬은 4mm 두께로 둥글게 썰고, 양파와 노랑 파프리카는 한입 크기로 썰고, 방울토마토는 4등분하고, 마늘은 꼭지를 제거한다.","imageUrl":null},{"step":2,"text":"볼에 레몬즙을 넣고 올리브유를 조금씩 부어가며 거품기로 골고루 섞는다.","imageUrl":null},{"step":3,"text":"올리브유를 섞은 레몬즙에 소금, 후춧가루, 다진 양파를 넣고 고루 섞어 레몬소스를 만든 뒤 연어에 버무려 15분간 재운다.","imageUrl":null},{"step":4,"text":"종이포일에 애호박, 연어, 레몬, 로즈메리 순으로 깔고, 손질한 채소를 올린다.","imageUrl":null},{"step":5,"text":"올리브유(1Ts)를 뿌리고 종이포일 양끝을 돌돌 만 뒤 작은 구멍을 2~3개 낸다.","imageUrl":null},{"step":6,"text":"찜기에 김이 오르면 연어를 넣고, 뚜껑을 덮어 센 불로 25분간 익혀 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJe-xN', 431.7, 8.3, 33.3, 29.5, 121.1),
  ('3365', '떡꼬치구이', '기타', ' 떡볶이떡(40g), 파(3.5g), 양파(7g), 식용유(3g)
, 케첩(8g), 스리라차(3g), 올리고당(2g), 다진마늘(2g), 간장(1g), 참기름(1g), 통깨(0.5g)', '["떡볶이떡","파","양파","식용유","케첩","스리라차","올리고당","다진마늘","간장","참기름","통깨"]'::jsonb, ARRAY['af336608-1eeb-4b10-9a3a-1df0ad140ccb','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','a7a59e81-de3d-4893-b56a-b2218732a25b','0136fc6a-3a80-4f4c-8057-10bbf34ea572','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"떡볶이 떡은 끓는 물에 데쳐 건진다.","imageUrl":null},{"step":2,"text":"꼬치에 데친 떡을 꽂는다.","imageUrl":null},{"step":3,"text":"파와 양파는 다진다.","imageUrl":null},{"step":4,"text":"양념장 재료에 다진 양파와 파를 섞어 양념장을 만든다.","imageUrl":null},{"step":5,"text":"팬에 식용유를 두른 뒤 양념장을 볶는다.","imageUrl":null},{"step":6,"text":"양념장을 떡꼬치에 묻힌 뒤 통깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054654_1678265214010.jpg', 160.9, 34.9, 3.1, 1, 214),
  ('3577', '부추 배무침', '반찬', ',
부추(30g), 양파(10g), 배(15g),
다진 마늘(8g), 고춧가루(8g), 멸치액젓(6g), 저염간장(3g), 레몬즙(10g), 통깨(4g)', '["부추","양파","배","다진 마늘","고춧가루","멸치액젓","저염간장","레몬즙","통깨"]'::jsonb, ARRAY['058648c3-fd8e-476d-952f-b15dc67f1877','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','fc6e31ce-388e-45cd-956b-b238b9134eb1','84104c49-0af4-4323-a56b-b67002a422d9','5fd46a51-6998-4ac9-a1fb-cab1eedf7cd9','f175019d-5a93-4cd4-aabc-e7e79445f15a','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"부추는 다듬어 5~6cm 크기로 썰고, 양파는 뿌리와 껍질을 제거해 얇게 채 썬다.","imageUrl":null},{"step":2,"text":"배는 껍질을 제거해 여덟 등분하고 씨를 제거하여 편 썰기를 한다.","imageUrl":null},{"step":3,"text":"다진 마늘, 고춧가루, 멸치액젓, 저염간장, 레몬즙, 통깨(2g)를 섞어 양념장을 만든다","imageUrl":null},{"step":4,"text":"부추, 양파, 배의 물기를 제거한다.","imageUrl":null},{"step":5,"text":"볼에 담고 양념장을 넣어 버무린다.","imageUrl":null},{"step":6,"text":"접시에 담고 통깨(2g)를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120014705_1732078025168.jpg', 32.1, 5.6, 1.5, 0.4, 305.1),
  ('895', '아보카도 두부 샐러드', '반찬', '연두부 50g, 아보카도작은것 35g, 게살냉동 50g, 양파 25g, 민트 0.25g,고추냉이 갠것 6g, 간장 1g, 소금 0.2g, 레몬즙 10g, 올리브유엑스트라버전 30g', '["연두부","아보카도작은것","게살냉동","양파","민트","고추냉이 갠것","간장","소금","레몬즙","올리브유엑스트라버전"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','eb4621c9-6ade-40ba-966c-32edd1754669','f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"아보카도는 검은 빛이 돌면서 윤기가 흐르는 것을 골라 세로로 칼날을 넣어 칼날이 씨에 닿으면 한바퀴 돌린다.","imageUrl":null},{"step":2,"text":"양손으로 아보카도 양 끝을 잡고 비틀면서 반으로 나누고 칼날 안쪽 모서리로 씨를 찔러서 빼낸다.","imageUrl":null},{"step":3,"text":"아보카도 과육을 5cm 두께로 썬다.","imageUrl":null},{"step":4,"text":"냉동 게살은 하룻밤 전에 냉장고로 옮겨 놓거나, 실온에서 해동시킨 후 잘게 찢는다. 양파는 얇게 채썰고 민트도 잘게 썬다.","imageUrl":null},{"step":5,"text":"고추냉이 드레싱 재료를 섞는다.","imageUrl":null},{"step":6,"text":"두부는 원형틀로 찍어두고 양파와 게살, 아보카도를 곁들이고 민트를 올린 뒤 드레싱을 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053530_1416213330214.jpg', 246.2, 8.5, 11.6, 38.7, 362),
  ('897', '과일 젤리', '후식', '젤라틴 5g, 자몽주수 100g, 귤통조림 20g, 파인애플통조림 5g, 체리 15g, 설탕 15g', '["젤라틴","자몽주수","귤통조림","파인애플통조림","체리","설탕"]'::jsonb, ARRAY['e1ee1919-9a32-462f-ae14-55c7a47ce0a0','f3ad66d4-1bf6-4c19-90de-6c18147837fd','bbf5a336-7a76-423e-a6a3-7f79147e5218','c97290bd-7146-45bc-8e7f-28390e7a95b0','115c21d5-f619-42df-a91e-58fccd4b2459','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"젤라틴을 물에 불려 놓는다.","imageUrl":null},{"step":2,"text":"자몽주스에 설탕을 넣고 가열한다.","imageUrl":null},{"step":3,"text":"불린 젤라틴을 넣어 약한 불에서 젤라틴을 녹인다.","imageUrl":null},{"step":4,"text":"틀에 귤과 파인애플, 체리를 넣는다.","imageUrl":null},{"step":5,"text":"틀에 젤라틴을 녹인 자몽주스를 넣는다.","imageUrl":null},{"step":6,"text":"냉장고에서 식혀 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053532_1416213332265.jpg', 143.4, 32.8, 1.1, 0.1, 25.3),
  ('900', '복숭아샤벳', '후식', '복숭아 150g, 식혜 100g, 설탕시럽 20g, 민트 0.1g', '["복숭아","식혜","설탕시럽","민트"]'::jsonb, ARRAY['eb4621c9-6ade-40ba-966c-32edd1754669']::uuid[], '[{"step":1,"text":"복숭아는 반으로 갈라 씨를 발라내고 두께 0.5cm가량만 남기고 속을 파낸다.","imageUrl":null},{"step":2,"text":"복숭아와 식혜, 설탕시럽을 넣고 믹서기에 굵게 간다.","imageUrl":null},{"step":3,"text":"2를 냉동실에서 4~5시간 정도 얼리면서 1시간마다 숟가락으로 긁어 샤벳을 만든다.","imageUrl":null},{"step":4,"text":"속을 파낸 복숭아도 냉동실에서 얼려 샤벳 그릇으로 사용한다.","imageUrl":null},{"step":5,"text":"3의 복숭아 식혜 샤벳을 떠서 얼린 복숭아 그릇에 담는다.","imageUrl":null},{"step":6,"text":"민트로 장식하여 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053534_1416213334638.jpg', 92.8, 24.3, 1.6, 0.3, 7),
  ('903', '과일 주스 조림', '후식', '천도복숭아 30g, 자두 20g, 체리 40g, 산딸기 20g, 블루베리 10g, 사과 30g, 포도 10g, 포도주스 50g, 설탕 20g', '["천도복숭아","자두","체리","산딸기","블루베리","사과","포도","포도주스","설탕"]'::jsonb, ARRAY['115c21d5-f619-42df-a91e-58fccd4b2459','203b7165-14df-4cb6-b165-e4dadf9a3079','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','483ecbd5-47a4-4fb5-bfee-852bded6c1dd','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"천도복숭아는 반으로 잘라 씨를 제거하고 각각 2등분하고 자두는 반으로 갈라 씨를 제거한다.","imageUrl":null},{"step":2,"text":"사과는 8등분하여 씨를 제거한다.","imageUrl":null},{"step":3,"text":"포도는 알알이 떼어내고 체리는 꼭지를 떼어내고 블루베리와 산딸기는 분량대로 준비한다.","imageUrl":null},{"step":4,"text":"냄비에 포도주스와 설탕, 준비한 과일을 넣고 약한불에서 끓인다.","imageUrl":null},{"step":5,"text":"천도복숭아가 부드러워지고 포도주스에 농도가 생기면 불을 끈다.","imageUrl":null},{"step":6,"text":"접시에 졸인 과일과 주스를 함께 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053536_1416213336433.jpg', 182, 39.4, 1.5, 0.5, 7),
  ('907', '감자를 곁들인 야채스튜', '반찬', '양파 15, 청피망 15g, 가지 10g, 애호박 18g, 양송이버섯 8g, 마늘다진것 2g, 토마토콩카세 10g, 감자 50g, 올리브오일 1g, 닭육수 15g, 토마토페이스트 8g, 생크림 5g, 우유 8g, 소금적당량, 후추 적당량', '["양파","청피망","가지","애호박","양송이버섯","마늘다진것","토마토콩카세","감자","올리브오일","닭육수","토마토페이스트","생크림","우유","소금","후추"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','df459e6f-3515-45d5-8c9a-9d37b6249379','3e12cf79-2cde-4309-9f7c-4eccce3fde28','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','fc6e31ce-388e-45cd-956b-b238b9134eb1','20894da1-739d-4d52-b5fe-4943bd3492d5','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','a4c37075-c03b-47bb-8aed-5e907620f5d2','76e95535-f965-4685-a7a6-55ae26aa202c','af187077-b7f6-4b0e-9e99-f844f6359ac2','e937397f-54e2-49df-997a-f393c58360be','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"마늘은 다지고, 양파, 청피망, 가지, 애호박, 양송이는 1cm 주사위모양으로 썬다.","imageUrl":null},{"step":2,"text":"토마토는 끓는 물에 데쳐 껍질을 벗긴 뒤 씨를 제거하고 야채들과 같은 크기로 자른다.","imageUrl":null},{"step":3,"text":"감자는 껍질을 벗겨 큼직하게 썰어 삶은 뒤 완전히 익으면 오븐서 수분을 제거하고 으깨 우유, 생크림, 소금, 후추를 넣는다.","imageUrl":null},{"step":4,"text":"팬에 기름을 두르고 양파를 투명해질 때까지 볶은 뒤 마늘, 토마토 페이스트를 넣고 볶다가 청피망, 가지, 호박, 양송이, 토마토를 넣어 볶는다.","imageUrl":null},{"step":5,"text":"야채가 부드러워지면 닭육수를 넣어 한번 더 끓이고 소금, 후추로 간 한다.","imageUrl":null},{"step":6,"text":"접시에 완성된 으깬 감자를 깔고 그 위에 야채 스튜를 올려낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053542_1416213342038.jpg', 87, 14.8, 3.4, 2.4, 30),
  ('909', '김치 고구마밥', '밥', '고구마 15g, 쌀 40g, 물 40g, 김치 8g, 사과작은것 95g, 참기름 1g, 마늘다진것 1g간장 1g, 국간장 1g, 고춧가루 1g, 다진마늘 1g, 통깨 1g, 실파송송썬것 1.5g, 참기름 0.5g', '["고구마","쌀","물","김치","사과작은것","참기름","마늘다진것","국간장","고춧가루","다진마늘","통깨","실파송송썬것"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','a5bc0b46-0192-496a-b429-d2cb90b2bca9','94786475-832c-4f97-aab7-bf6fbbe2236b','133f214e-50f4-431d-af36-d97f6c9d4f9b','0c0ade94-cfd8-4104-b44c-40e942cac482','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"고구마는 1cm의 주사위모양으로 썰어 놓는다.","imageUrl":null},{"step":2,"text":"물에 씻은 김치를 송송 썰어서 참기름을 두른 팬에 볶다가 마늘과 소금을 넣어 볶은 뒤 깨소긂으로 마무리한다.","imageUrl":null},{"step":3,"text":"냄비에 불린 쌀과 고구마, 볶은 김치를 넣고 고슬고슬하게 밥을 짓는다.","imageUrl":null},{"step":4,"text":"사과의 꼭지 부분을 자른 뒤 속을 파내고 밥을 채운다.","imageUrl":null},{"step":5,"text":"160℃로 예열된 오븐에 밥을 채운 사과를 넣고 사과가 익을 정도로 구워준다.","imageUrl":null},{"step":6,"text":"양념장 재료를 섞어 양념장을 만들고 밥과 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053546_1416213346049.jpg', 247.9, 54, 3.9, 2.4, 233),
  ('2986', '돈불고기 파인애플볶음', '반찬', '돼지고기(불고기용) 120g, 파인애플 35g, 양배추 15g, 양파 10g, 당근 7g, 대파 5g, 설탕 5g, 부추 1g, 마늘 2g, 참기름 3g, 간장 5g', '["돼지고기","파인애플","양배추","양파","당근","대파","설탕","부추","마늘","참기름","간장"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','c97290bd-7146-45bc-8e7f-28390e7a95b0','fd4254d4-2691-47e1-9367-c2b820ef8d00','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','4b410642-7bf9-45ad-9055-e7d9a34edaa1','06e6f3e7-0293-469d-a338-11a610f3e71b','058648c3-fd8e-476d-952f-b15dc67f1877','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"돼지고기를 흐르는 물에 담궈 핏물을 제거한다.","imageUrl":null},{"step":2,"text":"파인애플 일부는 먹기 좋은 크기로 썰고 나머지는 믹서에 간다.","imageUrl":null},{"step":3,"text":"간 파인애플과 양념을 섞어 양념장을 만든다.","imageUrl":null},{"step":4,"text":"핏물을 제거한 돼지고기에 양념장을 섞어 재운다.","imageUrl":null},{"step":5,"text":"프라이팬에 기름을 두르고 양념한 돼지고기와 한 입 크기로 썬 채소를 볶는다.","imageUrl":null},{"step":6,"text":"썰어둔 파인애플을 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033235_1554791555920.jpg', 113.18, 5.65, 9.03, 6.05, 187.59),
  ('2994', '비름나물 된장무침', '반찬', ' 비름나물(70g), 양파(10g), 마늘(3g), 생강(1g)
, 물(200g), 다시마(5g)
,  된장(2g), 고추장(1g), 마요네즈(2g), 고춧가루(1g)
, 참깨(1g), 참기름(4g)', '["비름나물","양파","마늘","생강","물","다시마","된장","고추장","마요네즈","고춧가루","참깨","참기름"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','94786475-832c-4f97-aab7-bf6fbbe2236b','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','392236b1-82e9-4e38-bd12-6a53b80bf463','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','549c7365-28e9-491f-9040-412558f93a5c','84104c49-0af4-4323-a56b-b67002a422d9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"비름나물을 적당한 길이로 잘라 다시마육수에 데친 뒤 찬물에 헹궈 물기를 뺀다.","imageUrl":null},{"step":2,"text":"양파는 2mm 두께로 채 썰고 생강과 마늘은 곱게 다진다.","imageUrl":null},{"step":3,"text":"된장을 곱게 다진 뒤 구멍이 큰 체에 걸러 식감을 살리고 고추장, 마요네즈, 고춧가루와 섞는다.","imageUrl":null},{"step":4,"text":"양념장에 다진 생강, 마늘을 섞는다.","imageUrl":null},{"step":5,"text":"비름나물에 양파, 양념장을 넣고 골고루 무친다.","imageUrl":null},{"step":6,"text":"참기름을 둘러 가볍게 섞은 뒤 깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032656_1678343216209.jpg', 60.3, 4.5, 3.4, 3.2, 130.4),
  ('3001', '소고기 들깨 알토란탕', '국&찌개', '소고기(양지) 3g, 무 20g, 알토란 30g, 대파 15g, 느타리버섯 10g, 고사리 10g, 콩나물 10g, 고춧가루 10g, 깻잎순 3g, 들깨가루 15g, 소금 3g, 간장 3g', '["소고기","무","알토란","대파","느타리버섯","고사리","콩나물","고춧가루","깻잎순","들깨가루","소금","간장"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','f80c9a7d-1510-44e2-a82b-28b9f684e191','4b410642-7bf9-45ad-9055-e7d9a34edaa1','7c91e298-5ace-4242-8619-cdcc80587cd7','9fb1e8e8-c9d9-41f1-a478-fccf9a335175','2db049b2-f39c-47ba-857f-fa02b3b0c610','84104c49-0af4-4323-a56b-b67002a422d9','184687ba-0cba-4fec-bb21-33fe300c2073','2cf0c12b-f248-4012-8f53-303c730a7b3d','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"양지를 찬물에 담가 핏물을 제거한다.","imageUrl":null},{"step":2,"text":"양지와 무를 냄비에 끓인 뒤 양지를 건진다.","imageUrl":null},{"step":3,"text":"알토란은 쌀뜨물에 1시간 정도 담근 뒤 소금물에 삶아 아린 맛을 제거한다.","imageUrl":null},{"step":4,"text":"각종 채소를 손질하고 건져낸 양지를 찢는다.","imageUrl":null},{"step":5,"text":"육수에 손질한 야채와 양지를 넣고 끓인다.","imageUrl":null},{"step":6,"text":"고춧가루와 들깨가루를 넣고 끓인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052034_1554798034902.jpg', 146.42, 17.4, 7.57, 5.17, 675.68),
  ('3078', '과일삼겹살조림&파채무침', '반찬', '돼지고기(삼겹살) 70.8g, 새싹채소 2.8g, 깐대파 3.5g, 파인애플 1.5g, 배 1.5g, 사과 1.5g, 깐양파 2g, 진간장 1.2g, 깐마늘 1.2g, 깐생강 0.3g, 고춧가루 0.17g, 레몬 1g, 식초 0.4g, 설탕 0.1g, 국간장 0.1g,', '["돼지고기","새싹채소","깐대파","파인애플","배","사과","깐양파","진간장","깐마늘","깐생강","고춧가루","레몬","식초","설탕","국간장"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','c97290bd-7146-45bc-8e7f-28390e7a95b0','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','84104c49-0af4-4323-a56b-b67002a422d9','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"삼겹살은 덩어리로 준비하여 삶아낸다.","imageUrl":null},{"step":2,"text":"배, 사과, 파인애플, 양파, 깐마늘, 깐생강은 갈아서 체에 거르고 간장과 함께 끓인다.","imageUrl":null},{"step":3,"text":"②에 삶아낸 삼겹살을 넣어 윤기 나게 조린다.","imageUrl":null},{"step":4,"text":"대파는 가늘게 채 썰고, 새싹채소는 깨끗하게 씻는다.","imageUrl":null},{"step":5,"text":"레몬즙, 식초, 설탕, 국간장, 고춧가루를 넣어 만든 소스를 야채에 버무린다.","imageUrl":null},{"step":6,"text":"한입 크기로 썬 삼겹살과 ⑤를 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313111944_1584065984038.JPG', 205.5, 15.9, 16.3, 8.5, 186.9),
  ('3171', '곤약백김치말이', '반찬', '판곤약 60g, 부추 2g, 파프리카(빨강, 노랑, 청색) 각 7g, 대왕오징어채 30g, 백김치 30g, 양조식초 3g', '["판곤약","부추","파프리카 각","대왕오징어채","백김치","양조식초"]'::jsonb, ARRAY['058648c3-fd8e-476d-952f-b15dc67f1877','133f214e-50f4-431d-af36-d97f6c9d4f9b','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"곤약은 얇게 편으로 썰어 데친 뒤, 백김치 국물에 절인다.","imageUrl":null},{"step":2,"text":"끓는 물에 식초를 넣고 오징어를 질기지 않게 살짝 삶는다.","imageUrl":null},{"step":3,"text":"파프리카는 채썰어 준다.","imageUrl":null},{"step":4,"text":"백김치는 물기를 제거한다.","imageUrl":null},{"step":5,"text":"곤약을 깔고 오징어, 파프리카를 얹어 백김치로 말아준다.","imageUrl":null},{"step":6,"text":"데쳐낸 부추로 풀어지지 않게 매듭을 짓는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053429_1611822869995.JPG', 46.99, 3.2, 6.28, 1.01, 171.08),
  ('3274', '꽈리고추 닭강정', '반찬', ' 꽈리고추(2줌=100g), 양파(½개), 건고추(3개), 마늘(10쪽), 대파(1대), 닭다릿살(400g), 백후춧가루(0.3Ts), 식용유(8Ts), 참깨(0.3Ts), 전분(2Ts), 달걀흰자(1개), 굴소스(1.5Ts), 올리고당(1Ts), 다진 마늘(0.5Ts), 생강가루(0.5Ts), 후춧가루(0.25Ts)', '["꽈리고추","양파","건고추","마늘","대파","닭다릿살","백후춧가루","식용유","참깨","전분","달걀흰자","굴소스","올리고당","다진 마늘","생강가루","후춧가루"]'::jsonb, ARRAY['30b5d53c-d247-4f04-9b50-c0f728e65cf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','a7a59e81-de3d-4893-b56a-b2218732a25b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','6613d1d9-80a2-4ce4-9d3d-647203197e53','c7d438a6-34d6-423f-905d-446b839e2f39','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"꽈리고추, 양파, 건고추는 3cm 길이로 썰고, 마늘은 2등분하고, 대파는 송송 썬다.","imageUrl":null},{"step":2,"text":"닭다릿살은 4×4cm 크기로 썰고, 백후춧가루에 버무린 뒤 튀김옷 재료를 입힌다.","imageUrl":null},{"step":3,"text":"약한 불로 달군 팬에 식용유를 두른 뒤 손질한 건고추, 마늘, 대파를 넣고 볶아 기름을 낸다.","imageUrl":null},{"step":4,"text":"튀김옷을 입힌 닭다릿살을 넣어 노릇해 질 때까지 튀기듯 볶고, 양파를 넣어 투명해질 때까지 볶는다.","imageUrl":null},{"step":5,"text":"센 불로 올린 뒤 양념장을 넣어 재빠르게 볶고, 꽈리고추를 넣어 10초간 볶아 꺼낸다.","imageUrl":null},{"step":6,"text":"참깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr90FP', 566.2, 32.8, 35.8, 32.4, 744),
  ('3291', '참치두부 주먹밥', '밥', ' 두부(1모=300g), 파프리카(빨강, 노랑 각 ¼개), 깻잎(4장), 잡곡밥(70g), 통조림 참치(50g), 스테비아(0.5Ts), 간장(0.5Ts), 참기름(1Ts)', '["두부","파프리카","깻잎","잡곡밥","통조림 참치","스테비아","간장","참기름"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','5e79d288-1400-4817-bd20-e5e6041821b1','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','49b48723-2e40-46b0-9588-00f41a6a02c2','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"큰 볼에 두부를 담은 뒤 물이 담긴 무거운 그릇을 3분간 올려 수분을 제거한다.","imageUrl":null},{"step":2,"text":"두부 속을 사각형 모양으로 파내고, 파낸 두부 속은 물기를 꼭 짜 으깬다.","imageUrl":null},{"step":3,"text":"파프리카와 깻잎은 잘게 썬다.","imageUrl":null},{"step":4,"text":"통조림 참치는 체에 밭친 뒤, 뜨거운 물을 부어 기름과 염분을 제거한다.","imageUrl":null},{"step":5,"text":"볼에 으깬 두부, 손질한 채소, 잡곡밥, 참치를 넣은 뒤 양념해 고루 섞는다.","imageUrl":null},{"step":6,"text":"주먹밥을 동그랗게 만들고, 속을 판 두부 속에 넣어 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Ba2', 299.7, 20.9, 24.7, 13.1, 248.3),
  ('3578', '열무톳김치', '반찬', ',
 열무(30g), 톳(10g), 마늘(3g), 생강(1g),
 어간장(5g), 고춧가루(2g), 통깨(2g)', '["열무","톳","마늘","생강","어간장","고춧가루","통깨"]'::jsonb, ARRAY['f3f07b4b-1a27-4a6d-be6d-09e58352e063','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"톳은 깨끗한 물에 여러 번 씻은 후 끓는 물에 살짝 데치고 물기를 제거한다","imageUrl":null},{"step":2,"text":"열무는 3cm 크기로 썬다.","imageUrl":null},{"step":3,"text":"손질한 열무는 끓은 물에 살짝 데치고 물기를 제거한다.","imageUrl":null},{"step":4,"text":"마늘, 생강은 잘게 다진다.","imageUrl":null},{"step":5,"text":"볼에 손질한 열무, 톳, 마늘, 생강을 넣고 고춧가루, 어간장으로 간하여 버무린다.","imageUrl":null},{"step":6,"text":"접시에 담고 통깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120014837_1732078117022.jpg', 13.7, 2.2, 1, 0.1, 379.3),
  ('3679', '콩가루 쑥 다쿠아즈', '후식', ' 달걀흰자 180g, 설탕① 50g, 아몬드가루 160g, 박력 밀가루 15g,슈가파우더 40g, 콩가루 40g, 생크림 150g, 설탕② 20g, 쑥가루 24g', '["달걀흰자","설탕①","아몬드가루","박력 밀가루","슈가파우더","콩가루","생크림","설탕②","쑥가루"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','52ba316f-8e7f-415f-8079-9a9d674c9adf','c1a987ee-fe94-4eb5-b3e7-d41c23cd3445','af187077-b7f6-4b0e-9e99-f844f6359ac2']::uuid[], '[{"step":1,"text":"달걀흰자에 설탕①을 조금씩 넣으며,\r\n단단한 머랭을 만든다. 아몬드가루,\r\n박력 밀가루를 체 쳐서 머랭에 넣고\r\n자르듯이 섞어 반죽을 만든다.","imageUrl":null},{"step":2,"text":"오븐 팬에 테프론 시트를 깔고,\r\n다쿠아즈 틀을 올린 후 반죽을\r\n팬닝한다. 다쿠아즈 틀을 제거하고,\r\n슈가파우더를 두 번에 나누어서 뿌린다.","imageUrl":null},{"step":3,"text":"180°C로 예열한 오븐에서 15분 동안\r\n구운 후 꺼내 식혀 다쿠아즈를 만든다.","imageUrl":null},{"step":4,"text":"생크림에 설탕②를 넣고 휘핑하여\r\n생크림이 약간 단단해지면 쑥가루를\r\n섞어 쑥크림을 만든다.","imageUrl":null},{"step":5,"text":"다쿠아즈에 쑥크림을 바르고, 다른\r\n다쿠아즈로 덮어 샌드한다.","imageUrl":null},{"step":6,"text":"콩가루를 골고루 뿌리고 냉장실에서\r\n10분 동안 식혀 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016014506_1760589906399.jpg', 152.8, 16.6, 5.9, 7, 43.2),
  ('912', '대구 크림스튜', '반찬', '양파다진것 10g, 청피망다진것 10g, 마늘다진것 2g, 청고추다진것 2g, 대구살 35g, 토마토콩카세 30g, 땅콩버터 1g, 생크림 13g, 파프리카가루 1g, 새우 20g, 올리브오일 1g, 소금적당량, 후추적당량', '["양파다진것","청피망다진것","마늘다진것","청고추다진것","대구살","토마토콩카세","땅콩버터","생크림","파프리카가루","새우","올리브오일","소금","후추"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','df459e6f-3515-45d5-8c9a-9d37b6249379','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','af187077-b7f6-4b0e-9e99-f844f6359ac2','5e79d288-1400-4817-bd20-e5e6041821b1','6f10b4ad-53a2-4a07-ba89-19a6b074373d','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"양파, 청피망, 마늘, 고추는 다지고, 대구살은 굵직하게 썬다.","imageUrl":null},{"step":2,"text":"토마토는 데친 뒤 껍질을 벗기고 씨를 제거해 과육만 썬다.","imageUrl":null},{"step":3,"text":"기름을 두른 팬에 양파, 고추를 넣고 볶다가 마늘을 넣고 볶는다.","imageUrl":null},{"step":4,"text":"생크림과 땅콩버터를 넣은 후 토마토, 파프리카, 새우 순서대로 넣어 끓인다.","imageUrl":null},{"step":5,"text":"썰어둔 대구살을 넣는다.","imageUrl":null},{"step":6,"text":"소금, 후추로 간을 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053550_1416213350093.jpg', 186, 4.4, 28.1, 5.5, 406)
